INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'super-fun-time', 'Super Fun Time', '**Minecraft IP:** play.superfuntime.org  
**Minecraft Version:** 1.20.1, can connect with 1.8-1.21+  
**Our Discord:**<https://discord.gg/P56dXsD>  
  
**Who are we?**  
Our community, SuperFunTime, was founded in 2010 and is one of the oldest and longest-serving Minecraft and gaming communities, where people can build, explore, and hang out. Throughout the past 15 years, SFT has hosted countless game servers including survival and modded Minecraft, alongside other games like GMod, Valheim, Rust, and 7 Days to Die. As one of the oldest servers still up, we''ve been visited by countless players and even Minecraft celebrities like CaptainSparklez.  
  
**Survival Server**  
Our Survival Server is our main Minecraft server here on SFT, and it has a bustling economy as well as multiple game enhancing plugins that offer a wide range of activities to do!   
  
• **Economy** with player-run shops and a staff-operated Emporium.  
• **Regular Events** hosted weekly by our staff team, including spleef and other player-made events in our Event World! (/w3)  
• **Minigames** available to play at any time, such as paintball, pool, minesweeper and many others!  
• **McMMO** a popular leveling plugin for upgradable skills and prestige ranks.  
• **SlimeFun** introduces technology and magic elements with its own addons, Foxy Machines and Fluffy Machines! You can craft new armor and magical tools!  
• **Enhanced Fishing, Mining and Farming** with PyroTempus'' PyroFishing, PyroFarming, and PyroMining that offer a wide range of challenges, profit and leveling!  
• **Quests and ClueScrolls** are challenges that you can complete for a wide variety of prizes, some of which include enchantment books, SlimeFun tools, and more.  
• **Realistic Seasons** adds realistic foliage, dictates our day-cycle and adds cool weather events for each season.  
• **SteveCo Crates** offer a wide variety of collectable custom items that follow themes from different famous movies and TV shows! (/warp SteveCoMuseum)  
• **Discord Connection** where you can actively communicate with Discord users from in-game.  
  
Whether you want to build, explore, or just hang out and talk with our casual player base, Survival is open to all players and has been home to talented builders, devoted players, and most of all, people just looking for a casual place to hang out with other people.  
  
**Creative Server**  
Our Creative Server offers automatic plot placements and the ability to mesh plots together with help from our committed staff team! In addition, we have WorldEdit accessible to all our players on Creative.  
  
**Other Servers**  
We are not limited to just Minecraft on SuperFunTime! We have other servers such as DayZ and ProjectZomboid that you can check out on our Discord as well as some of the other Minecraft servers we are beginning to develop.  
  
**Our Links**  
SFT Forums: <https://www.superfuntime.org/>  
SFT Wiki: <https://wiki.superfuntime.org/>  
SFT Social Media: <https://linktr.ee/sftmedia>  
SFT Servers: <https://www.superfuntime.org/forum/index.php/topic,89705.0.html>  
SFT Rules: <https://www.superfuntime.org/forum/index.php/topic,198401.0.html>  
  
**Owners:** Autpek, BuilderCreep, saywhat2365, TowelieDOH  
**And by the way...** CaptainSparklez made a video about us when he visited! https://youtu.be/S7HKXMxQbW8', 'mc.superfuntime.org:25565', 25565, 'mc_java', 'active', true, NULL, 'http://www.superfuntime.org', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'legion', 'Legion', 'Legion Servers is a group of servers including Legion of Anarchy, Legion of Battles, Legion of Creativity, and Legion of Destruction.  
  
Legion of Anarchy is an anarchy server that doesn''t force you to mess with hundreds of plugins to just play the game. There are no factions, no economy, no towny, and in general, no significantly game-altering plugins. Griefing, looting, PVP, etc. ARE all allowed.  
  
Legion of Battles is a new breed of polished Minecraft minigame server, featuring standard games such as Deathmatch and TDM, as well as novel game types such as Minecraft Tower Defense and Payload.  
  
Legion of Creativity is a no-grief creative prototyping server for prototyping battle arenas or other LOA contraptions.  
  
Legion of Destruction is a world that will be reset (approximately) weekly to never get boring, and to always keep gameplay alive. The rules are similar to LOA - no hacks, but just about everything else is allowed. Additionally, LOD has some brand new gameplay elements to make it more exciting. There are no teleports, homes (besides beds), or warps on LOD. Everyone is on even footing. There''s a 2k world border, so you can''t get so far out that you''re impossible to find.  
  
We run several custom plugins that you can''t find elsewhere to make the game more fun, without altering core gameplay. For example, we periodically hold battles where all players start on even footing and the best fighter can win a prize. Come join to check it out!  
  
  
IP: MC-L.NET', 'MC-L.NET', 25565, 'mc_java', 'active', true, NULL, 'http://l-s.co', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'creeper-s-lab', 'Creeper''s Lab', 'Like Minecraft? Want to create awesome builds? Play with friendly people? Get involved in building contests? Survive the nights and discover new worlds? Then join us today, you won''t regret it!  
  
We’re a Minecraft network and community that has been around **since 2011** , with **no major world reset** : we''re in this for the long term! We''re always looking for friendly new faces to join us. Our **active staff** is here to help newcomers get started and to fix issues. **Griefing is not tolerated** and quickly reverted. Our primary gameplay mode and focus is **near-vanilla survival** , but we also offer alternatives described below. Several community builds have been created over time, like an extensive rail network and public farms, for the benefit of all. [View our Seven Wonders](https://www.creeperslab.net/news/2016/11/314-day-2-the-seven-wonders.html) for a showcase of what our players have done in the past!  
  
We support both Java and Bedrock editions, the players from both platforms being able to play with each other! We welcome Minecraft newcomers and veteran builders alike, and we want you to feel right at home. Our network is run on a fast, dedicated hardware server to keep lag to a minimum.  
  
Tired of mining and crafting? We''ve got alternatives for a change of pace:  
- **[More than a hundred achievements](https://www.interordi.com/mboard/achievements.php)** , ranging from building targets to exploration... and explosions;  
- **Challenges** , with a new map every month;  
- **Adventure areas** , with custom loot;  
- **Minigames** , like parkour and PvP;  
- And more!  
  
[Registration is required](https://www.creeperslab.net/start.php) to access most survival worlds, but we also have a **starter world** where you can start to play right now. There are multiple benefits to registration, including achievements tracking, a **custom web profile** , and the ability to earn Merit Points through various events! The process is automatic, so **you can play within minutes**.  
  
Visit our [website](https://www.creeperslab.net/), maybe [look at the forums](https://www.interordi.com/mboard/), then point your Minecraft client to **play.creeperslab.net** today for some fun!', 'play.creeperslab.net', 25565, 'mc_java', 'active', true, NULL, '[https://www.creeperslab.net/?s=list&i=2](https://www.creeperslab.net/?s=list&i=2)', NULL) ON CONFLICT (slug) DO NOTHING;
