INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'empire-minecraft-survival-custom-mobs-town-no-pvp', 'Empire Minecraft [Survival, Custom Mobs, Town, No PVP]', 'Empire Minecraft is far from your average Minecraft server. With a unique combination of PROTECTED town plots, wilderness outposts with optional ANTI-GRIEF PROTECTION, and a player-focused ECONOMY system, there is something for every player to enjoy.  
  
