INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'efcraft', 'efCraft', 'About us:  
Welcome to the efCraft Survival server.  
  
We try to have a fun friendly environment for players. You can protect your own builds, earn economy in game, make shops to sell things, and just enjoy the server without spending a penny.  
  
We offer a rankup path on the server that grants users more permissions for free. These ranks evolve around progression in the game, and helps us build trust to the user. The higher the rank you achieve the more exciting tools you get access too. We have three tiers of ranks that vary difficulty and reward the player: 1) normal, 2) Pro, 3) Elite. The higher difficulty ranks are not for the feint of heart, and will push you in terms of how tedious some tasks; however, if you are able to complete these ranks, then you will be rewarded.  
  
  
Thank you for coming and have a great time in game!', 'play.efcraft.net', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cubeside-de-deutscher-minecraft-server', 'Cubeside.de - Deutscher Minecraft Server', 'Servertrailer: http://www.youtube.com/watch?v=OPMp_Nn4-xY  
  
Moin,  
  
wir sind Cubeside, einer der ältesten deutschen Minecraft-Server. Cubeside wurde im April 2011 gegründet und ist seitdem ein fester Bestandteil der deutschen Minecraft Community. Mit über 10 Jahren Erfahrung, ein Dutzend eigener Plugins und eigener Server Infrastruktur bieten wir jedem Spieler das perfekte Minecraft Erlebnis. Ein gut aufgestelltes Staffteam steht dir zu jeder Tages- und Nachtzeit zur Verfügung, um dir bei großen oder auch kleinen Problemen mit Rat und Tat zur Seite zu stehen.  
  
Folgende Features und Welten bieten wir an:  
  
- Freebuild  
- Spielerdörfer  
- Projektsicherungen  
- Separate Ressourcen- und Farmwelten  
- Creativewelt  
- Plotwelt  
- Haustiere  
- Daily Quests  
- Spielershops  
- Skyblock  
- Classicwelt  
- Creative und Survival Bauevents  
  
Alle Survivalwelten sind an unser Wirtschaftssystem angeschlossen. Das bedeutet für dich, dass du alle 30 Minuten automatisch 1200 Cubes (Ingame-Währung) bekommst, egal ob du gerade am Bauen oder Farmen bist. Mit dieser Währung kannst du Handel mit anderen Spielern betreiben, um dir z.B. Ressourcen zu kaufen oder zu verkaufen. Unsere offene und freie Marktwirtschaft ermöglicht dir unbegrenzte Möglichkeiten im Handel mit deinen Mitspielern.  
  
Für den Spielspaß im Bereich Minigames ist ebenfalls gesorgt.  
  
Dort bieten wir dir:  
- Gameswelt: z.B. Arcade, Bedwars, Hide and Seek, Skywars, Survival Games, 1vs1 und vieles mehr  
- Jump and Run Welt: mit Community JnRs in verschiedenen Schwierigkeitsgraden  
- Challengewelt: z.B. Speedrun, Bingo, ForceItem und viele weitere  
  
Zusätzlich zu unseren Minigames, die du jederzeit spielen kannst, finden bei uns auch mehrmals in der Woche große und kleine Serverevents statt, bei denen du tolle Preise gewinnen kannst. Beispiele für große Serverevents sind: Domination, CTW, CTM, Battle Royale (Varo) etc.  
  
Haben wir dein Interesse geweckt?  
  
Dann zögere nicht und besuche uns. Das Team und die ganze Community freuen sich darauf, dich kennenzulernen. Wir wünschen dir ganz viel Spaß bei uns!  
  
Unsere Serveradresse lautet:  
  
cubeside.de  
  
Schau auch gerne hier vorbei:  
Homepage: https://cubeside.de  
Forum: https://cubeside.de/forum/  
Teamspeak 3 Server: cubeside.de  
Discord: https://cubesi.de/discord', 'cubeside.de:25565', 25565, 'mc_java', 'active', true, NULL, 'https://cubeside.de', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mcbf-vanilla-survival', 'MCBF - Vanilla Survival', 'MCBF is a vanilla SMP server that offers the authentic, traditional Minecraft experience. If you enjoy simplicity and just want to play some good ol'' block game, then this server is most likely what you''re looking for:  
  
◽ **Straightforward** — You can start to play the game as soon as you join.  
◽ **Completely vanilla** — The server uses no plugin and runs on the official release.  
◽ **Regular survival** — The difficulty is set to Normal, and most settings are left to default.  
◽ **Latest version** — The server generally updates to new Minecraft versions as soon as they''re released.  
◽ **Trigger commands** — We offer access to essential commands such as ''spawn'' and ''home'' thanks to our custom datapack.  
◽ **Long-running server** — The server was first created in 2012, and is still going to this day.  
◽ **No microtransactions** — We offer a clean game experience; no wallet required.  
  
We hope that you will enjoy your journey on MCBF. See you there!  
  
IP: play.mcbf.pw  
Website: <http://www.mcbf.pw>  
Discord: [Join us here!](https://discord.mcbf.pw)', 'play.mcbf.pw', 25565, 'mc_java', 'active', true, NULL, 'http://www.mcbf.pw', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'foxcraft', 'Foxcraft', 'Foxcraft is a Minecraft Server Network that has been around since 2011 and provides it''s playerbase with multiple classic gamemodes like Prison, Skyblock, Survival, Creative, and more! All of our gamemodes feature custom additions to keep things interesting and modern. We also provide custom gamemodes like Kingdoms (a custom take on the popular factions gamemode) and we like to run a wide variety of events.  
  
