INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cavetale', 'Cavetale', 'Dive into the ultimate Minecraft survival multiplayer experience on Cavetale! If you crave adventure, creativity, and community, this is your new home. Play on the latest version of Minecraft Java Edition, packed with all the newest features, and enjoy a truly immersive survival experience without any pay-to-win elements.  
  
