INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'grandtheftminecart-gta-in-minecraft', 'GrandTheftMinecart - GTA in MineCraft!', 'The most played Grand Theft Auto in Minecraft server. IP: mp.gtm.network  
  
Features:  
* Use our 35 custom weapons; from shotguns to snipers, all unique to GTM  
* Drive custom vehicles; from cars to tanks, and even planes  
* Join a big community, with gangs and multiple languages  
* Own your own penthouse apartment in our custom-built map  
* Enjoy our frequent, large updates as we make the server even cooler  
  
IP: mp.gtm.network  
  
– Grand Theft Minecart –  
  
Hop into the city of MineSantos, Sanktburg or New Mineport, loot chests full of awesome gear, and kill anyone who stands in your way. Be careful though, there are police roaming the streets, and they do not like murderers! As you level up, gain access to more and more powerful weapons and vehicles, and purchase a wonderful apartment or house to store all your stuff. Join a Gang, or make your own, and become the Crime Lord of Los Santos. At Grand Theft Minecart the opportunities are limitless.  
  
IP: mp.mc-gtm.net / Then choose a GTM server with your compass to play this gamemode.', 'mp.gtm.network', 25565, 'mc_java', 'active', true, NULL, '[http://grandtheftmc.net?utm_medium=serverlist&utm_source=mp](http://grandtheftmc.net?utm_medium=serverlist&utm_source=mp)', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), '1-21-11-the-mushroom-co-survival', '[1.21.11] The Mushroom Co. Survival', 'A nice friendly small server.  
This server is freebuild pure survival, with factions so you can work together with others! Our aim at Mushroom Co. is to provide the best server experience for any player.   
  
We try to cater for any Minecraft playing style, there''s a pvp arena for PVP and an awesome shop where you can buy and sell! We have the ChestShop plugin to allow you to create your own shops. Recently, survival games has been introduced to the server and has been a moderate success!  
  
Come join and be a part of our closely-knit community and join in the fun of a wonderful server where everyone respects each other''s opinion.  
  
No asking for creative mode. There are factions, but only to allow you to claim land so your house doesn''t get destroyed. PVP is on, but not recommended as we try to be friendly and nice to one another on Mushroom Co. PvPToggle allows you to turn pvp off for yourself with /pvp.  
  
Griefing is not tolerated! We like to help and all be friends on Mushroom Co. and anyone who breaks the peace will instantly be banned. CoreProtect is used to rollback griefers, so you don''t have to worry about that!  
  
I am an owner who previously ran a server for a year, then decided to get it hosted, and it has now been upgraded!  
[Older ip was 178.239.166.247]  
[Old ip was 188.165.170.184]  
  
I have also since added some more plugins such as LWC (to protect chests, furnaces and doors), and ChestShop, which allows you to create your own shops and store the shop contents in chests for players to buy from.   
More plugins are coming soon, such as the Survival Games and much much more! If you have a plugin suggestion, leave a comment below.  
  
The staff are very nice.  
  
No Greifing, and please be nice and friendly to other players, thanks :)', 'mc.webbcraft.co.uk', 25565, 'mc_java', 'active', true, NULL, 'http://webbcraft.co.uk', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cosmicx-creative-plots-with-worldedit-512x512', 'CosmicX Creative [Plots with WorldEdit] [512x512]', 'There is a reason why we are the most popular creative server, join the server and find out for yourself!   
  
+ Advanced plot protection system to keep your builds safe, even when you are offline  
+ Toggle between survival, creative, and pvp gamemodes  
+ Safe for children of all ages, we have a large team of hand picked moderators to ensure safe gameplay  
