INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mineverse', 'Mineverse', 'Mineverse is a unique multiplayer network with custom gamemodes and minigames.  
  
