INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'sentinelcraft-1-21-10', 'SentinelCraft [1.21.10]', '![](https://www.sentinelcraft.net/resources/images/sentinelcraft_web_home_logo.png)  
**IP: play.sentinelcraft.net**  
  
Sentinelcraft | 1.21.10 | Survival | Towns | Claims | Economy | No Grief | McMMO | Jobs  
  
SentinelCraft is a survival based minecraft server that was founded in May 2013! It’s been running for over 10 years and has grown a mature, friendly and welcoming community and staff.   
We do not allow raiding or griefing, which means all your builds are safe. If you like survival with some extra spice you’ll fit right in!  
  
  
Here at SentinelCraft you can play with your friends, make land claims, make towns, interact with player shops, participate in community events and more!   
  
Our aim is that everyone in this community feels welcomed, has fun and creates long-standing friendships as we all have done for the past 10 years in a mature, lighthearted environment.  
  
  
If you want to find out more, or join the ride check our website http://www.sentinelcraft.net', 'play.sentinelcraft.net', 25565, 'mc_java', 'active', true, NULL, 'http://www.sentinelcraft.net', NULL) ON CONFLICT (slug) DO NOTHING;
