INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'loka-minecraft', 'Loka Minecraft', 'Loka is a Semi-Vanilla, PvP Survival Server that uses custom plugins to create a one of a kind Minecraft experience. For PvP types, we have custom, rated PvP including 1v1 and 2v2 [arenas and battlegrounds](http://loka.minecraftarium.com/pvp) if that is your style.  
  
