INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mp-pika-host-pikanetwork', 'mp.pika.host | PikaNetwork', 'PikaNetwork is the ultimate all-in-one destination and the best Minecraft server of 2026! At go.pika.host, we have it all: a massive and friendly community, a huge variety of the most popular gamemodes (Survival, Skyblock, Prison, Factions, and more), and a commitment to providing a top-rated player experience. Our player base is growing daily, with users from every corner of the globe. We are constantly updating and adding new features to keep things fresh and exciting. If you are looking for the best Minecraft server that ticks all the boxes, your search is over. Join PikaNetwork now!', 'mp.pika.host', 25565, 'mc_java', 'active', true, NULL, 'https://pika-network.net/play', NULL) ON CONFLICT (slug) DO NOTHING;
