INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'pixelmon-unlinked', 'Pixelmon Unlinked', 'Un-Linked is the way to go for those of you who really want to enjoy pixelmon!  
