INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'differentcraft-minecraft-towny-server', '★ DifferentCraft ★ Minecraft Towny Server', 'DifferentCraft is a mainstream Minecraft Towny server with a bunch of custom features. We''ve been running since early 2014 nonstop and have invested heavily into our own privately owned hardware keeping performance and up-time our main priority (We won''t be going anywhere any time soon).  
  
Discord: https://discordapp.com/invite/geC7Zfw  
  
We run a bunch of custom-made plugins so you''ll never get bored! You''ll find custom items and crafting systems at your fingertips, a rank progression system that grants you new perks while climbing the ranks! Some other things you''ll find are a brewing plugin that adds 60+ custom brewing recipes, a modified version of Slimefun to offer over 200 new items with lag-free gameplay, MythicDrops and so much more!  
  
  
We''re always looking to add new awesome features to our server and are always listening to the community''s suggestions. Some of our most popular plugins are:  
  
Towny   
McMMO   
Jobs   
Elevators   
Custom GUI''s   
Custom NPC''s  
MythicDrops  
LWC  
QuickShop  
Gemshop  
Grief Rollback system  
McMMO and Marriage and many many more.  
  
  
The staff is always available on the discord server and in-game, so there''s no need to worry about rule breakers. If you ever have a problem you can always count on our staff to rectify the situation. We also have specialized plugins to rollback any griefs done by rule breakers to keep your mind at peace.  
  
  
During the holidays we put on events for players to play through and collect amazing custom items. Major events are usually around Summer & Christmas (My favorite) which are absolutely fabulous! We often add new fresh content to keep the game fun and enjoyable! We''re always listening to everyone''s suggestions to keep the community a happy and fun place to be.', 'mp.differentcraft.net', 25565, 'mc_java', 'active', true, NULL, 'http://www.differentcraft.net/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'shadowxcraft', 'ShadowXCraft', 'I represent a fantastic, excelling community. We have been public since November 2013, and we are holding strong!  
  
ShadowXCraft is a fun, appealing network, featuring:   
-A popular 1.7.2-1.8.8 mildly-**competitive KitPVP** (with a HUGE variety of unique gametypes: BuildUHC, ComboUHC, Soup, Potion, OverPowered, Parkour and Basic!). Two professionally built Free for All arenas, parties, killstreaks and our very own cosmetic plugin are also featured!  
-A **Creative** server, supporting 1.7.2-1.10.2 versions! Build and create all your inspirations and ideas, with no absolute limit holding you back!   
-A popular **Factions** server, supporting 1.8.9-1.10.2 versions! A new version of Factions is being developed, and will be 1.7.2-1.10.2 compatible! Everything will be completely revamped, to everyone''s liking! A lot of the new features will also be ShadowXCraft-unique!   
-A peaceful 1.7.2-1.10.2 **Survival** server, where you have large, separate plots, all to yourself! Play with other people, and renew your vanilla playstyle!   
-An engaging **Prison** server, supporting 1.8.9-1.10.2! It will soon be redone, just like Factions, and it will bring a whole lot of new features and gameplay!   
-A fun, interactive **Minigames** server, where you can enjoy our Minigames, such as BlockHunt, Turfwars, Bridges, and our **custom-coded** Mineopoly and Battlezones!   
-A competitive **UHC** server, where you can battle to your heart''s content! Health does not naturally regenerate, so you have to rely on golden apples and healing potions to regenerate lost health! There is also a private, HostedUHC server for those who are sponsoring and advertising the server!   
  
  
Additionally, we have an amazing **small community** , who will get to know you and help whenever they can! Our staff team also monitor the network, so troublemakers are kept in line! This is a US based network!   
Website: <https://www.shadowxcraft.net/>  
The full terms and conditions are here: <https://www.shadowxcraft.net/help/terms>  
The full player rules are here: [https://docs.google.com/document/d/1gsSBuQE58_SF2_RMdWOELrs0EybuGiyPn0PtK7lfQXw/edit ](https://docs.google.com/document/d/1gsSBuQE58_SF2_RMdWOELrs0EybuGiyPn0PtK7lfQXw/edit%20)  
List of staff are here: <https://www.shadowxcraft.net/staff/>  
  
Help us out!: <http://donate.shadowxcraft.net/>  
  
Vote for us!: <https://www.shadowxcraft.net/vote/>  
  
Come join us now! We''d love to see you here!   
  
**ShadowXCraft.net**', 'shadowxcraft.net', 25565, 'mc_java', 'active', true, NULL, 'https://www.shadowxcraft.net', NULL) ON CONFLICT (slug) DO NOTHING;
