INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'havoc-games-the-mining-dead-craft-theft-auto', 'Havoc Games // The Mining Dead // Craft Theft Auto', '![](https://i.imgur.com/p4bMvmt.png)  
