INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'catscraft-net', 'CatsCraft.net', 'CatsCraft is a Creative, Survival and Minigames server where everything is FREE including world edit and building space there are no paid ranks so everyone is equal here!   
  
