INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mega-craft-an-avatar-themed-minecraft-server', 'Mega Craft - An Avatar Themed Minecraft Server!', 'If you’re looking for a fun, exciting, and customized minecraft experience, Mega Craft has something for you! We have three unique servers, each one with a variety of features that will completely change the way you play.  
  
You’re going to love our Avatar themed game mode! Once you enter, you’re given access to a wide range of powerful moves and bending styles from each of the four elements, as seen in Avatar: The Last Airbender. You can even use custom moves and bending types that have never been seen before, like sunshine bending! Face off against other players in our massive arenas to hone your skills; participating in our tournaments is also a great way to see what you’re capable of. If you prefer a more peaceful bending experience, you can start your own town or join one of our welcoming communities!  
  
On our Slimefun Survival game mode, you have the freedom to customize-in all ways! Magical armor and unique machines allow you to thrive and be a part of a friendly, cooperative community. There are so many different things to do, but one thing is for sure: whether you’re cooking up delicious foods like ice cream and burgers, creating powerful, rare weapons that can never be lost, or starting your own shop and becoming a minecraft millionaire, you will never be bored on Slimefun Survival!', 'hub.megacrafting.com:25565', 25565, 'mc_java', 'active', true, NULL, 'http://www.megacrafting.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'trekcraft-towny', 'TrekCraft - Towny', 'TrekCraft is not any ordinary server, we are a committed 1.21.8 Towny/Survival server with tons of extra plugins to enhance your experience at TrekCraft. Our towny server is a longstanding friendly community that welcomes everyone and lets you build and play without extra drama. We include mcMMO, LWC, Jobs, ArtMap, tough custom bosses, chestshops, and more.   
  
Here at TC we have a growing community that takes part in events every week and an active, all player staff that will help you through any situation. We''re fully EULA compliant and our great ranks are completely free, and can be earned through contests, treasure hunts, events, and voting. We''ve been up since 2014, so you know we''ll be there when you need us.  
  
When you find yourself on TrekCraft you feel like you are part of the family, and that is exactly what we want you to feel.  
  
Take time today and come join us at mc.TrekCraft.net  
You can also visit our website at http://www.trekcraft.ca/home  
  
Minecraft is an adventure, Trek it. -TC2014  
Website: http://www.trekcraft.ca/home', 'mc.TrekCraft.net:25565', 25565, 'mc_java', 'active', true, NULL, 'http://www.trekcraft.ca/home', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mclabs-chems-cops-formerly-mcdrugs', 'MCLabs - Chems & Cops (Formerly MCDrugs)', 'In MCLabs, you choose to be a **CHEMIST** or a **COP**. Chemists grow crops to turn them into illegal **CHEMS** and **COMPOUNDS** to sell. Cops try to arrest chemists and take the chems for themselves. Use money from selling chems to rank up, earning new perks and abilities to build your chem empire towards Chem Lord status, or to ascend the police ranks towards Operator status.  
  
MCLabs has been running for **over 10 years** (formerly **MC-Drugs/MCDrugs**) and is home to unique mechanics not seen on any other server.  
  
Along with the main Chems gamemode, we have Creative, KitPvP, Parkour, and a unique PvE experience: The Pit.', 'mp.labs-mc.com', 25565, 'mc_java', 'active', true, NULL, 'https://labs-mc.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'shirecraft', 'ShireCraft', 'Welcome to The Shire, wanderer.  
  
A midst your travels, you''ve approached us, The Shire.  
  
Let us take you on a journey of what it is like to be a member of The Shire.  
  
We boast a Semi-Creative server. This means, you start in survival, and earn creative through the ranks.   
  
We admire those who love to build for fun. Those who love to delve into projects that are way bigger than originally anticipated. We love when members are in over their heads, and exceed their expectations on the final outcome of said project. For this, rewards shall follow, in due time. Creative mode, is, one of them.  
  
Along with ranking up, members who receive a rank up, enjoy an increase in respect, and privileges.  
  
Although, ranking is something that comes with dedication, hard work, and fun. We do not tolerate those looking to build just for ranks. (Don''t believe me? Its all over the server!)  
  
Along with our ranking system, our members can expect to enjoy a vast, developed world to explore and build in. With the opportunity to build freely in the wilderness, the world really is, in your hands. (Of course, this is subject to you following our few, yet crucial rules, found on our website).  
  
On top of our free build policy, our members have a blast forging bonds with current, existing members. I mean c''mon, building with the buddies on a weekend, late at night, Doritos in bowl, ah, nothing better!  
  
We have an extensive railway system on top of our well developed towns, cities, cathedrals, and more!  
  
We also have a forum, and a wiki for all of your needs and needs to be.  
  
We host build competitions, and a plethora of other fun ideas and ideals, on the server.  
  
We don''t want to give too much information away, we want you to come see it for yourself! So what are you waiting for?  
  
Apply via our "join us" tab on our website at www.shirecraft.us. Allow for 48 hours before someone checks the application, it is usually done way before then, but sometimes, life happens.  
  
We hope to see you soon!', 'play.shirecraft.us:25565', 25565, 'mc_java', 'active', true, NULL, 'http://www.shirecraft.us', NULL) ON CONFLICT (slug) DO NOTHING;
