INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'vanilla-high', 'Vanilla High', 'Server updated to 1.20.2 Vanilla High, your build-focused/community-oriented Keep Inventory Vanilla server. We dont allow griefing/raiding and unwarranted PvP. We also require of players a maximum effort to keep the server atmosphere family-friendly.  
Vanilla High is a server that tolerates languages other than English.  
  
