INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'extremecraft-net', 'ExtremeCraft.Net', 'Experience the boundless adventures awaiting you at ExtremeCraft.net! Embark on a journey through a plethora of exhilarating game modes, blending both timeless classics and innovative new experiences seamlessly.  
  
Navigate to our website forums at www.extremecraft.net and immerse yourself in the vibrant community. Engage with fellow players, share strategies, and stay updated on the latest developments.  
  
