INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minesuperior', 'MineSuperior', 'Discover MineSuperior – your ultimate 1.21 Minecraft: Java Edition destination, meticulously curated by a seasoned management team dedicated to crafting an unparalleled experience for all. Embark on an adventure through multiple dimensions: from the classic allure of Survival, to the innovative challenges of Skyblock, the adrenaline-pumping intensity of Lifesteal, and the collaborative camaraderie of Towny.  
  
Immerse yourself in a dynamic realm that evolves with each passing moment, as our commitment to regular updates ensures a perpetually rejuvenated environment. However, this is not your ordinary realm; here, the boundaries of vanilla are transcended. Engage in thrilling encounters with custom-designed bosses, forge unbreakable bonds with upgradable pets, and test your mettle against waves of malevolent mobs in electrifying envoys, all for the chance to seize coveted prizes.  
  
Join us at MineSuperior and experience Minecraft as it was meant to be – a canvas for boundless creativity and unforgettable adventures, all within a community that values your journey as much as you do. Your story starts here; where will it lead?', 'play.mcs.gg', 25565, 'mc_java', 'active', true, NULL, 'https://store.minesuperior.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minemora', 'Minemora', 'Nombre del servidor:  
