INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'dank-prison', 'Dank Prison', 'Dank Prison was Released January 1st 2018. I set out on a quest to create the best prison server possible. Realizing there was no good plugins I could just download I started creating my own. I work on server daily to improve existing code and implement new code to provide the Best Prison Experience', 'DankPrison.com', 25565, 'mc_java', 'active', true, NULL, 'http://DankPrison.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rok-network-factions-colony-wars-tnt-run-apocalypse', 'Rok Network: Factions/Colony Wars/TNT Run/Apocalypse', 'In colony wars, there are four colonies (teams). Only one colony can win. The colonies must battle it out until one is victorious. Each colony must build a base, with buildings such as cannon towers and landmines.   
  
Each player must additionally select a class, such as cloaker, which will give you additional benefits. You can upgrade your class items at buildings, but to upgrade your items, you first require gold. You can collect gold from mining or chopping down trees.  
  
When there are only two colonies or four players left, showdown commences. From this point on everyone has zero respawn chance, and must battle to the death. One colony will emerge victorious.  
  
The network also has TNT Run, 1v1 and Survival Games.  
  
Recent-Updates:  
- Added 1v1', 'play.mccolony.net', 25565, 'mc_java', 'active', true, NULL, 'http://ithinkrok.enjin.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'the-noob-adventures-official-server', 'The Noob Adventures OFFICIAL SERVER', 'This server is based upon the hit series THE N00B ADVENTURES on Youtube!  
  
Series: https://www.youtube.com/watch?v=O4r0hWgx1-Y  
Site: http://www.NoobAdventures.com  
Discord: https://discord.gg/NdVmEzaBDG  
  
  
Our Survival and Event server has fantastic admins who are great at helping players save and manage their creations! Take part in pvp, mob, raid, hungergames, quest, dodgeball, admin-run, holiday, and trivia events DAILY! Brew your own custom potions and beverages! Grab several custom magical weapons and firearms! You can play with all the characters from the N00b Adventures too! Gaylord Steambath might even grief you! I''d recommend staying away from him though...  
  
There are also global donator perks such as pets, nicknames, and magic spells Learn more about it in the server or on our forum and get gear for just voting for us!  
  
Drop on by when you can! We look forward to playing with you!  
  
Additional Notes  
Based upon the animated series, come on in and fight against the mighty Gaylord Steambath!', '23.94.159.71:25565', 25565, 'mc_java', 'active', true, NULL, 'http://www.NoobAdventures.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'let-s-mine', 'Let''s Mine', '**Das ist Let’s Mine**  
Wir haben ein nettes und hilfsbereites Server-Team, dass Dir mit Rat und Tat zur Seite steht. Hast Du Lust selber mal in einem Server-Team mit zu arbeiten, stehen Dir bei uns alle Türen offen jede erdenkliche Position zu erreichen. Bringst Du Ideen mit, die der Community gefallen könnten und nicht gegen unser Regelwerk verstoßen, werden wir Dir helfen und Dich bei allem unterstützen um deine Ideen zu verwirklichen.  
  
  
**Reisende, Pioniere und Bürger**  
Wir sind Bürger von Let’s Mine und heißen Dich willkommen. Wenn Du Lust hast unserer Community beizutreten stehen Dir alle Tore offen und unser netter Support begleitet Dich auf deiner Reise. Als Reisender legst Du im Communityhafen an und startest deine Laufbahn als Pionier. Erkunde erstmal in Ruhe alle Ecken von Let’s Mine und lasse Dich dort nieder, wo Du dich am wohlsten fühlst. Wenn ein wenig Zeit verstrichen ist und Du deine ersten Fußspuren in unseren Welten hinterlassen hast, kannst Du offiziell eingebürgert werden. Dann bist Du ein Bürger von Let’s Mine.  
  
  
**Lasst die Spiele beginnen!**  
Unser Eventteam schraubt immer an neuen Eventideen, um allen Bürgern genügend Abwechslung und Attraktionen zu bieten. Bei uns ist immer was los. Von den Minievents innerhalb der Woche bis zum großen Sonntagsevent an jedem Wochenende. Für alle die mehr wollen starten wir auch schonmal Dauerevents, die sich über mehrere Tage oder sogar Wochen ziehen können. Hier findest Du bestimmt auch was passendes zum Zeitvertreib. Wenn Du eigene coole Ideen hast, kannst Du dich gerne an unser Eventteam wenden und mit ihnen besprechen, wie man Deine Idee am besten einbringen kann. Wir sind immer offen für neues.  
  
**Wirtschaft**  
Um unser Wirtschaftssystem mit eigenen Custom-Villagern und einer ganzen Stadt zum Handeln kümmert sich eine extra Gruppe aus Teamlern und Bürgern. Du kannst Dir Grundstücke in unseren verschiedenen Serverstädten kaufen, oder Du nimmst Dir vor Großgrundbesitzer zu werden um außerhalb der Städte dein eigenes kleines Reich zu erschaffen. Sollte Dir das alles nicht so zusagen, stehen Dir 3 große Freebuild-Welten zur Verfügung in denen Du bestimmt eine gemütliche Ecke zum “minecraften” findest.  
  
  
**Der Server**  
Unser Server wird immer schnellstmöglich auf die aktuellste Minecraft version gebracht. Mit einer Uptime von 99,83% bieten wir Dir einen Minecraftserver der eigentlich immer erreichbar ist und nur für Wartungsarbeiten, Neuerungen und restarts kurz down geht. Er wird von unserem Java-Grinch bestens gewartet und alle laufenden Plugins sind feinste Handarbeit. So kannst Du bei uns auf einen sauber programmierten Server spielen.  
  
**Du bist Neugierig?**  
Du kannst ganz leicht ein Teil unserer schönen Community werden. Wenn Du dich entschlossen hast, mal einen Blick zu riskieren, kannst Du hier alle nötigen Informationen finden. Klick dazu einfach mal auf den Link [hier](https://www.letsmine.eu)', 'server.letsmine.eu', 25565, 'mc_java', 'active', true, NULL, 'http://www.letsmine.eu', NULL) ON CONFLICT (slug) DO NOTHING;
