INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'geoblock', 'GeoBlock', 'Con más de 5 años de experiencia, GeoBlock es considerado por muchos el **mejor servidor de SkyBlock en español** .  
  
Es muy diferente a cualquier otro SkyBlock que puedas encontrar en otro sitio. Hay mecánicas innovadoras nunca vistas en otros servidores:  
  
- _**La pesca es genial**_. Más de **100 peces** nuevos con texturas, con **condiciones de pesca** (hora, mes, bioma, lluvia...), rarezas y mucho más. Ah, y tambien ¡se pueden **pescar peces en la lava del nether**!  
![](https://topg.org/gallery/130322/60234.png)  
  
- _**Encantamientos únicos**_. ¿Quieres conseguir la cabeza de los mobs o jugadores que eliminas? ¿Quieres que el casco te de visión nocturna? ¿Y qué tal un pico que explote los bloques de alrededor?  
![](https://topg.org/gallery/130322/60235.png)  
  
- _**Jetpacks**_. Vuela por tu isla con los jetpacks crafteables.  
  
- _**Muchos muchos objetos exclusivos**_. Varitas para replantar, crear hielo, flores... Unas tijeras para esquilar a todas las ovejas cercanas a la vez.  
![](https://topg.org/gallery/130322/60237.png)  
  
  
Esto es solo el 1% de lo que ofrece GeoBlock. Porque lo más importante eres tú, la **Comunidad**.', 'geoblock.es', 25565, 'mc_java', 'active', true, NULL, 'http://web.geoblock.es', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'harmony', 'Harmony', 'Harmony  
