INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'gamster-org-gaming-is-not-a-crime', 'Gamster.org - Gaming is not a crime', '![](https://i.imgur.com/Hu9v0tl.png)  
  
Our community provides you with a professional and objective team to assist you in resolving your administrative or technical issues in the most efficient manner possible. We''ve gone to great lengths to ensure that you have the safest systems possible so that you can enjoy your recreational and competitive activities to the fullest. Over time, the Gamster community has built and laid the foundations for an environment where you can enjoy the most well-known and well-liked Minecraft Multiplayer.', 'mc.gamster.org:25565', 25565, 'mc_java', 'active', true, NULL, 'https://www.gamster.org', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'playuhc-1-8-1-21', 'PlayUHC 1.8 - 1.21', '**  
** 24h/7d UHC games **  
** Randomizer UHC **  
** Cut Clean UHC **  
** 80+ Different Scenarios **  
** Survival Games UHC **  
** Flower Power UHC **  
** Dragon Rush UHC **  
** Meetup UHC **  
** UHC FFA Arena **  
** UHC Duels **  
** Custom Games**  
** Monthly challenges and competitions **  
** Creative server **  
** Friendly community **  
** PG/no swearing **  
** Best staff and custom report system **  
** Full-time software developer constantly making new scenarios/game modes! **  
**
  
  
UHC = Ultra Hard Core: one life, no natural regeneration!  
  
PlayUHC is an established UHC server which launched in the summer of 2016, and our goal is to bring the best possible experience to all our players and UHC games to the whole community! We have a variety of UHC gamemodes that are enjoyable for everyone. These consist of Speed UHC, God UHC, Flower Power UHC, Gone Fishing UHC, Dragon Rush UHC, Scenario Madness UHC, Meetup UHC, Red vs Blue UHC, Cut Clean UHC, Vanilla UHC, Survival Games UHC, Wither Rush UHC and Randomizer UHC!  
  
For those that don''t want to play lengthy gamemodes, we also have a creative build server where you can chill with friends, and an UHC Free For All (FFA) Arena!  
  
Our staff team is always present, nice, and friendly! We have a /helpop and /report system: you will always get an answer from our staff about your questions!  
  
We frequently organise events and custom server builds for Content Creators (mostly Youtubers and Twitch streamers). We also host Reddit UHCs.  
  
Enjoy!  
  
Server Address: playuhc.net  
Client versions accepted: Java Edition from 1.8 to 1.21', 'playuhc.net', 25565, 'mc_java', 'active', true, NULL, 'https://www.playuhc.net/', NULL) ON CONFLICT (slug) DO NOTHING;
