INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'badwolfmc', 'BadWolfMC', 'Experience [**BadWolfMC: An Adult Minecraft Server**](https://www.badwolfmc.com) - a long-running, drama-free, and inclusive community for adults. With spacious build areas and carefully curated plugins, our server maintains the vanilla feel while adding a touch of fun and ensuring the safety of your creations. Connect and chat seamlessly via our integrated Discord server, enjoy **Java-Bedrock Crossplay** from any device, and find answers to all your questions on our helpful [wiki](https://wiki.badwolfmc.com/).  
  
Join one of the best online communities you''ll ever be a part of, where members from around the world come together to forge friendships and share their Minecraft passion. Guests are welcome to log in and explore, and once your [application](https://www.badwolfmc.com/membership-application/) is approved, you''ll gain build permissions to bring your imagination to life. Discover the captivating world of BadWolfMC and let your creativity roam free!', 'play.badwolfmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.badwolfmc.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'survivaldub-network', 'Survivaldub Network', '**SurvivalDub Network: 14 Años de Historia | Survival, Skyblock & Crossplay**  
¡Únete a la comunidad histórica más activa! SurvivalDub es una network legendaria activa desde hace **14 años**. Ofrecemos una experiencia de **Vanilla Real** con actualizaciones constantes e innovación en modalidades como Survival Custom, Skyblock, Prision y Creativo.  
**¿Por qué elegirnos?**  
  
[*] **Comunidad Hispana Veterana:** Miles de usuarios y un staff con alta experiencia en networks.  
[*] **Infraestructura de Élite:** 3 Servidores Dedicados (+192GB RAM) con Protección Anti-DDoS profesional y Uptime 24/7 sin interrupciones.  
[*] **Juego Justo y Seguro:** Sistemas Anti-Hacks avanzados y backups semanales para proteger tu progreso.  
[*] **Variedad Total:** Desde el PvP más competitivo hasta el PvE más relajado.  
  
La historia de Minecraft se escribe aquí. ¡Estamos ansiosos por verte en línea!  
**IP Java:** mc.survivaldub.com  
**IP Bedrock:** mc.survivaldub.com (Puerto: 19132)  
**Web:** https://survivaldub.com', 'mc.survivaldub.com', 25565, 'mc_java', 'active', true, NULL, 'https://survivaldub.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'raidersheaven-multigaming-netzwerk', 'RaidersHeaven Multigaming Netzwerk', '﻿Hallo!  
  
Schön, dass wir Deine Aufmerksamkeit haben.  
  
Wir sind **RaidersHeaven** , ein aufstrebendes Netzwerk für mehrere Spiele. Unter anderem eben auch mit einem großartigen Minecraft-Server. Und diesen wollen wir Dir einmal vorstellen!  
  
Auf unserem Minecraft-Server bieten wir Dir ein gemütliches und umfängliches Gameplay im klassischen Survival-Stil - Freebuild eben. Baue das, worauf Du Lust hast und erstaune andere Spieler mit Deinen Bau Skills und Deinem Survival Know-How.  
  
**Achtung!**  
Die serverweite Schwierigkeit steht auf **Hard**. Sei also gegen starke Mobs gewappnet und hab immer ausreichend Verpflegung dabei!  
  
  
**_Plugins / Extras_**  
Wir nutzen viele bekannte und erfolgreiche Plugins wie z. B. Essentials, ChestShop, Bolt (LWC), Lands, WorldGuard. Ebenfalls kommt bei uns ein sehr starkes AntiCheat-System zum Einsatz.  
Nebst diesen, haben wir eigene Plugins programmiert, um für alle Spieler ein noch umfangreicheres Spieleerlebnis zu garantieren.  
  
Zum Beispiel kannst Du bei uns Items signieren. Oder du pflanzt beim Ernten von Crops direkt mit der Hacke nach. Oder du baust Dir einen Aufzug aus Eisen, Gold, Diamant, Smaragd oder einem Leuchtfeuer. Oder Du prüfst mit einem Command, ob der Chunk in dem Du stehst ein Slime-Chunk ist. Oder Du schaust zu, wie das Laub der Bäume nach dem Abholzen sofort verschwindet....  
  
Du siehst also - das sind schonmal ein paar nette Extras! :)  
  
  
**_Events_**  
Bei einer höheren Spielerzahl veranstalten wir auch kleine Events. Im Regelfall mit Drops zum Einsammeln. Zukünftig sind auch klassische Abbau-Events, oder Events mit Aufgaben geplant. Über Events kannst Du sehr seltene Serveritems bekommen, die Dir im Kampf gegen Mobs (oder auch Spielern) helfen, oder die Dir das Leben auf dem Server für z. B. Farmen erleichtern.  
  
  
**_Protections_**  
Wie Du oben schon gelesen hast, kannst Du mit Bolt (LWC) alle Deine Kisten, Türen, Trichter, Spender, usw. abschließen. Optional kannst Du andere Spieler auf Deine Blöcke Zugriff gewähren indem Du sie trustest.  
  
Für alle Bau Enthusiasten bieten wir natürlich eine entsprechende Option für Protections. Mit dem Lands Plugin (/lands, /claim, etc.) kannst du gegen Ingamewährung Deine Bauwerke vor dem zerstörerischen Leichtsinn von Griefern schützen.  
  
Bei besonders herausragenden Bauwerken kann man sich Belohnungen verdienen und bekommt eine Admin-Bewertung.  
  
**  
_Livemap_**  
Über unsere Website kannst Du auf unsere Livemap gelangen. So kannst Du alle bisher aufgedeckten Chunks und Protections sehen. Das macht das Navigieren auf dem Server leichter.  
  
  
**_Sonstige Hinweise_**  
Wir halten unseren Server so aktuell wie möglich (Serversoftware, Plugins). Deshalb wird unser Server in unregelmäßigen Abständen aktualisiert und neugestartet.  
Damit gewährleisten wir die Funktionalität  
  
Wenn Du einen Bug findest oder einen Spieler melden willst, kannst Du dies über unsere Website tun (Registrierung vorausgesetzt).  
  
  
Das war erst einmal unsere _grobe_ Vorstellung und wir hoffen, Dein Interesse geweckt zu haben.  
Komm uns mal besuchen.  
  
Wir freuen uns auf Dich!  
  
  
**Das RaidersHeaven - Team**', 'mc.raidersheaven.eu', 25565, 'mc_java', 'active', true, NULL, 'https://raidersheaven.eu/', NULL) ON CONFLICT (slug) DO NOTHING;
