INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'swancraft-semi-vanilla-smp', 'SwanCraft Semi-Vanilla SMP', '🔸⬥🔷⬥🔸──── **SwanCraft** ────🔸⬥🔷⬥🔸  
**IP:** mp.swancraftmc.com  
**Version:** 1.21.11  
**Website:** <https://swancraftmc.com/>  
**Discord:** <https://discord.com/invite/sVQMwTT>  
**Founded:** Jan 21, 2017  
  
✨ **Map Info** ✨  
Overworld: 30k x 30k  
Nether: 30k x 30k  
The End: 30k x 30k  
  
✨ **Spread your wings and fly home to SwanCraft** ✨  
In a world full of soulless Minecraft Networks and "one-size-fits-all" hub servers,  
SwanCraft aims to give you something different: **a place to call home.**  
Our close-knit community is ready to welcome you into our family!  
  
  
✨ **_“Semi” Vanilla_** ✨  
We aim to keep gameplay itself as vanilla as possible, while providing access to some commands that make Minecraft life a little less mundane.  
For example, we have /tpa, /sethome, and /spawn.  
  
✨ **_Grief Prevention_** ✨  
Claim your land and only give access to people that you trust!  
This prevents griefing and raiding, which gives you peace of mind and gives staff more free time to plan features and events!  
  
✨ **_Ranks_** ✨  
We have two systems of ranks: voting and donating. Our donator ranks are designed to be "Pay-to-skip" rather than P2W. This means that nearly all donator perks are available from vote ranks and higher vote ranks provide you with better perks than any donator rank.  
  
✨ **_Crates & Collectibles_** ✨  
Use keys from voting or donating to open crates for special rewards. We bring a different element to Minecraft with Collector Series. There are dozens of collector series'' on our server and more are being added every month! Collect custom heads, items, maparts, and OP weapons and armor. From themed crate series, holidays, movie collectibles, custom gear, and more, it''s a collector''s paradise!  
  
✨ **_Community Feel_** ✨  
We want everyone to enjoy their time on SwanCraft.  
We try to promote a friendly environment free from toxic energies.  
Players are encouraged to voice any suggestions or concerns they may have for the community.  
💖🧡💛💚💙💜 LGBTQ+ inclusive! 💜💙💚💛🧡💖  
  
✨ **_Events_** ✨   
• Falling Crate Keys  
• Map Art Contests  
• Movie Nights  
• Build Contests  
• Art Contests  
• Discord Events  
• Special themed events  
  
✨ **_Player Shops_** ✨  
Our economy is entirely item based. No economy plugins $$ here!  
Browse our several dozen player shops at /warp shops!  
  
  
When searching for a new place to play, sometimes what a server doesn''t have is just as important as what it does.  
  
**NO** Towny  
**NO** MCMMO  
**NO** Factions  
**NO** Economy Plugins  
**NO** different game modes  
**NO** Dynmap  
**NO** Keep Inventory  
(But your death coordinates are recorded.)  
**NO** Custom Enchants  
**WE ARE NOT A HUB SERVER**', 'mp.swancraftmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.swancraftmc.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'happycloud-pixelmon-server', 'HappyCloud - Pixelmon Server', 'Welcome to the HappyCloud Pixelmon Server!  
  
