INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'edoras-minecraft-espa-ol', 'Edoras Minecraft (español)', '**Edoras** es una pequeña comunidad de Minecraft Survival Vanilla en Español con algunos plugins cuyo principal objetivo es la diversión. Nuestro servidor, comandado por varias personas al frente, hace de sus usuarios la principal fuente de construcción de la misma. Podréis construir vuestras propias ciudades a partir de recursos que podréis extraer de un mundo dedicado para ello.  
  
El compañerismo y el respeto son la clave y los pilares fundamentales de este proyecto. No tenemos grandes objetivos, simplemente disfrutar del tiempo juntos y de dejar huella en un mapa que nos representará a cada uno de nosotros dejando momentos de risas, pequeños altercados, ilusión y ganas.  
  
De vez en cuando esa diversión inunda el servidor, disfruta tu propia aventura participando en eventos o minijuegos esporádicos que realiza el Staff y que hacen que la experiencia sea mucho más amena y se creen conexiones de amistad entre los usuarios.  
  
Utilizamos el español (España), aunque conocemos y sabemos manejarnos en inglés y aceptamos abiertamente gente de otras nacionalidades aunque no conozcan o quieran aprender nuestro idioma.  
  
¿A qué esperas para formar parte de nuestra comunidad? ¡Te esperamos!  
  
**Contacta con nosotros en nuestro Discord** : <https://discord.edoras.es>', 'server.edoras.es:25565', 25565, 'mc_java', 'active', true, NULL, 'https://edoras.es', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'opencraft-pl', 'openCraft.pl', '🎮 OpenCraft.pl – Twoja Przestrzeń do Kreatywności i Przygody! 🌍  
🔹 Start gry: opencraft.pl  
🔹 Wersja: Java + Bedrock  
🔹 Tryby: Freebuild/Survival, Skyblock  
🔹 Adres serwera: opencraft.pl  
  
OpenCraft.pl to niezwykły serwer Minecraft, który od 2011 roku łączy graczy w jednym, stale rozwijającym się świecie. Niezależnie od tego, czy jesteś fanem kreatywnego budowania, survivalowych wyzwań, czy eksploracji, znajdziesz tu coś dla siebie! 🌟  
  
Dlaczego OpenCraft.pl?  
  
🛠 Równowaga i sprawiedliwość – Każdy gracz ma równe szanse, a system ekonomii oparty na "walucie czasu" eliminuje inflację.  
🚆 Transport z duszą – Zapomnij o nudnych teleportach! Podróżuj koleją, łódkami lub odkrywaj sieć portali.  
🗺 Dynamiczny świat – Mapa serwera regularnie się rozszerza, a Ty możesz budować, gdzie tylko chcesz, w trybie Freebuild.  
🌌 Skyblock 2.0 – Klasyczny tryb Skyblock wzbogacony o nowe mechaniki i wyzwania.  
💡 Autorskie pluginy – Ponad 110 unikalnych dodatków, które sprawiają, że rozgrywka jest jeszcze bardziej wciągająca.  
  
  
Dołącz do społeczności, która:  
  
🤝 Współpracuje i tworzy niesamowite projekty.  
🌿 Ceni sobie relaksującą rozgrywkę bez agresywnego PvP.  
🚀 Regularnie organizuje eventy i konkursy.  
  
  
Podstrony i Społeczność:  
  
📜 Świat – Mapa, transport, unikalne mechaniki: opencraft.pl/lokacje  
🗺 Mapa serwera – Śledź rozwój świata na żywo: opencraft.pl/mapa  
📸 Galeria – Zobacz, co stworzyli gracze: opencraft.pl/galeria  
📢 Ogłoszenia – Bądź na bieżąco: opencraft.pl/ogloszenia  
  
  
💙 Dołącz do nas i zacznij swoją przygodę już dziś! 🚀', 'opencraft.pl', 25565, 'mc_java', 'active', true, NULL, 'https://www.opencraft.pl/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'vestlandet', 'Vestlandet', '**Vestlandet**  
[Vestlandet](http://www.vestlandetmc.no) er en norsk Minecraft server som siden mars 2017 har skapt mange gode minner og spilleglede for alle og enhver. Vi ønsker at alle skal kunne spille sammen og bli bedre kjent med hverandre, uansett alder enten du er 8 eller 70 år. Det er derfor utrolig viktig for oss at tilpasningene er deretter slik at små barn kan spille sammen med ungdom og godt voksne.  
  
Vi er derfor en gjeng godt voksne som passer på at alle trives med nulltoleranse for mobbing og dårlig ordvalg. Vi i team [Vestlandet](http://www.vestlandetmc.no) gjør vårt ytterste for å skape den beste Minecraft opplevelsen! Vi på [Vestlandet](http://www.vestlandetmc.no) elsker det vi gjør og alle har det samme målet. Nyskapende, en trygg tilværelse og ikke minst en vanvittig gøyal server!  
  
**Hva kan vi tilby?**  
• Et ranking system for deg som ønsker å avansere! Få ekstra perks og kommandoer ved å  
klatre på ranking stigen.  
  
• Dette er en Survival server, hvor vi spiller med PvE, men det er fremdeles mulig å gå i PvP  
modus å sloss mot andre likesinnede. Vestlandet baserer seg på fredelighet, og det skaper vi   
gjennom frivillig PvP.  
  
• Gøyale plugins som gjør opplevelsen din på serveren mye bedre. Det skjer ting hele tiden og   
man blir aldri lei!  
  
Hva venter du på? Logg deg på [Vestlandet](http://www.vestlandetmc.no) og bli en del av dette fantastiske miljøet!', 'vestlandetmc.no', 25565, 'mc_java', 'active', true, NULL, 'https://www.vestlandetmc.no', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'fallout-the-last-frontier', 'Fallout: The Last Frontier', 'Fallout: The Last Frontier is a serious post-apocalyptic role play server based in the Alaskan Wasteland. We aim to provide quality a Fallout role play experience that many types of players can enjoy. Compared to Fallout role play servers of the past, we plan to keep provide quality post-apocalyptic role play for an extensive amount of time that we hope can be forever. So join us in this amazing experience and apply today.', 'Fallout.thebigdigmc.info:25565', 25565, 'mc_java', 'active', true, NULL, 'https://fallout-the-last-frontier.enjin.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'geocraft', 'GeoCraft', '[title]**Alle gebouwen, wegen en rivieren staan in GeoCraft. Loop door Amsterdam, Rotterdam of bijvoorbeeld Utrecht. Ga naar je eigen huis en begin met bouwen.**[/title]  
De computer heeft alles grijs ingeladen, help mee om Nederland in Minecraft mooi te maken: bouw bijvoorbeeld je eigen huis of het paleis van de Koning. Elke plaats in Nederland is te vinden: kom bijvoorbeeld in Groningen met /warp Groningen of ga naar een adres met /gc adres, bijvoorbeeld /gc Nieuwe Steeg 74 Herwijnen of /gc 4171KG 74  
  
Geen zin om te bouwen in Nederland? Je kan ook naar onze Survival server of bouwen in de plot wereld.  
  
Wil je weten hoe GeoCraft werkt? Hier leggen we alles uit: geocraft.nl/minecraft-starters  
  
**IP geocraft.nl**  
www.geocraft.nl', 'geocraft.nl', 25565, 'mc_java', 'active', true, NULL, 'http://wwwgeocraft.nl', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mineland-network', 'Mineland Network', '**[1.8 - 1.21.x]** Welcome to **Mineland Network** — the best **Cracked Minecraft server** on the planet! Every day, players from all over the world join us to experience real action and become part of epic adventures.  
  
⏩ IP: **crazy.mineland.net**  
  
🌎 The real excitement starts here!  
Our SkyBlock is unique: all islands, resources, and houses have been **preserved since 2016**! This sky-high world is filled with thrilling quests, a robust economy, and intense battles. Create your own shop, trade at auctions, and become a true millionaire. Discover our unique ore generator system with Auto-Smelting, Filtering, and Leveling Up — your luck depends on it! Battle with the collections system, uncover their secrets, and obtain epic items. Get into the TOP islands and try to stay there because the competition is fierce!  
  
🚂 **Cozy survival with Herobrine on 1.16**  
Team up with friends in clans and defeat your enemies using unique collections that will make you the king of survival! Face the dangers, challenge the mighty Herobrine, build your empire, and earn the respect of other players.  
  
🏹 **Epic battles await you!**  
Ready for real challenges? Take on the challenge in BedWars and SkyWars modes, where strategy and skill determine the winner. Looking for something new? Dive into the RPG world in Prison mode. Don’t forget about our exclusive cosmetics — from cool effects to epic pets!  
  
💥 **Find friends and become part of our community!**  
Discord: https://mineland.net/discord/en  
Forum: https://forum.mineland.net  
  
⏩ IP: **crazy.mineland.net**  
  
Join the best server on the planet ❤️', 'crazy.mineland.net', 25565, 'mc_java', 'active', true, NULL, 'https://mineland.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'businesscraft-cityrp-economy-jobs-democracy', 'BusinessCraft » CityRP • Economy • Jobs • Democracy', '![](https://i.imgur.com/npB962v.png)  
**Welcome to Businesscraft!**  
  
Are you ready to explore a new role play server? Are you ready to adventure the city and find your destiny? BusinessCraft is a minecraft-survival City Roleplay server that uses custom easy to use plugins to simulate aspects of a real city. The server includes a wide selection of jobs such as: Engineer, Miner, Lumberjack, Doctor, Lawyer and many more! This server also has a government and democratic elections!  
  
  
**Server Dynamic Map**  
  
View our server dynamic map by clicking [here](http://mcbusinesscraft.com/map/).  
  
  
  
**Discord Server / Forums**  
  
To Join our Server Discord/Forums, you must join the server by using the server IP and type /links. You will find an array of links, including the server’s website/forums, the Discord server as well as the Store & Dynmap.  
  
  
  
**City Life!**  
  
Live in a cozy house in the suburbs while building your business empire downtown. You can start businesses ranging from agriculture to manufacturing, scale your business into a large corporation or keep it a small local business, or you can work for another company and enjoy everything else the city has to offer!  
  
The city has lots to explore, you can rent apartments including penthouses, explore easter eggs like the sewers, or venture into the acres of wildlife preserve just outside city limits! Buses, trains, subways, and planes can help you travel throughout the city and world. Nearly everything built within the city is player owned and operated.  
  
The servers economy is very dynamic, starting a business is easy but the process can change depending on the governments regulations. Businesses can scale up quickly by hiring other players and advertising. Discords and websites can be made to facilitate business operations and your business will be listed in our services list.  
  
BusinessCraft is based on a democratic government system. Become a part of the Executive Branch by joining a government department and possibly one day running one as a Minister! Or get elected into the Parliament and create new laws with fellow Members!  
  
  
**Wild Life!**  
  
You can choose to live in the wild! Adventure the fierce survival world and build your base. Collect resources to sell them to players or the Government! Regioning your base creates a secure anti-griefing barrier. It prevent players from destroying or stealing anything out of your chests.  
  
  
Join us today, and prepare to adventure the city or wild to find your destiny!', 'play.mcbusinesscraft.com', 25565, 'mc_java', 'active', true, NULL, 'https://mcbusinesscraft.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'craftyourtown', 'CraftYourTown', '**CraftYourTown – Build, Explore, Conquer**  
  
Established in **2017** , **CraftYourTown** has been providing a top-tier Minecraft experience for players who love to build, explore, and take on new challenges. Whether you''re designing your dream town, embarking on epic quests, or battling custom mobs, there''s always something to discover.   
  
**Why Join?**  
✔ **Established & Trusted** – Running since 2017 with a dedicated community.   
✔ **Creative Freedom** – Build, craft, and design without limits.   
✔ **Engaging Quests** – Take on challenges and uncover hidden treasures.   
✔ **Keep Inventory Enabled** – No more losing everything on death.   
✔ **Custom Mobs & Gadgets** – Unique mechanics to enhance gameplay.   
✔ **Community-Driven** – Your feedback helps shape the server.   
✔ **Regular Events** – Compete in minigames and earn valuable rewards.   
✔ **Cosmetics & Custom Tools** – Stand out with unique designs.   
✔ **Active Community** – Meet like-minded players and forge new friendships.   
  
**Join CraftYourTown today and be part of a server with years of history and a bright future.**', 'mp.cyt.gg', 25565, 'mc_java', 'active', true, NULL, 'https://www.craftyourtown.com', NULL) ON CONFLICT (slug) DO NOTHING;
