INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'kriptonpvp', 'KriptonPVP', 'KriptonPVP es una Network de Minecraft donde la calidad estará presente desde el primer momento que te conectes al servidor. Entre todo el staff tratamos de solucionar en el menor tiempo posible todos los problemas que van surgiendo, además de añadir mejoras a la Network para que la experiencia de juego cada día sea mejor. También nos caracterizamos por tener un staff amigable y cercano con los usuarios. Todos los meses invertimos el dinero de las donaciones en tener servidores sin lag, estar abiertos 24/7, en plugins propios, protección anti-DDoS, anti-Hacks y backups.  
  
Como podrás observar entre todos hemos puesto mucho empeño para que el servidor sea como es ahora, así que espero que nos quieras acompañar en esta aventura que estamos seguros que te vas a divertir.', 'mc.kriptonpvp.com', 25565, 'mc_java', 'active', true, NULL, 'http://www.kriptonpvp.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'efsane-craft-1-11-1-12-factions-lapis-edit-yok', 'Efsane Craft » 1.11 - 1.12 » Factions » Lapis/Edit YOK!', 'EfsaneCraft Hard Faction Server - Lapis/Edit Yok! - 6 Yıldır açık kapanma riski yok.  
  
