INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'unknowntekkit', 'UnknownTekkit', 'Tekkit Classic • Minimal Restrictions • 24/7 No Lag • Custom Dynamic Economy • Land Claims • World Anchors* • Longest Running Tekkit Classic Server  
  
**IP:** classic.ut-mc.com  
**Website:** <https://ut-mc.com>  
**Tekkit Classic Version:** 3.1.2  
**Minecraft Version:** 1.2.5   
  
**Server Type:** Survial  
**Land Claiming:** Grief Prevention (Gold Shovel)  
**PVP?** Toggled with /PVP. Can be done almost anywhere at any time, assuming your target has PVP enabled as well.  
**Towny?** We do not offer towny, however you can make towns using Grief Prevention!  
  
**Last Map Reset:** March 1, 2024  
**Note:** We do not intend on resetting the map again.  
  
UnknownTekkit, otherwise known as UT-MC, is the oldest Tekkit Classic server still standing! We launched in June 2014 with the goal to provide the least restrictive Tekkit Classic experience possible. We use a multitude of custom developed patches, fixes, enhancements improve performance, stability, and playability, without compromising on your experience!  
Come find out what UnknownTekkit is all about!  
  
**How to install Tekkit Classic and join the server:** <https://ut-mc.com/classic/getting-started>  
  
![](https://ut-mc.com/media/vsdi.png)  
  
  
In case the server description image above does not appear, here are its contents:  
  
**Why UnknownTekkit?**  
_Unlike many other servers, we constantly strive to provide the best possible Tekkit Classic experience, and greatly value our community!_  
  
**Economy**  
_A dynamic and advanced economy system helps keep a balance between beginning and end game users!_  
  
**Performance**  
_A combination of high end server grade hardware and custom patches provides a smooth and enjoyable experience for all users._  
  
**Staff Team**  
_Our skilled and dedicated staff team ensures that the community remains friendly and provides quality support to users in need!_  
  
**Custom Plugins**  
_We offer many custom plugins to provide features such as a reliable keep inventory system, vote crates, a unique chat based shop system, and cloud chests!_  
  
**Community**  
_We offer a friendly, active, and helpful community that always welcomes new members, and won''t hesitate to lend a hand to those who need it!_  
  
**History**  
_UnknownTekkit, formerly known as Realm of the Unknown, is one of the longest standing Tekkit Classic servers around! We opened our doors on June 8, 2014!_', 'classic.ut-mc.com', 25565, 'mc_java', 'active', true, NULL, 'https://ut-mc.com', NULL) ON CONFLICT (slug) DO NOTHING;
