INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mineclick', 'MineClick', 'MineClick is a unique Minecraft server that features an incremental/idle clicker gamemode. Start your adventure today by joining the server at play.mineclick.net  
  
- You are given your own island where you can mine special blocks.  
- For starters, every mined block gets you 1 gold. In order in speed up your progress you can upgrade your Pickaxe and hire workers that do the job for you. By upgrading your workers you increase their income rate.  
