INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'instacube-dein-leben-server-1-15-2', 'InstaCube | Dein Leben Server 1.15.2', 'Was ist InstaCube?  
InstaCube ist unser Minecraft Server Netzwerk.Wir zeichnen uns durch eine besondere Liebe zum Detail aus.   
Uns ist es wichtig, dass ihr auch noch in den letzten Ecken schöne und überraschende Kleinigkeiten findet.Vom Konzept her sind wir simpel. Unser Ziel war es, ein normales Singelplayer Minecraft zu nehmen und dafür zu sorgen, dass man auch im Multiplayer ohne Angst vor Griefern und Trollen spielen kann. Dabei wollten wir aber möglichst das Singelplayer-Gefühl beibehalten, weshalb wir nicht wie viele andereServer einfach eine Grundstückswelt erstellen und ein Grundstück neben das andere pferchen.Bei uns habt ihr freie Wahl, wo oder ob ihr ein Grundstück macht. Die Welt in der ihr spieltist eine normale Minecraft Welt. Die einzigen Bereiche, die geschützt sind, sind Städte und eure Grundstücke.Außerhalb des geschützten Bereichs herrscht Freebuild (mit PvP).  
  
Was für Möglichkeiten habe ich auf InstaCube?  
Neben dem oben bereits erwähnten Gameplay habt ihr auch die Möglichkeit,euch einen Marktplatz zu mieten, ChestShops zu erstellen, eigene Teleport Punkte zu kaufen (Player warps(für alle zugänglich)) und vieles mehr (+ eine Menge Easter Eggs)  
  
Was gibt es sonst noch zu wissen?  
Wir verfolgen eine "Nicht Löschen"- Politik. Das bedeutet wir werden keine Welt löschen oder ähnliches. Alles bleibt ewig (solange es den Server gibt) zugänglich, auch wenn sich vieles ändert.  
Natürlich entfernen wir unangebrachte Sachen trotzdem. Aber ein normales Haus wird von uns nicht gelöscht werden(Das bedeutet nicht,dass es nicht seinen Schutz verlieren kann und somit dem Freebuild zum Opfer fällt).   
  
Der Server läuft 24/7 (24 Stunden 7 Tage die Woche) und es werden tägliche backups gemacht. Der Server hat eine DDOS Protection. Mit Spenden sollte sich der Server finanzieren, wird aber auch ohne noch sehr lange bestehen bleiben.  
  
TeamSpeak: ts.instacube.at  
Discord: https://discord.gg/pzB9sPG  
E-Mail: support@instacube.at  
  
﻿  
﻿', 'play.instacube.at:25565', 25565, 'mc_java', 'active', true, NULL, 'https://www.instacube.at', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'dexouille', 'Dexouille', 'Dexouille propose un contenu très varié ! Survie, Skyblock, Créatif, Semi-RP, PvP, Jump, des Campagnes et bien d''autres ! Et une zone How to Train Your Dragon ! On est très OldSchool. Le serveur se renouvelle sans cesse ! Venez vous amuser :)', 'dexouille.omgcraft.fr', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
