INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'limitless-pixelmon', 'Limitless Pixelmon', 'Welcome to the world of Limitless Pixelmon!
  
  
