INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'skimdoo', 'Skimdoo', 'Skimdoo es un servidor survival / no premium con una comunidad tranquila y amigable.  
  
