INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'm-lk-dansk-survival-siden-2012', 'MÆLK | Dansk Survival siden 2012!', '**Kunne du tænke dig, at være en del af en SMP server hvor fællesskabet betyder allermest?  
som ovenikøbet har kørt lige siden 2012! (Selvfølgelig med resets ind imellem)**  
  
