INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'jhos-minecraft-server', 'JhoS - Minecraft Server', 'The former [LMT] Server is back with other name. Clan Jhoo has brought the server back to you with a new map, new ideas and a lot of features, but with some of the old staff remaining.  
You can create a faction and play with your friends, raiding dungeons with your party, leveling up skills and getting powerful abilities participating in events that can be quite challenging even if you have full enchanted diamond gear.  
If you dont want to PvP, the PvE server will be opened soon.  
Due to the result of one of the events, players can now bend the elements at their will!  
Will you be a hunter, a vampire or a werewolf?  
See you in Clan Jhoo Server.  
  
JhoS - Forum: https://forum.clanjhoo.com/  
  
Minecraft Server Address: clanjhoo.com', 'clanjhoo.com', 25565, 'mc_java', 'active', true, NULL, 'https://forum.clanjhoo.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'crafters-dk-dansk-minecraft-siden-2010', 'Crafters.dk - Dansk minecraft siden 2010', 'Vanilla | Adventure | Fællesskab | Dansk  
  
Crafters.dk tilbyder:  
- Professionel Serverdrift (Crafters har kørt siden september 2010 og intet resettes).  
- Alle har lige rettigheder og man kan ikke købe sig til fordele.  
- Ingen snyd. Ingen spawn af blokke.  
- Plads til alle, vi er både unge og gamle spillere  
- Nemt at joine, kræver bare en snak med en moderator  
- Discordserver - Her er det let at tale med de andre spillere eller få fat på en Admin/Moderator.  
  
---------------------------------------------------------------------------  
  
_Læs mere om Crafters.dk:_  
  
**Maps**  
Crafters.dk er en af de ældste servere i verden. Vi har eksisteret siden 2010.  
Vi har 3 maps, som der alle kan spilles på.   
_Senex_ - den oprindelige server fra 2010  
_Novus_ - fra 2014  
_Tertius_ - fra 2022  
  
I takt med Minecrafts udvikling, med nye opdateringer, har det været nødvendigt at åbne et nyt map, for at kunne tilbyde spillerne en up-to-date oplevelse af spillet.  
Dog bliver intet resat, fordi på Crafters mister man ikke det man har bygget, og derfor kan man stadig spille på de tidligere servere hvis man ønsker det.  
  
**Hvad er Crafters?**  
Crafters er klassisk Minecraft, i den forstand at vi miner og bygger, dog uden monstre.  
I stedet har vi mining worlds, med mobs, hvor man kan lave mobfarme, og hvor man opfordres til at hente materialer til at bygge med.  
På den måde holdes normal world rimeligt pænt, og fri for store ødelagte områder.  
  
På Crafters er det ikke muligt at købe sig til nogle fordele.  
Og vores staff spiller på lige fod med andre.  
Vi spawner ikke blokke eller ting ind, alt er minet og bygget manuelt.  
  
**En unik oplevelse**  
Crafters er en helt unik minecraft oplevelse, som du ikke finder på andre danske servere.  
Vi har nemlig været med siden spillet var i alpha, og er dermed en meget sjælden ting, ikke kun i Danmark men også i verden.  
På Crafters kan man mærke historiens vingesus, og man kan følge Minecrafts udvikling ved at gå rundt og kigge på de mange byggerier, fra dengang alt var lavet i cobble og planker, og frem til nu.  
  
**Effektivt hold bag serveren**  
De mange år på banen, har givet os stor erfaring i serverdrift. Og vi har i dag et setup som vi er stolte af, med plugins der kan hjælpe vores moderatorer med hurtige og gode løsninger i tilfælde af grief eller tyveri. Alt aktivitet bliver logget, og der kan laves rollback hvis det er nødvendigt.  
  
**Events og venskaber**  
De fleste af de events, og andre fællesarrangementer du finder på Crafters, er lavet af spillerne selv.  
Der bygges offentlige farme af forskellig slags til fællesskabet, også af spillerne selv, fordi vi har et imødekommende fællesskab.  
Ind i mellem arrangeres der spil udenfor serveren, hvor folk mødes og spiller andre spil end Minecraft.  
  
Crafters er med andre ord, mere end bare en Minecraft server. Den er et fællesskab, hvor man i trygge rammer kan hygge sig med vennerne, og finde nye bekendtskaber.  
Man kan vende tilbage efter lang tids fravær og ens ting står stadig som man efterlod dem.  
Vennegrupper er skabt hos os, og flere af dem mødes i virkeligheden.  
  
Vil du gerne vide mere, findes vi på  
Discord: <https://discord.gg/hA3HpaT5yj>  
Facebook: [http://www.facebook.com/itsallaboutthecommunity](https://www.facebook.com/itsallaboutthecommunity)  
Youtube: <https://bit.ly/CraftersYT>  
TikTok: <https://www.tiktok.com/@crafters.dk>  
Hjemmeside: <https://crafters.dk/>  
  
Kig gerne ind, og få en snak, og se om Crafters ikke også er en server for dig :)', 'Crafters.dk', 25565, 'mc_java', 'active', true, NULL, 'http://Crafters.dk', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minexilon', 'MinExilon', '**Bienvenido a MinExilon!**  
  
  
