INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'familymc-full-1-19-survival-skyblock-vanilla', 'FamilyMC Full 1.19 Survival, SkyBlock, Vanilla', 'Welcome to the FamilyMC network! We are fully 1.19 release. We strive to provide a safe environment for everyone to play in 24/7 with 100% uptime and absolutely 0 lag.  
  
We run across two high quality professional dedicated servers featuring our main machine with an overclocked i9-9900k running at 5.1GHz. Through our high performing hardware we are able to provide a high performing minecraft server even on the latest and most demanding minecraft releases!  
  
We offer Survival, Creative, Vanilla, and SkyBlock servers.  
  
Our Survival 1.19 server offers: Land claiming, player shops, player warps, in game ranks, custom enchants, jobs, scrolls, and more!  
Our town is located at /warp Town. Our spawn offers easy access to all features and game play.  
  
Keep inventory is enabled  
You can be randomly teleported into the wild to start playing, or look around spawn and find a place to build a shop.  
Useful Commands:  
/start - for a tutorial  
/warp ClaimTutorial  
/warp ShopTutorial  
/spawn  
/sethome  
/tpa  
/tpahere  
/pwarp  
/msg  
  
Our Vanilla 1.19 server offers: vanilla game play with no plugins, basic rules such as no griefing, and always running the latest version. If a grief ever occurs, message staff and they can have it completely fixed within seconds!  
  
Our SkyBlock 1.14.4 is one of our favorites. It''s fully 1.14.4 and has custom islands, crates, spawners, an auction house, and a vast market place with every material and item you could possibly need!  
  
We can''t wait to see you in game at familymc.xyz!  
  
Be sure to join our discord: discord.gg/YVDapVP', 'familymc.xyz', 25565, 'mc_java', 'active', true, NULL, 'https://www.familymc.xyz', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minetown-mining-since-09-2010', 'Minetown - Mining since 09/2010', 'Looking for a laid back and friendly server with a focus on the community? Tired of Pay to Win servers that make it impossible to enjoy the game without paying for it? Just want to play Minecraft with friends without a bunch of overbearing rules and restrictions? If so, come join us on Minetown! Our IP is **MT.GG** (Bedrock Port **19132**)  
  
There''s a lot to do on our server network! Our main map, **Idarun** , is the current generation of our long-term survival economy world, and features claim protections, shops, warps, teleports, clans, and lots more! The economy is based around player-run shops and cities, and gives shop owners the freedom to set their own prices, giving every player an equal chance to succeed. We also have a **Creative** server, giving a place to do everything from testing your farms to wowing everyone with your building prowess. Finally, we also offer an **Event** and **UHC** server, if you want a place to just play games rather than build.  
  
Our focus on player experience gives you the freedom to design what you want and play how you want. We have an active and friendly community of players from all over the world, doing everything from building complicated cities and farms to simple tree punching! Additionally, we are one of the oldest servers in existence, having been founded in September 2010! If you want to have a great multiplayer experience, join Minetown today!', 'mt.gg', 25565, 'mc_java', 'active', true, NULL, 'https://minetown.net/', NULL) ON CONFLICT (slug) DO NOTHING;
