INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'gahvila', 'Gahvila', '**Gahvila** on vuonna 2018 avattu suomalainen Minecraft-palvelin, jonka päätavoitteena on luoda yhteisöllinen ja mukava peliympäristö muokkauksin alkuperäisen pelin päälle.  
  
Palvelimella on tarjolla kaksi pelimuotoa: **Survival** ja **Luova** ;  
  
**Survival** tarjoaa klassista Minecraft-kokemusta elämää helpottavilla lisäominaisuuksilla, kuten kodit, warpit, ja erilaiset pelivaluutalla ostettavat lisäosat. Survivalissa on monipuolinen ekonomia, joten tapoja tuottaa massia on monia.  
  
**Luova** -pelimuodossa pelaajat voivat rakentaa omille ploteilleen rajattomasti hyödyntäen useita tarjolla olevia rakennustyökaluja, kuten WorldEdit, VoxelSniper, HeadDatabase ja muita. Nykyisellä Luovan kartalla on jo pitkä historia, sillä se alunperin avattiin vuoden 2020 alkupuolella. Inspiraatiota omiin rakennelmiin saa helposti muiden tuotoksista, ja rakentamiseen saat varmasti apua kun vain kysyt. Kartan nollausta ei ole suunnitelmissa, joten voit olla varma että rakennelmasi pysyy tallessa.  
  
Palvelimelle on lisäksi tulossa pian uusi Aula, josta tulee löytymään useita minipelejä pelattavaksi tovereidesi kanssa.  
  
Lisätietoja pelimuodoista ja niiden ominaisuuksista löydät [Gahvila dokumentaatiosivulta](https://gahvila.net/docs/).  
  
Verrattuna suurimpaan osaan suomalaisista palvelimista, Gahvila ei pyri tuottamaan voittoa, eikä se myy mitään tuotteita. Palvelinta tehdään pelkästään rakkaudesta käsityöhön ja tarjoamme tuotoksemme kaikille koettavaksi. Tämä tarkoittaa, että kaikki toiminta palvelimella perustuu vapaaehtoisuuteen ja intohimoon. Pyrimme toteuttamaan kaikki pelaajien antamat hyvät ideat mahdollisuuksien mukaan.', 'mc.gahvila.net', 25565, 'mc_java', 'active', true, NULL, 'https://gahvila.net', NULL) ON CONFLICT (slug) DO NOTHING;
