INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'terraconia', 'Terraconia', 'Mit Terraconia vereinen wir drei wesentliche Konzepte: Survival, Freebuild und Citybuild ergeben eine Spielidee, bei der nahezu alle Spielergruppen auf ihre Kosten kommen.  
  
Es gibt keine langweiligen aneinander geklatschten Grundstücke, sondern eine wunderschöne Welt mit verschiedenen Städten, die von Spielern gegründet, verwaltet und ausgebaut werden. Die Statthalter entscheiden darüber, ob und wie sie Grundstücke in ihrer Stadt anbieten wollen: Groß oder klein? Teuer oder umsonst? Zur Miete oder zum Kauf?  
  
Damit eine Stadt zur nächsten Stufe aufsteigen kann, benötigt diese neben Geld und anderen Voraussetzungen auch Einwohner. Eine Stadt, die keine Grundstücke anbietet, kann sich deshalb ab einem gewissen Punkt nicht weiterentwickeln.  
  
Jede Stadt fängt mit einem normalen Grundstück an, welches sich jeder Spieler kaufen kann. Wer das Geld und ein ausreichend großes Grundstück hat, kann daraus eine Stadt machen. Die unterschiedlichen Stadtstufen bieten verschiedene Erweiterungen für die Stadt und ihre Einwohner und erhöhen die Kapazitäten der Stadt.  
  
Die gesamte Welt ist an sich nicht geschützt, sodass ihr überall bauen könnt. Wer keine Lust auf Städte oder andere Spieler hat, der baut halt alleine drauf los oder besorgt sich ein privates Grundstück.  
  
Erst durch eine Erweiterung kann PvP innerhalb der Stadt deaktiviert werden. Dadurch ist es nicht mehr möglich, dass Spieler von anderen Spielern angegriffen werden. Ansonsten können sich Spieler jederzeit angreifen.  
  
Interesse geweckt? Dann schau auf unserer Internetseite vorbei!', 'terraconia.de:25565', 25565, 'mc_java', 'active', true, NULL, 'https://terraconia.de/willkommen', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'knight-network', 'Knight Network', 'Knight Network Minecraft Sunucusu  
  
