INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'monumenta', 'Monumenta', '**Monumenta is a free Minecraft-based, Survival-mode, action-oriented MMORPG, with a foundation in the Complete the Monument (CTM) genre of adventure maps.**
  
![](https://playmonumenta.com/img/logo.png)  
  
With over 20 huge, handmade dungeons, over a hundred quests, 1000+ custom items, eight customizable classes, and multiple enormous overworlds to connect everything together, Monumenta is a truly massive adventure that can be played solo or cooperatively for hundreds of hours with almost no repetitive grinding.  
Monumenta has remained live since Closed Beta in June 2017 and updates weekly with new content and bug fixes. It is a community-driven project which is and always will be free to play.  
  
Join today! server.playmonumenta.com  
