INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ccnet', 'CCNet', 'CCNet is back, with two new and fresh gamemodes!  
  
**CCNet Nations** is a unique server set on a 1:1000 map of the Earth.  
  
![](https://wiki.ccnetmc.com/nations/ships/dreadnought.png)  
  
Build moving, fully-functional **warships** , **ground vehicles** and aircraft to wage war across the globe using our in-depth, heavily-customized version of the Movecraft plugin.  
  
Experience a **dynamic, player-run economy** comprised from over one thousand player shops, facilitated by custom plugins to enhance shop discovery and arrange trade contracts.  
  
Fight in **wars** involving dozens of players, intense combat and vehicles of all kinds.  
  
Deploy your navy to seize control of vital naval chokepoints, such as the Suez Canal and Straits of Gibraltar.  
  
Explore the **Slimefun** plugin to industrialize and build up the productive capacity of your nation.  
  
Whether you are a PvPer, diplomat, shipbuilder, nation leader or builder, there is a place for everyone on Nations.  
  
  
  
**Towny** is for those who would like to build. Construct a town, and band together with other people to create a thriving nation. Construct massive factories, huge machines and epic gear with Slimefun! Lead your nation to victory during wars, or live peacefully by yourself - the choice is yours. Watch out for powerful infernal mobs though!  
  
You can visit our website at cometcraft-reloaded.enjin.com.  
  
We hope to see you ingame!', 'mcmp.ccnetmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://ccnetmc.com', NULL) ON CONFLICT (slug) DO NOTHING;
