INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ohanacraft', 'Ohanacraft', 'We are a family friendly server that currently offers a lobby, survival, creative, game server with minigames like turfwars, tower defense, bedwars and sky block in the near future. Our community was created from a group of admins and staff from Towncraft.   
