INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), '90gqopen', '90gQopen', 'Våra spellägen erbjuder något för alla, oavsett om du gillar att utforska, bygga eller tävla mot dina vänner. Dessa erbjuder vi just nu:  
🏠**Survival**  
Utforska, samla resurser och bygg ditt drömhus, eller varför inte öppna en affär?  
🏃**Parkour**  
Utmana dig själv genom att klara parkour-banor på så kort tid som möjligt. Vem vet, du kanske även slår rekord!  
🎨**Creative**  
Bygg med kraftiga verktyg som WorldEdit och VoxelSniper för att skapa något fenomenalt!  
🎵**Musical Blocks**  
Dansa loss till musiken, men se till att stå på rätt färg innan den pausas!  
🎉**Event**  
Var med när vi spelar en mängd olika minispel för att fira helgens ankomst! Varje fredag kl. 20:30!  
⚔️ **Ultra Hardcore**  
Skapa ett lag, samla resurser och bekämpa andra lag för att till sist ta hem segern! Varje lördag kl. 20:30!  
  
🔗 Besök vår hemsida för mer information och nyheter: https://90gqopen.se', '90gqopen.se', 25565, 'mc_java', 'active', true, NULL, 'https://90gqopen.se/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'skogliv-no', 'Skogliv.no', 'Vi lagde Skogliv.no sommeren 2018 etter at NRK Super la ned sin Minecraft-server Ragnarok. Gjennom vårt arbeid i NRK Super oppdaget vi nytten og gleden barn og unge hadde av å ha et sted på internett hvor de kan oppholde seg innenfor trygge rammer, satt og passet på av voksne. Et digitalt fristed hvor de kan være seg selv, men også være trygge på at det er voksne personer på dette fristedet som de kan kontakte om det skulle være behov.   
  
Vi ønsker å rette en stor takk til våre frivillige Vakter og Moderatorer som gjør en kjempeinnsats med å passe på at alle har det bra på Skogliv!   
  
Håper vi ses på Minecraft!  
IP: Skogliv.no', 'Skogliv.no', 25565, 'mc_java', 'active', true, NULL, 'https://skogliv.no/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'the-war-of-the-ring-mc', 'The War of the Ring MC', 'Step once more into Middle-Earth, and enter the War of the Ring. A team of enthusiastic and dedicated people have come together to bring forward the best Lord of the Rings MineCraft experience out there.   
  
Once you enter the world you will start your journey. Select the race you will play as: Mordor Orcs, Rohirric Man, Shire Hobbit and more. Enter into a protected marketplace, and begin your adventure. Go mining in the Misty Mountains for Mithril, or grow pipeweed near Hobbiton. Go seek the treasure of Erebor, or bend the knee to the Dark Lord in Mordor.   
  
Bring your friends or make allies to begin to earn Renown across the lands as someone to follow. Build your Seat of Power, and from their grow your armies until you are ready to wage war! Once you have become strong enough, you can become a true King!   
  
This is not a game that everyone will win, this is a war! Bring your intellect, cunning, and knowledge to the table if you have any hope of gaining a Ring of Power. Let alone the One Ring.....  
  
Step into Middle-Earth one more time at www.wotrmc.com  
https://discord.gg/mUuvFfN', 'wotrmc-world1.com', 25565, 'mc_java', 'active', true, NULL, 'http://www.wotrmc.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'balkania-craft-towny-ekonomija-krekano-cro-srb-bih', 'Balkania Craft || Towny, Ekonomija || Krekano || CRO/SRB/BiH', '- BALKANIA CRAFT -  
NAJVECI MINECRAFT TOWNY SERVER NA BALKANU  
  
Cilj igranja na našem Minecraft serveru na početku je da sagradis svoju vlastitu bazu u divljini i suocavas se sa opasnocu mobova i drugih igraca i zaradis dosta novaca da se preseliš u jedan od naših towny gradova koje su osnovali i odrzavaju naši mayori, kada se preseliš u grad zasticen si od griefa pvpa i reidanja i mozes da napredujes u gradu da postanes co-mayor i pomazes gradu da bude najveci i najmocniji grad na serveru!   
  
Towny:  
Balkania Craft je bazirana na minecraft Role-Playu, Towny gaming aspektu, sagradi svoj grad i budi najjaca sila na serveru uz pomoc suigraca! Procitate vise informacija na nasem discordu.  
  
Ekonomija:  
Oporezuj igrace, prodavaj zemljista, napravi svoj shop, prodavaj stvari na auction house ili sagradi svoj shop u svom minecraft towny gradu i prodaj svoje resurse koje ce ti pomoc da budes sve jaci i jaci na balkaniji craft!  
  
I ne samo to nego imamo jedan od najfriendly communitija u minecraftu! Dodi i pridruzi nam se :)', 'play.balkaniacraft.com', 25565, 'mc_java', 'active', true, NULL, 'http://balkaniacraft.com', NULL) ON CONFLICT (slug) DO NOTHING;
