INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'the-seed', 'The Seed', 'The Seed was created with one thing in mind - Minecraft. For the players that are looking for a server that has countless custom-coded features, The Seed isn''t for you. While we do have custom features, our goal is to keep The Seed simple and community-based for those that just want to play Minecraft with friends. So, here''s what we offer:  
  
- Player Shops | Anybody and everybody is allowed to create their own shop  
- Player Warps | Once you are a Nomad (play for one hour), you can create public warps  
- User-Friendly Land Claiming | Protect your property with ease  
- Rank promotions for playing on the server | Each Rank has it''s own upgrades  
- Pets | Every player is able to tame their own pet by killing any animal with a lead  
- Player-Driven Economy | The Seed sells a limited amount of items at it''s shop. Go buy and sell   
from other players!  
- Friendly Community | Although we are a new server, we encourage our future players to be   
mature, respectful, and friendly!', 'theseedmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/seed', NULL) ON CONFLICT (slug) DO NOTHING;
