INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), '0b0t-org-minecraft-anarchy-server', '0b0t.org - Minecraft Anarchy Server', '**0b0t is a minecraft anarchy server from 2016 and a good alternative to the popular server 2b2t, but without the long queue. Hacks, swearing, raiding and everything else is allowed. There are basically no rules. The server features vanilla survival gameplay, with only soft anticheat and teleportation outside the spawn area. The owners are almost not intrusive and everything you can see on the server was created by the players. 0b0t is also known for its active mapart making community. There are active dupes and most players are friendly and will give you equipment. The server had some ownership changes over the time, but the current map of 0b0t is based on the map from july 2016.**', '0b0t.org', 25565, 'mc_java', 'active', true, NULL, 'https://0b0t.org', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'sofurry-minecraft', 'SoFurry Minecraft', 'SoFurry Minecraft is a vanilla minecraft server that strives to bring people close together for some fun, clean minecraft fun. We are a growing network, backed by the popular furry website, SoFurry.com. Everyone is welcome on our server, furry or not, and we have plenty for people to do; whether you want to work jobs to make money and buy things in player or admin shops, or if you want to level up skills to multiply your ores, the possibilities are endless!  
  
NOTE: We plan to expand into the modded minecraft scene by the end of the year, but until then, our vanilla server is more than happy to accept you!', '173.214.175.34', 25565, 'mc_java', 'active', true, NULL, 'http://sfmc.sofurry.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'purity-vanilla', 'Purity Vanilla', 'Purity Vanilla is a vanilla anarchy Minecraft server running since 23rd of March 2019, designed to give players total freedom to play Minecraft just as the developers intended. This means there are no gameplay-alterting plugins, no teleportation, no playerhomes and no pre-determined economy. Everything is left up to our players. Griefing and raiding are permitted and there are no grief-prevention methods.', 'mc.purityvanilla.com', 25565, 'mc_java', 'active', true, NULL, 'http://www.purityvanilla.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'aqua-ruby-community-server-towny-friendly-survival', 'Aqua Ruby - Community Server [Towny - Friendly - Survival]', 'Welcome to the Aqua Ruby Community Server!  
  
Ip address: **aquaruby.mc.gg**  
