INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'faithavenue', 'FaithAvenue', 'FaithAvenue is Christian faith focused family friendly city themed network. Our server is packed with all the latest plugins (over 50) and tons of custom content/gear for you to enjoy! We have a massive 1400 block wide by 2400 block long interactive city. Filled with random events, shops and hundreds of places to call home. We also always have the latest survival world and never delete maps. Our staff are well seasoned and always willing to help. Ranks are class based with tiers and are completely free, each class has a feature packed guild to visit. Our classes are Economist, Archer, Soldier, Worker, Traveler, Architect and Thieves. We have custom enchants, with hundreds of hand made items built into the events as loot!  
  
So pop your head in and get to know us, we promise you''ll find us to be your new second home!', 'FaithAvenue.host', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'sparkcraft-vanilla', 'SparkCraft Vanilla', 'SparkCraft Vanilla – приватный ванильный сервер с классическим выживанием без привата, доната и лишних плагинов. Честный, комфортный, ламповый сервер, созданный для души.  
У нас вы сможете отдохнуть, наслаждаясь уютной и атмосферной игрой в дружном коллективе.  
  
Сервер поддерживает вход как с лицензионного клиента, так и с пиратки.  
  
ВАНИЛЬНЫЙ СЕРВЕР  
Наш сервер предполагает максимально классическое ванильное выживание, которое придётся по вкусу как новичкам, так и опытным игрокам.  
На сервере присутствуют плагины, но они НЕ меняют каким-либо образом существующий оригинальный геймплей, в основном они нужны для управления сервером.  
Без телепортаций. У нас нет таких команд, как /home, /rtp, /call, /spawn и подобных. Все перемещения по миру происходят своим ходом.  
Без экономики. Наша форма торговли - бартер.  
Без привата территориии. В этом просто нет необходимости, все держится на полном доверии.  
Без доната. На нашем сервере все игроки равны между собой.  
Без кит старта и халявы. Вы начинаете игру со спавна абсолютно пустым.  
У нас также отключена защита от мобов: криперы могут разрушать постройки, эндермены воровать блоки, зомби ломать двери и т.д.  
Всё, как и в обычной одиночной игре, только с игроками.  
  
ГРИФЕРСТВО, ЧИТЕРСТВО И ВОРОВСТВО СТРОГО ЗАПРЕЩЕНО  
Мы ведь не для этого пришли сюда играть, правильно?  
Наша цель - объединить на сервере адекватных игроков, которые хотят насладиться игрой в уютной, дружеской атмосфере.  
У нас запрещено гриферство, читерство, воровство и дюпы. За это нарушитель получит БАН, без возможности вернуться назад.  
Если ваше имущество пострадает – нарушителя накажут, а полученный ущерб можно будет откатить. Мы ведем логи и всё можно очень легко вычислить.  
  
ПОЛНАЯ СВОБОДА ФАНТАЗИИ  
Вы можете строить города, деревни, создавать поселения, торговать с другими игроками, устраивать совместные вылазки в шахты, исследовать мир.  
Всё ограничивается лишь вашей фантазией. Творите, создавайте, изобретайте, покоряйте!  
  
ВЗАИМОДЕЙСТВИЕ МЕЖДУ ИГРОКАМИ  
У нас есть беседа сервера в VK и сервер Discord, где вы сможете пообщаться с игроками сервера, что-то обсуждать и строить планы.  
Чат сервера транслируется в Discord канал и есть возможность общаться с игроками сервера со своего смартфона или компьютера, даже не заходя на сервер.  
Каждый игрок может основать свой клан. Если вас от 3 и более человек, то вы можете официально зарегистрироваться, получив префикс.  
  
ВЫСОКАЯ ПРОИЗВОДИТЕЛЬНОСТЬ И СТАБИЛЬНОСТЬ  
Сервер расположен на выделенной машине (i7-4790K / 32 ГБ ОЗУ / 240 ГБ SSD).  
Мы постоянно следим за обновлениями ядра сервера, оно всегда находится в актуальном состоянии и имеет самые последние исправления и доработки.  
Также на сервере были исправлены некоторые потенциально опасные игровые эксплоиты.  
Если вы искали комфортный, честный и стабильный сервер, то вы пришли по адресу.  
Проект SparkCraft существует с 2012 года, а данный сервер был открыт в марте 2019 года.  
  
ПЛАТНЫЙ ВХОД  
Почему на сервере платный вход?  
Мы ежемесячно оплачиваем аренду выделенной машины, на которой расположен сервер, а так как на сервере полностью отсутствует донат, нам необходимо вести какие-то сборы с игроков.  
К тому же, платный вход является некой гарантией адекватной игры. Вы сможете в комфортной обстановке играть на сервере со своими друзьями, не беспокоясь, что кто-то придет и ради фана разрушит ваш дом. Кому захочется платить деньги, чтобы просто побаловаться?  
  
Присоединяйся к нам и получай удовольствие! ;)', 'vanilla.sparkcraft.ru', 25565, 'mc_java', 'active', true, NULL, 'https://vanilla.sparkcraft.ru/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mucraft', 'MuCraft', 'En svensk survival server (SMP) med en mysig och lugn atmosfär för dig att bygga och leva tryggt. Vi har funnits i flera år och erjuder nog den enda platsen för spelare att kunna gå tillbaka flera år i tiden och kolla på vad man byggt och åstadkommit i spelet. Varmt välkommen till MuCraft!', 'spela.mucraft.se', 25565, 'mc_java', 'active', true, NULL, 'http://mucraft.se', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'obscuros-pixelmon', 'Obscuros Pixelmon', '![](https://i.imgur.com/DN5mxGX.gif)  
  
Looking for a Pixelmon Server? We offer a home that never resets, where you can play any way you want. Whether that''s casual survival style with progression or adventure-like with challenges, or party-like with minigames, we got it all in one creative package with a lot of heart.   
  
Come join us and let us surprise you with a truly unique and original experience like you''ve never seen before. Explore and enjoy of our many features in company of beautifully designed Obscuros Regional Pokémon and a friendly, active community of players.   
  
Instead of resets we add constant feature updates to keep players engaged and passionate about the server for a long time.  
  
The easiest way to get started playing is by installing our Technic Pack here: https://www.technicpack.net/modpack/obscuros-pixelmon.1599542/  
Other Installation Methods: https://obscuros.fandom.com/wiki/Installing_Pixelmon  
  
Server IP: mc.playobscuros.com  
  
Discord: https://discord.gg/HqwwFHK  
Gallery: https://obscurosofficial.wixsite.com/obscurosgallery  
Wiki: https://obscuros.fandom.com/wiki/Obscuros_Pixelmon_Wiki  
----------------  
FEATURES  
----------------  
• Friendly Community: Community focused server  
• User-friendly layout. Use your NavGear or /nav for easy navigation  
• Obscuros Regional Pokémon: Unique Forms with different textures/stats/abilities/moves/sprites  
• Naturally-spawning: Obscuros Form Pokémon & Custom Texture Pokémon [They are like 2nd shinies but more common]  
• Obscuros Starters: 2nd Starters with unique typings   
• Bug Contest: Hourly Contest, earn Bug Catching Points and claim unique rewards at /warp NationalPark  
• Fishing Contest: Hourly Contest, Earn Fishing Points with a unique system and claim rewards at /warp FishingHamlet  
• McMMO: Level Up System  
• Treasure Hunts: Collect hidden treasures in the cities for Obscuros Form Pokémon & unique rewards  
• Game Corner: Gamble and win prizes  
• Pokémon Crane Game: Daily self-contained minigame. Anyone can participate, no advantages outside of skill and luck!  
• Giant Pokémon Boss Raids: See raids schedule in our Discord (daily)  
• Obscuros Region: Custom Cities to explore, with Boss Trainers and unique features  
• Lunar New Year: Claim a unique Regional Form Dynasty Pokémon every year at /warp LunarNewYear  
• Player Gyms ║ Player Elite Four ║ NPC Gyms ║ [open applications]  
• Player Gym Rewards: Defeat Player Gym Leaders twice to get exclusive Gym Custom Textured Pokémon  
• Pokémon Parks: Pal Park, Safari, National Park, Eterna Forest, & more  
• Monthly Tournaments ║Monthly Drop Party [items donated by players]  
• Events & Contests: [Iki Town Festival | Lake of Rage | Pokémon Snap | Fishing Contest | Bug Catching Contest | & more]  
-------------------------------  
TRAINER GAUNTLETS  
-------------------------------  
• Mt. Battle: Battle through all 100 Trainers for increasingly lucrative rewards  
• Battle Tower: Battle endless randomized trainers to earn Battle Points and claim great rewards  
• Rocket Castle: Battle Team Rocket to earn exclusive Pokémon and rewards  
• Gym Leader Castle: Earn Castle Coins by defeating NPC Leaders & Trainers  
• Battle Café: Battle all 3 Café Masters daily for delicious rewards  
----------------------------------------  
UNLOCKABLES & REWARDS  
----------------------------------------  
• Obscuros Regional Pokémon: Unique Forms with different textures/stats/abilities/moves/sprites  
• Pokédex Rewards: Unique rewards as you catch more Pokémon  
• Earnable in-game Ranks  
• Unlockable Areas & /kits  
• Aura effects: Particles for your Pokémon  
• Octillery''s Vote Shop: Exchange vote tokens for special goodies  
• Mall: Use your well-earned PokeDollars to get a variety of exclusive Pokémon  
• Persian''s Gold Shop: Use PokeDollars for a chance to get random Gold Pokémon, Gold Bottle Cap & Auras  
--------------  
UTILITIES  
--------------  
• NavGear: User-friendly layout. Use your NavGear or /nav for easy navigation  
• PokeSell: Sell Pokémon to Shopkeepers!  
• Pokémon Modifications: Buy Pokémon mods with in-game currency [not cheap]  
• EV Training Arenas  
• Level Up: ''''Zen Garden'''' Training Zone  
• Farm World: For resource gathering  
• Public Mines: /warp Mine & /warp Mine2  
• Daycare: with Virtual Ranch Blocks [for better performance]  
• All Ride Pokémon Enabled [no tokens required]  
• GTS║Wondertrade║Hunts║Ultra Space enabled  
• Keep Inventory║-Land & Chest Protection  
  
Twitter: @PlayObscuros  
Instagram: @PlayObscuros  
Twitch: PlayObscuros', 'mc.playobscuros.com', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/HqwwFHK', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minescape', 'MineScape', 'MineScape is an exciting Minecraft server that brings together the enchanting worlds of Minecraft and OSRS. Whether you''re a fan of the nostalgic graphics, captivating quests, or thrilling PvP battles, MineScape offers a unique and immersive experience that combines the best of both games.  
  
Immerse yourself in a meticulously crafted world inspired by OSRS, where you''ll find iconic locations, familiar characters, and a vast array of quests to undertake. From exploring the sprawling cities of Varrock and Lumbridge to venturing into the treacherous Wilderness, MineScape offers endless opportunities for adventure and exploration.  
  
Choose from a variety of skill sets, including combat, mining, woodcutting, fishing, and more, as you strive to level up your character and become a formidable force in the realm. Engage in intense PvP combat against fellow players, form alliances, and compete for glory in epic battles that will test your skills and strategy.  
  
But the journey doesn''t end there! MineScape also features an active and passionate community of players who are ready to collaborate, trade, and embark on grand adventures together. Join guilds, participate in player-run events, and forge lasting friendships as you navigate the rich and immersive world of MineScape.  
  
So grab your pickaxe, sharpen your sword, and embark on a grand adventure like no other. The MineScape Minecraft Server awaits you!', 'minescape.com', 25565, 'mc_java', 'active', true, NULL, 'https://minescape.com', NULL) ON CONFLICT (slug) DO NOTHING;
