https://discord.gg/v7NZpPC', '127.0.0.1', 25565, 'mc_java', 'active', true, NULL, 'https://www.rcthemepark.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'colis-o-do-tempo', 'Colisão do Tempo', 'Servidor com MODS 1.7.10 Pirata e Original, MODPACK leve com staff 24 hrs e servidor também 24 horas sem LAG  
  
