INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'moddedvanilla-1-21-11-no-plugins', 'ModdedVanilla [1.21.11] [No Plugins]', 'A Vanilla Minecraft Server with a strong focus on community, driven by a self-made Datapack.  
  
