INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'powacraft', 'PowaCraft', '**⚔️ POWACRAFT | Battle Royale, Survival, PVP ⚔️  
Pripoj sa na PowaCraft už teraz!**  
MC.POWACRAFT.EU  
BEDORCK PORT: 41122  
  
**Čo server ponúka?**  
Na serveri nájdeš veľký počet minihier z ktorých si každý vyberie to svoje. Na PowaCrafte sú pravidelné updaty minimálne raz za týždeň. Pri minihrách používame vlastný resourcepack, pre vylepšenie Vášho zážitku. O server sa starajú admini s dlhoročnou skúsenosťou. Na serveri je úžasná komunita ľudí, ktorá už vyše 7 rokov drží tento server.  
  
**Aké minihry u nás nájdeš?**  
⛏️ ECONOMY SURVIVAL 💸  
Na PowaCrafte je klasický vanilla survival so zopár zmenami ako sú custom svet, lobby questy a zopár custom itemov. Na custom svete nájdeš množstvo nových biomov, jaskýň a štruktúr, ktoré môžeš objavovať!  
Na survival lobby môžeš nájsť NPC obchody, kde si môžeš kupovať špeciálne itemy. Nájdeš tam aj quest NPC, vďaka ktorým si vieš zarobiť, alebo ti dokážu poradiť s crafting receptmi.  
Survival je pravidelne aktualizovaný a môžete sa na ňom stretávať s rôznymi eventmi a novými vecami!  
A ak by ťa nebavil klasický survival, na serveri nájdeš aj SLIMEFUN!  
  
🔫 BATTLE ROYALE 🔫  
Pravý Minecraft Battle Royale zážitok zažiješ iba na PowaCrafte! Sme jedni z prvých, ktorí prinášame na Česko-Slovenskú scénu Battle Royale minihru. Nájdeš tu limitované eventy (Heist, Only Grenades, Hunger Games...), Kity, Množstvo zbraní a viac! Battle Royale si môžeš zahrať aj s kamarátmi (Solo, Duo, Squady).  
  
⚔️ PVP⚔️  
Na PowaCrafte nájdeš aj PVP minihru, kde si môžeš zahrať klasické 1v1 (v rôznych modoch ako sú Sumo, Combo, SkyWars... ), Bot Practice, Rankedy a omnoho viac! Je tu veľa máp na každý mode a pravidelne pridávame nové!  
  
⬇️ ĎALEJ U NÁS NÁJDEŠ ⬇️  
⚔️ BEDWARS, SKYWARS ⚔️  
🏝️ SKYBLOCK, ONEBLOCK, SLIMEFUN 🏝️  
🔨 CREATIVE A BUILD BATTLE 🔨  
  
☎️ KONTAKT ☎️  
Instagram: https://instagram.com/powacraft  
Discord invite: https://powacraft.eu/discord  
Web: https://www.powacraft.eu/  
TikTok: https://www.tiktok.com/@powacraft', 'mc.powacraft.eu:25655', 25565, 'mc_java', 'active', true, NULL, 'https://powacraft.eu', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'enchanted-reef-mc', 'Enchanted Reef MC', 'Hello and Welcome to the all new Enchanted Reef Minecraft server!  
  
  
