INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'powerplex', 'PowerPlex', 'Welcome to PowerPlex – the Minecraft server where adventure meets story!   
