INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'siriusmc', 'SiriusMC', '**_Modpacks:_**   
Tekkit SMP (v1.0.5) | Tekkit 2 (v1.2.6) | The 1.12.2 Pack (v1.6.6) | RLCraft (v2.9.3) | All The Mods 10 (v4.14) | All The Mods 10: To The Sky (v1.6.1)  
  
