INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minecraft-brasil', 'Minecraft Brasil', 'Minecraft Brasil é um servidor de Minecraft que oferece uma experiência de jogo única para os jogadores brasileiros. Com uma comunidade vibrante e ativa, este servidor é um dos melhores lugares para se divertir jogando Minecraft online.  
  
Atualmente, o servidor Minecraft Brasil apresenta o modo Pixelmon, onde os jogadores podem explorar o mundo do Pokémon dentro do jogo Minecraft. Este modo de jogo é uma das principais atrações do servidor, e tem atraído muitos jogadores que são fãs de Pokémon.  
  
No modo Pixelmon, os jogadores podem capturar, treinar e batalhar com os seus próprios Pokémon, em um ambiente totalmente imersivo. A jornada para se tornar o melhor treinador de Pokémon é emocionante e desafiadora, e os jogadores podem contar com o suporte da comunidade para avançar em suas aventuras.  
  
Mas o Minecraft Brasil não para por aí. Em breve, o servidor irá lançar outros modos de jogo para que os jogadores possam experimentar novas aventuras e desafios. O servidor está em constante evolução, e a equipe de desenvolvimento está sempre trabalhando para trazer novidades para a comunidade.  
  
Se você é um fã de Minecraft e está em busca de uma comunidade divertida e acolhedora para jogar, o Minecraft Brasil é o lugar certo para você. Venha se juntar a uma das comunidades mais animadas do Brasil e experimente a emoção de jogar Minecraft com outros jogadores apaixonados pelo jogo!', 'jogar.minecraft-brasil.com', 25565, 'mc_java', 'active', true, NULL, 'https://loja.minecraft-brasil.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'eternia-pixelmon', 'Eternia Pixelmon', 'Welcome to Eternia, a Pixelmon Minecraft server where you can catch, train, and battle with your favorite Pokémon! Explore the vast world of Minecraft and discover rare and powerful Pokémon along the way. Join forces with other trainers and battle against formidable foes and become the ultimate Pokémon Master. Join us today and start your journey to become the very best!  
  
What do we offer?  
