INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'firestarter-community-driven-1-21-smp', 'Firestarter - Community-driven 1.21 SMP', 'Firestarter is the simple yet exciting community Minecraft experience you’ve been looking for! Whether you just love to play the game with friends or want to indulge in massive community projects, we welcome you Firestarter with open arms!  
  
To keep it simple, we offer these features:  
- Unlimited homes for everyone  
- Playtime ranks: enhance your experience simply by being online and active  
- Claiming & grief protection: claim your builds to protect them from grief! Trust your friends to your claims or create fully-fledged towns with smaller plots. You’re the imperialist!  
- Player-driven economy: the players decide how the economy functions! Our admin shop is very limited, so players are encouraged to create their own shops and compete with other players.  
- Exciting community: we encourage a friendly, respectful, and mature community on our server.   
- Tons of small quality-of-life tweaks: Firestarter focuses heavily on the quality of life. We want to make the game as fun as possible; hop on and start exploring!  
  
We hope to see you online!', 'mmp.firestartermc.com', 25565, 'mc_java', 'active', true, NULL, 'https://firestartermc.com', NULL) ON CONFLICT (slug) DO NOTHING;
