INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mcnext-survival-server', 'MCNext | Survival Server', 'MCNext is the successor of the MCNEXT server that was run by Athene. This server is owned by Athene''s mother, aka The Mommy, and Athene''s brother MinecraftTosog, and is free to join.  
  
