INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mc-ages', 'MC-AGES', 'Pixelmon Server – Opening 1st September 2024.  
  
MC-Ages is a small but growing network. All our main game servers rest at the end of August ’24 and are running on the latest Minecraft version - 1.21.x.  
  
