INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'world-of-keralis-survival-creative', 'World of Keralis | Survival & Creative', 'This is the Official Website, Discord, and Minecraft Network of The Famous Youtuber, Keralis. Come be a Part of Our Community!
  
  
