INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ohboii-survival-server-freebuild-citybuild', '[ohboii] Survival Server (Freebuild / Citybuild)', '---===[OHBOII]===---  
KLASSISCHER SURVIVAL SERVER  
  
  
Der [ohboii] Survival-Server stellt sich gegen den Trend der PvP und Minispiel-Server. Wir bieten einen klassischen Survival-Freebuild, wie man es im Jahre 2011 noch von vielen großen Servern gewohnt war.  
  
  
  
In unserem Freebuild kannst du ganz deinen Minecraft-Gewohnheiten nachgehen, wir setzen kaum Limits, welche dein Erlebnis einschränken. Wir wollen das Vanilla-Minecraft Gameplay durch ein paar kleine Komfort-Features ergänzen, welche insbesondere den Interaktionen mit anderen Spielern dienen, aber auch den Buildern tolle, neue Möglichkeiten verschaffen!  
  
-=CLAIMS=-  
  
Du selbst bestimmst die Grenzen deines Grund und Bodens, welcher vor anderen Spielern geschützt wird. Je länger du auf dem Server spielst, umso größer kann dein Gebiet werden! Natürlich kannst du auch deinen Mitspielern Zugriff geben!  
  
-=FARMWELTEN=-  
  
Unsere Farmwelten sind jederzeit zugänglich, und werden auch regelmäßig zurückgesetzt. Du kannst auch am Spawn das "Wild"-Schild nutzen, um in eine frische Gegend zu gelangen.  
  
-=AUKTIONSHAUS=-  
  
In unserem Auktionshaus kannst du mit anderen Spielern handeln, alle Preise regulieren sich durch den Markt. Unsere Währung sind „Schekel„, Zehn Stück davon erhälst du für einen Diamant. Eine stabile Economy ist uns sehr wichtig!  
  
-=SKULLS=-  
  
Um deinen Räumen den finalen Touch zu verpassen, kannst du tolle Dekorations-Köpfe erwerben! Von Rubiks-Cubes über Wecker bishin zu Mirkowellen oder gar einem Zombie! Für Jedermann ist etwas dabei!  
  
-=SILK SPAWNER=-  
  
Auf unserem Server kannst du jeden Spawner mit einer Diamant-Spitzhacke und Silk-Touch abbauen, und in deine eigene Farm zu Hause setzen. Generell sind automatische Farms erlaubt, solange sie keine "klassischen", dauerhaft aktiven Clocks beinhalten.  
  
  
  
Unser aktives und freundliches Serverteam ist jederzeit Bereit, euch den Start in den Server zu erleichtern, und aufkommende Fragen zu beantworten. Auch für Vorschläge zu Verbesserungen und Neuerungen sind wir jederzeit Offen, die Community entscheidet, wohin es geht!  
  
  
  
Haben wir dich überzeugen können? Dann besuche uns noch Heute in Minecraft oder auf unserer Website und werde Teil einer stetig wachsenden Community, deiner Community! [ohboii]', 'mc.ohboii.de', 25565, 'mc_java', 'active', true, NULL, 'http://server.ohboii.de', NULL) ON CONFLICT (slug) DO NOTHING;
