INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'a-towny-server', 'A Towny Server', 'A Towny Server delivers a close-to-vanilla experience with the Towny and Jobs plugins!  
  
Our small community of dedicated people are ready to welcome you with cosy and friendly vibes and will be happy to welcome you into the borders of a beautiful town!  
  
On our server, we try to keep things simple, rather than going for complicated things. When you join, you''ll be welcomed by the cosy spawn that we built ourselves with members of our community, who themselves will be ready to welcome you!  
  
To keep things simple while still encouraging interaction within the community, we have a player-driven economy where you can buy and sell helpful things to and from other players at better rates than the server shop. Sporting the Jobs plugin as well, you can earn money by simply doing your favourite thing in vanilla Minecraft, be it mining, farming, enchanting, brewing or many other things!  
  
We also have lots of cosmetics! Pets, Hats, Trails, Mounts, Gadgets, and more, all available for everyone to get their hands on!  
  
Other plugins that contribute to our comfy feel are Harbor for skipping to daytime, /back for returning to your location should you die, FastLeafDecay for getting rid of those pesky leaves, Chest Shops for player markets, LWC for locking your valuable chests away from other players and an Anti-Cheat to keep everyone playing fair!  
  
Thank you for reading through and we hope to see you in-game!', 'play.atownyserver.com', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'liveandbuild-net-survival-server-java-bedrock', 'LiveAndBuild.Net | Survival Server (Java & Bedrock)', '**Description**  
  
