INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'buildtheearth-network', 'BuildTheEarth Network', 'Server-IP: BuildTheEarth.net  
Version: 1.8 - 1.16  
  
BuildThEarth.net is a server network from the BuildTheEarth project. Our mission is to fully recreate the entire Earth in Minecraft at a 1:1 scale. One block in Minecraft equates to roughly one meter in the real world, meaning that this project will fully recreate the size of our planet.  
  
Anyone is able to join us and contribute to the largest and most expansive build project to ever have been attempted in Minecraft.  
Every language, nationality, and regional difference is accepted and regarded as our greatest attribute as we continue our journey to unite all of Humanity''s greatest achievements into a single Minecraft world.  
  
Our Minecraft Server BuildTheEarth.net allows players to help building with the simplest building system out there.  
You can also join the BuildTheEarth Build Teams and join their servers from this network.  
  
If you want to learn more about this project, join our discord server.  
You don''t need to use any mods, just join with minecraft java vanilla 1.18 - 1.16', 'BuildTheEarth.net:25565', 25565, 'mc_java', 'active', true, NULL, 'http://buildtheearth.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'olimpocraft-network', 'OlimpoCraft Network', '¿Estás buscando un servidor divertido, sin lag y diferente a los demás? ¡Entonces estás en el lugar adecuado! NeroCraft Network te trae impresionantes experiencias, staff agradable y ganas de llegar muy lejos. ¿A qué esperas? ¡Entra ahora!', 'olimpocraft.me', 25565, 'mc_java', 'active', true, NULL, 'https://olimpocraft.es/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'steamwar', 'Steamwar', 'Seit gegrüßt werte Damen und Herrn,  
  
es ist mir eine Ehre, Ihnen heute den Steamwar- Server vorstellen zu dürfen. Dieser Server welch sich im Steampunk Ambiente aufgebaut ist, dreht sich alles rund um Redstonemeschaniken. Es handelt sich um einen Industriellen Krieg um sogenannte Redstone- Wartech. Auf diesem Server sind Wargears, Warships und Airships beheimatet.   
  
Wargear ----- mächtige Kampfmaschinen ausgestattet mit TNT Geschütze dessen Ziel es ist gegnerische Wargears zu vernichten.   
  
Warships ---- Redstone- Großkampfschiffe welche sich beim Seegefecht mit TNT Kanonen und Schleimblockraketen gegenüber stehen.  
  
Airships ----- Fliegende Kampfschiffe welche dem Himmel zum Schlachtfeld verwandeln.  
  
Auf Steamwar könnt Ihr Eure eigene Kampfstation bauen und gegen andere Spieler mit Ihren erbauten Kampfstationen kämpfen. Es wird noch offiziellen Regelwerken welch auf der Webseite zu finden ist gebaut und Events sowie Turniere abgehalten.   
  
Aufgrund der Besonderheit diese Spie-l Modis besitzt Steamwar ein eigenes Programmier- und Architektenteam welche Arenen und Plugins entwickeln. Zudem ein umfangreiches Supportteam welch aus experten der "WarTech" Community besteht.   
  
Tretet der Community bei und beweist, dass Ihr der beste Redstone- Ingenieur seit, welch Minecraft je gesehen hat.', 'steamwar.de', 25565, 'mc_java', 'active', true, NULL, 'http://steamwar.de', NULL) ON CONFLICT (slug) DO NOTHING;
