INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'aurora-mc', 'Aurora MC', 'Join Aurora today for a unique and fun minecraft survival experience!  
  
From our bespoke, in-depth towny and war systems to our industry leading battle pass system, there is so much to discover!  
  
Will you join a town and live in peace, or will you take on the world''s leaders to forge your own glorious path? The choice is up to you!  
  
Here on Aurora, we have a multitude of unique features meant to bring your minecraft experience to the next level.  
  
Our Battle Pass System is, as with all of our unique features, created in-house for the purpose of pushing your minecraft experience to the highest level. Each season will include a new set of unique tools, weapons, and armor to collect, as well as special titles and helpful items to enhance your gameplay! Each season will only last about 3 months, so dont miss your chance to collect them all!  
  
Our unique Towny and War systems are here to take everything you know about minecraft battling and turn it on its head! On Aurora, a war can be something as small as a group of rebels overthrowing their towns leadership, or as large as an all-encompassing war throwing the entire world out of balance. Depending on your personal actions in battle, you may even receive special items as a gift from our staff! Will you pray for peace, or will you go for glory? Your choice is the key to the server''s future!  
  
On Aurora, we take immense pride in being able to express ourselves with unique items, and as such we have taken painstaking efforts to include Custom Textures on many of our items! Each Battle Pass season will include a number of these custom textured items to collect, and you may even find yourself in possession of a rare item by virtue of our Voting System! Be sure to vote every day for your chance to get incredibly rare and powerful custom textured items!  
  
(Custom Textured Items are only available with the download of the server''s custom texture pack upon login, no exterior texture pack or other downloads are required to play on Aurora)  
  
From lazing your days away in a simple village, to experiencing life in a large metropolitan city, from peace to war, we at Aurora have an incredible amount to offer. We sincerely hope that you enjoy your time here.  
  
Join us today at play.auroramc.dev', 'play.auroramc.dev', 25565, 'mc_java', 'active', true, NULL, 'https://aurora.tebex.io/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'nostalgiacraft', 'NostalgiaCraft', '📽️**Trailer/Showcase:** https://youtu.be/Ai0BZEq1xIA  
  
**NostalgiaCraft is a 4+ year old** community SMP that feels like a whitelisted server without the application process. Join the server and be a part of our active community with item shops, spawn builds, and community events just like the servers you used to play on!  
  
🎉 **Join our Discord:** https://discord.gg/nostalgiacraft  
  
**What''s Unique About Nostalgiacraft**  
  
🌟 **Established in 2020:** We avoid resets unless Mojang changes significantly how the worlds are generated (Our community is over 4+ years old)!  
  
🌐 **Large World Border:** Due to our dedicated server storage, we have a 300k x 300k world.  
  
💰 **Vanilla Item-based Economy:** You are able to make vanilla shops, or you can use /trade with other players.  
  
🌈 **Exclusively Enhancing Your Quality of Life:** Our gameplay strictly adheres to the Vanilla+ experience, ensuring that no additional plugins introduce new mechanics (such as claims or McMMO). However, the Vanilla experience is enhanced with commands such as /sethome, /spawn, /togglephantoms, /trade, sitting on stairs, etc.  
  
🔒 **Graylist System:** Our spawn area (1400 x 1400) is a safe and interactive environment reserved for members of our community to interact without the threat of stealing or PvP.  
  
🗣️ **Active Community/Discord:** There are always people online, make new friends and meet new people on Nostalgiacraft today!  
  
⚡ **Dedicated Server:** Our server is hosted on a dedicated machine with a Ryzen 9 7950X, ensuring 20TPS and smooth gameplay throughout your time on the server!  
  
**Join NostalgiaCraft today to experience a cozy, high-quality, and fun SMP!**', 'mc.nostalgiacraft.fun', 25565, 'mc_java', 'active', true, NULL, 'https://nostalgiacraft.fun', NULL) ON CONFLICT (slug) DO NOTHING;
