INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hauntedmc', 'HauntedMC', 'Welkom bij HauntedMC!  
  
**IP** : play.hauntedmc.nl  
**Website** : hauntedmc.nl  
**Versie** : Speel op alle Minecraft versies!  
**Startdatum** : 5 april 2013  
  
HauntedMC is dé gezelligste Nederlandse Minecraft server waar je samen met anderen een geweldig avontuur kunt beleven. We hebben een actieve community en bieden een hoop te doen met verschillende gamemodes. Benieuwd wat je allemaal kunt doen? Lees snel verder!  
  
**Gamemodes**  
- Survival: Overleef, bouw en speel samen met vrienden!  
- Creative: Laat je creativiteit de vrije loop in onze creatieve wereld.  
- KitPvP: Test je vechtkunsten tegen andere spelers in snelle PvP gevechten.  
- Minigames: Speel verschillende minigames en ontdek wie de beste is!  
- Skyblock: Bouw je eigen eiland en groei uit tot de grootste Skyblock-koning!  
Cosmetic Crates: Verdien toffe cosmetics zoals pets, hats, particles, en meer!  
  
**Waarom kiezen voor HauntedMC?**  
- 10+ jaar ervaring: Sinds 2013 maken we de beste Minecraft server-ervaring voor jou!  
- Actieve community: Met een gigantisch trouwe player base en een gezellige chat voel je je hier altijd welkom.  
- Veilig spelen: We hebben geavanceerde beveiliging, een betrouwbaar claim-systeem, en een anticheat die ervoor zorgt dat alles eerlijk verloopt. Bij ons moet iedereen zich veilig voelen, van jong tot oud. Daarom zit er altijd een extra verificatie stap tussen de server, discord en de website.   
- Plugins: Bij ons draaien de leukste plugins zoals McMMO, Vis wedstrijden, Voertuigen, Dynmap, Chatgames en Pinata party.  
- Events: Van tijd tot tijd houden wij leuke events. Denk hierbij aan bouwwedstrijden, PvP wedstrijden, dropparty''s, en thema events tijdens pasen, kerst en halloween.  
- Cosmetics & Ranks: Unlock speciale cosmetische items en speel met extra functies via onze beschikbare ranks.  
- Support: Ons ervaren team staat altijd klaar om je te helpen als je vragen of problemen hebt.  
  
Doe mee met het avontuur! Sluit je aan bij HauntedMC, ontdek alle gamemodes, en word onderdeel van onze toffe community. Er is altijd iets leuks te doen en genoeg vrienden te maken. Waar wacht je nog op? Kom vandaag nog spelen!', 'play.hauntedmc.nl', 25565, 'mc_java', 'active', true, NULL, 'https://hauntedmc.nl', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'gospelcraft-com', 'GospelCraft.com', 'Enter the Kingdom  
  
Do you love playing Minecraft and want to experience it in a Christian light? Join GospelCraft today! You will be able to experience scripture and learn the gospel with the help of our many plugins that enable you to live out biblical principles in the game. Come experience our server today.  
  
GospelCraft is a Christian Minecraft server introducing scripture through gaming. Would you like to know more about the Bible? Come check out GospelCraft! We hold Bible studies twice weekly and are willing to look into answering any of your questions about God!  
  
We have custom programmed NPCs, and are looking for people interested in learning how to program to join our staff team.  
Java IP: GospelCraft.com  
Bedrock IP: GospelCraft.com Port: 19132  
https://discord.gg/Uyc3Rsu', 'GospelCraft.com', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/CCEH3GrXdm', NULL) ON CONFLICT (slug) DO NOTHING;
