INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'empire-s-conquest', 'Empire''s Conquest', 'Empire''s Conquest is a nation building geopolitics server. We engage in diplomacy and war along with building up our empires. We have many talented builders and are looking for more. Since the server isn''t quite open to the public, you have to go through a very short vetting process. But after this, the door is open.', '127.0.0.1', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/uQfbZuN', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'refugiacraft-de', 'RefugiaCraft.de', 'Serverbeschreibung RefugiaCraft  
  
Was wir dir bieten in Kürze:  
  
Eine offene Freebuild-Welt ohne Claiming-Einschränkungen  
Regelmäßige Farmwelt-Resets  
Kreativ-Welt für Redstonetechnik, Pixelarts und Sonstiges  
Verschiedene MiniGames und gelegentliche Events   
Nette und aktive Community  
Ein erfahrenes Team  
  
Wir bieten ein Semi-Vanilla Minecraft-Erlebnis. Das bedeutet, du kannst Survival genauso spielen wie du es gewohnt bist, musst aber dennoch nicht auf Homes oder den /back Befehl verzichten. Auch deine Kisten können von dir gesichert werden.  
  
Bei uns kannst du dir deinen eigenen Bauplatz in unserer Freebuild-Welt frei aussuchen. Es gibt keine Einschränkungen durch Claiming oder Grundstücke. Gestalte dir dein Zuhause wie es dir gefällt! Falls doch mal etwas verloren gehen sollte, können wir das ohne Probleme wiederherstellen.  
  
Wir verwenden kein Geld-Plugin. Unsere Servereigene Währung RefugiaMünzen stellt neben Ingame-Items die Basis der Wirtschaft dar. Für den Handel steht dir unser übersichtlicher Marktplatz mit Usershops zur Verfügung oder du nutzt den direkten Handelsweg untereinander.   
  
Falls du etwas Ablenkung vom Baualltag brauchst, bietet dir die Kreativ-Welt uneingeschränkte Möglichkeiten deine Kreativität auszuleben. Dazu hast du in vier abgegrenzten Bereichen die Möglichkeit Redstone, Pixelarts und gestalterische Bauwerke aller Art zu planen oder zu entwerfen.  
Du suchst noch mehr Spaß? Kein Problem! Bei uns findest du MiniGames, die einzeln oder zusammen gespielt werden können. Auch Events finden immer wieder statt.  
  
Wir legen großen Wert auf Detail und Wohlfühlfaktor. Unser großes Ziel ist es eine familiäre Atmosphäre zu schaffen. Jeder soll hier sorgenfrei spielen können. Sollte das mal nicht der Fall sein, zögere nicht dich an das Team zu wenden und wir werden eine Lösung finden.   
  
Um immer auf dem neuesten Stand zu sein, bieten wir einen Discord an. Dort erhältst du immer alle neuen Infos und kannst dich in verschiedenen Channeln mit der Community austauschen. Für alle die lieber Teamspeak nutzen, bieten wir auch hier einen Server an.  
  
Wir freuen uns auf deinen Besuch!   
  
Dein RefugiaCraft Team  
  
  
  
Teamspeak: refugiacraft.de  
Homepage: https://refugiacraft.de/  
DynMap: https://map.refugiacraft.de/', 'refugiacraft.de', 25565, 'mc_java', 'active', true, NULL, 'https://refugiacraft.de/', NULL) ON CONFLICT (slug) DO NOTHING;
