INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ogcraft', 'OGCraft', 'OGCraft is a free-build, non-grief, toggle PvP Survival Server. This server features multiple unique qualities, one being the admins have 35+ years collectively of Minecraft knowledge and server insight.  
  
This server also has its own Player Market system, where players can buy, sell, and trade items with each other all while being able to buy and sell items from the server shop! Players can also set a warp at their custom shops!  
  
OGCraft also has premium features such as Donator Ranks and Crates, but all of these are accessible without spending a penny. Since we use a time-based ranking system, eventually you can be on the same level as the highest Donator Rank without buying a single item!  
  
One of the most unique features OGCraft brings to the Minecraftian scene is that we have several survival worlds, one with custom generation, and 2 resource worlds that reset every month to allow for more items and spawners… speaking of which…  
  
Silk Touch Spawners? Oh heck yes. Any spawner, any location, any pickaxe with Silktouch. You see a spawner, and it is yours. Because of our welcoming community, anyone online with a Silktouch Pickaxe will come and help you pick up a spawner when you need, even if you misplace it!  
  
One of the most welcoming things OGCraft brings to the table is that the staff members (including the Founders!) can all have jokes back and forth between players without any repercussions (whilst obviously abiding by the rules 😉 ). The staff are not all and mighty like other server’s, they are standard players who just have that ability to go the extra mile for the server.  
  
The Admin team regularly talk and keep each other updated, even with the multiple time zone differences.  
  
Join now at IP: play.OGCraft.org  
Join their discord: https://discord.gg/uMNHtUK  
Check out our website: https://ogcraft.org/', 'play.ogcraft.org:25565', 25565, 'mc_java', 'active', true, NULL, 'https://store.ogcraftmc.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'blossomcraft-1-21', 'BlossomCraft 🌸 [1.21+] 🌸', 'Java IP: play.BlossomCraft.org  
Bedrock IP: play.BlossomCraft.org Port: 19132  
