INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hellominers-bedrock-java-crossplay', 'HelloMiners - Bedrock/Java Crossplay', 'HelloMiners is a modern city economy server started in 2011, one of the oldest communities in Minecraft. Our community is completely unique, there are few communities in Minecraft that are as close-knit as ours!   
  
On HelloMiners, you may become a business owner, running a large, successful business with many properties and employees; a famous architect renowned for their designs across the map; a city mayor known for creating a vast, beautiful city; a shop owner, running a frequently visited shop that serves everyone in the community; a government official, who helps enforce rules and keeps the community running smoothly; the possibilities are endless.   
  
You start out with nothing but some cash and some tools and food, and where you go from there is only as limited as your imagination!  
  
Explore our server map at http://play.hellominers.com:8123  
  
Join the community at play.hellominers.com to explore our vast world, and to check out some of the marvelous builds that have been completed over the years! To join on Bedrock Edition, make sure the port is 19132.  
  
Also, join our Discord at bit.ly/discordhm for the best server experience.  
  
If you would like to check us out on other platforms, check us out on:  
YouTube: https://www.youtube.com/hellominers  
Instagram: https://www.instagram.com/mchellominers  
Twitter: https://www.twitter.com/mchellominers  
TikTok: https://www.tiktok.com/@mchellominers', 'play.HelloMiners.com', 25565, 'mc_java', 'active', true, NULL, 'http://HelloMiners.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'torchcraft-nl-be', 'TorchCraft NL/BE', 'TorchCraft is de gezelligste server van Nederland en België. Naast veel gezelligheid hebben we leuke (en unieke) gamemodes, snelle servers en een leuk team die ook echt betrokken zijn met de spelers. Onze knusse community staat altijd open voor nieuwe spelers. We houden met regelmaat leuke events en updaten onze gamemodes regelmatig met nieuwe features. Kom je is langs?  
  
We hebben verschillende Gamemodes, namelijk:  
  
- Survival (SMP):  
Een van de oudste survival servers van Nederland! We hebben twee survival werelden en resetten nooit! Ontdek de wereld van Minecraft in onze super gezellige community!   
  
- Skyblock:  
Onze skyblock server is recent helemaal gereworked! DE skyblock ervaring die je zoekt! Gezellige community en wekelijks nieuwe challenges!  
  
- Creative  
Ontdek de eindeloze mogelijkheden van minecraft creative. Op onze grote plots kun je zeker je creativiteit kwijt!  
  
- Hardcore  
Overleef op onze hardcore SMP met maar 3 levens.   
  
- Event  
We houden ook geregeld events, hiermee zijn prijzen te winnen en bovendien is het ook gewoon leuk!  
  
- Lobby  
Misschien wel de beste gamemode van onze server is de lobby. Het heeft geen bijzondere functies maar is een uitstekende lobby.   
  
Discord!  
Join onze discord server om je helemaal aan te sluiten bij onze community. We hebben diverse kanalen en er is altijd wel iemand in voor een gezellige minecraft sessie in call!  
www.torchcraft.nl/discord', 'server.torchcraft.nl', 25565, 'mc_java', 'active', true, NULL, 'http://TorchCraft.nl', NULL) ON CONFLICT (slug) DO NOTHING;
