INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'instacraft', 'InstaCraft', 'InstaCraft is a friendly PvE, "mostly" vanilla Minecraft server started on 3/3/20. Unlike most servers, we have no land-claim system(make a report when you''re griefed, and staff will ban/roll back the damage). We strive to keep the nostalgic vanilla minecraft experience. The few plugins added are there to help increase player to player interaction.(AuctionHouse, PlayerShops, Mobhunt) Also, All of our ranks are balanced, and go directly against hosting a pay-to-win environment. We would love to have any player join us who will be a positive contribution to the community.', 'play.myinstacraft.com', 25565, 'mc_java', 'active', true, NULL, 'http://www.myinstacraft.com', NULL) ON CONFLICT (slug) DO NOTHING;
