INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'xironite-network-1-21-11', 'Xironite Network [1.21.11]', '![](https://i.imgur.com/sHL1DQQ.gif)  

**Xironite Towny [1.21.11]**  
**Xironite** is a server dedicated to interacting with our community through _hosting events and listening to player feedback_ On Xironite, we offer a various amount of gamemodes for players to try. The gamemodes are Towny, Skyblock, Survival, Creative, Minigames and Events!  
  
  
**########## Towny ##########**  
In _Towny_ , you can team up with other players and build your own town from the ground up 🏘️ Recruit members, expand your land with _Towny Claims_ , and work together to create the biggest and strongest town on the server.  
  
If competition is more your style, challenge rival towns in tournaments and contests for real prizes 🏆⚔️ Climb the leaderboards with _McMMO_ , grind through _Ranks & Prestiges_, and dominate the economy using _Jobs & Shops_ 💰📈  
  
Looking for adventure? Dive into custom _Dungeons_ , unlock powerful _Custom Enchants / Items / Gear_ , and push your progress even further with the _Battlepass_ 🔥  
  
Build your town, grow your power, and compete your way — whether that means becoming the richest, the strongest, or the most feared town on the server.  
  
**########## Survival ##########**  
In _Survival_ , you’re playing _Vanilla Minecraft_ — just with some fun extras added in. 🌍⛏️  
  
Level up your skills with _mcMMO_ , make money with _Jobs_ , set your own _homes_ , and team up with friends to build whatever you want 🤝🏗️  
  
Use _claims_ to protect your land and keep your stuff safe 🔒  
  
We’ve also got _custom pets_ 🐾 that level up with you! Unlock different _skill trees_ , gain new _abilities_ , and grow your pet into a strong companion for your adventures ⚔️  
  
It’s still vanilla at its core — just with a little more to grind, build, and enjoy 🔥  
  
**Xironite** is constantly _evolving_ based on _player feedback and ideas from our amazing management_. Join now before you miss our next _event_!  
  
**How to Join?**  
Join now using our IP:  
Java: _mc.xironite.com_  
Bedrock: _bedrock.xironite.com_  
  
  
**Social Media**  
[Discord](https://discord.xironite.com/)  
[Instagram](https://www.instagram.com/xironite)  
[TikTok](https://www.tiktok.com/@xironite)  
[YouTube](https://www.youtube.com/channel/UCc4O3IaYx8s-LQznYNomJTw)', 'mc.xironite.com', 25565, 'mc_java', 'active', true, NULL, 'http://xironite.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'togethercraft-whitelist-survival-server', 'TogetherCraft - Whitelist Survival Server', 'TogetherCraft is an adult Minecraft community that offers a friendly, fun, and inclusive environment. It is the perfect place to relax after a day at work or school. We aim to offer a true-to-game survival experience, adding a few quality of life tweaks. We are driven to provide a friendly, engaging and fair Minecraft community. Our server is intended to be a place to chill alone or with your friends.', 'play.togethercraft.online', 25565, 'mc_java', 'active', true, NULL, 'https://togethercraft.online/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'skyprison', 'SkyPrison', 'SkyPrison is a prison located hundreds of feet above civilization. This prison consists of several floating islands which you can unlock by ranking up. Rank up by earning money and completing tasks on each island. As you make your way to freedom you may meet some not-so-friendly prisoners. Luckily, guards are there for your protection as long as you obey the prison laws. Fly high with SkyPrison today!  
  
But wait there’s more.  
  
SkyPrison also offers other games to enjoy within the server like paintball, parkour, and more to come! From time to time staff will host events such as SkyPvP, Tnt Spleef, Lavarun, and more original games from which you can earn rewards to advance your rank.  
  
* PVP, Events, Easter Egg Secrets, and Giveaways!  
  
* McMMO, Crates, Cars, Custom Recipes, Chat Games, and more!  
  
Visit https://www.skyprison.net/ for forums, rules, and more information!  
  
Join our Discord community today! https://skyprison.net/discord', 'mc.skyprison.net', 25565, 'mc_java', 'active', true, NULL, 'https://skyprison.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'nekone-n-p-b-h', 'Nekonečný příběh', 'Nekonečný příběh   
  
• Server vznikl pro hráče, kteří milují tuto hru. Proto jsem se rozhodl udělat něco výjimečného a vyváženého, kde si každý hráč najde to své, co zbožňuje na Minecraftu. zároveň dle dlouholetých zkušeností tomu dodáváme společně speciální nádech.  
  
• Zaměřujeme se především na kvalitní hraní společně s kamarády, rodinou a zároveň na bezpečí hráčů, majetku a celého serveru pro spokojenou komunitu.  
  
• Je tu klasický Survival, s téměř nekonečnou mapou. K dispozici je plně vyvinuta ekonomika, kterou doplňuje několik speciálních metod na získávání odměn. Celá herní mechanika samotné hry je pozměněna na několik různých úrovní skillů všeho druhu. Jsou k tomu přizpůsobené monstra s odpovídající obtížností než v původní hře. K dispozici jsou připravená vlastní kouzla, které všichni velmi rádi vyzkouší. Je tu připraveno spoustu zábavy, která nikdy neomrzí a hlavní kouzlo celého serveru musíte poznat Vy sami :3  
  
• Životní příběhy každého z nás se odehravají každy den, pojďme je spolu sdílet a vytvořit tak jeden velký, který nebude mít konce. Těšíme se právě na tebe o/  
  
Odkazy:  
Web: https://www.nekonecny-pribeh.eu/  
Discord: https://discord.gg/a8MSGPd  
YouTube: https://www.youtube.com/Chipmunkatels  
Facebook: https://www.facebook.com/npribeh/  
Instagram: https://www.instagram.com/npribeh/  
TikTok: https://www.tiktok.com/@nekonecny_pribeh', 'play.nekonecny-pribeh.eu', 25565, 'mc_java', 'active', true, NULL, 'https://www.nekonecny-pribeh.eu/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'sprookjescraft', 'Sprookjescraft', 'Visit the Efteling theme park virtually in Minecraft! Ride all the rides. See all the shows and experience how magical Minecraft can be. Get all the joy''s of visiting a themepark, without the long ques. Ride rollercoasters, buy souvenirs, eat some junkfood. The Efteling is a themepark in the Netherlands. Sprookjescraft has created a one on one copy of this themepark in Minecraft. Active since 2012 Sprookjescraft is the longest running minecraft themepark in the Netherlands.', 'play.sprookjescraft.nl', 25565, 'mc_java', 'active', true, NULL, 'https://sprookjescraft.nl/', NULL) ON CONFLICT (slug) DO NOTHING;
