INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'flightsmp', 'FlightSMP', '✦ . ⁺ . ✦ . ⁺ . ✦  
  
Welcome to FlightSMP!  
  
  
FlightSMP is a semi-vanilla 1.21 server that anyone can play on! We don’t tolerate griefers, thieves, or hackers! Our community is friendly, inclusive, and always happy to welcome new players! We host fun events with many prizes; including, rank upgrades, in-game money, crate keys, and more! We have an array of plugins to enhance the Minecraft experience while still keeping the feel of vanilla Minecraft!   
  
Some of our plugins include:  
