INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'illusivemc-survival', 'IllusiveMC Survival', 'IllusiveMC is a Non-Vanilla Minecraft SMP Server, where the fun never ends! Our server boasts a treasure trove of features like mcMMO, Voting Crates, VeinMiner, RTP, Silk-Touchable Spawners, Clans, Player Shops, Land Claims, Supply Drops, and so much more that you might just forget to eat!   
  
We''re all about community here, which means we actually listen to our members'' feedback to make the server even better—yes, we do take suggestions, not just pizza orders!   
  
Whether you''re a Java Edition wizard or a Bedrock Edition newbie, we''ve got you covered. Our server welcomes players from nearly every platform—computer, phone, tablet, console—you name it, you can join the fun!  
  
Our staff team is on the ball, actively moderating the server. So if you encounter any hiccups, whether it''s a pesky player or a server snafu, they’re ready to swoop in and save the day!  
  
Plus, we roll out monthly updates packed with new and exciting features, ensuring you''ll always have something to keep your pixelated self busy!  
  
Feel free to hop onto our Discord Server to learn more about the server or to mingle with our awesome community!  
  
  
[ https://discord.gg/arW9qFsHpT ](https://discord.gg/arW9qFsHpT%20)  
  
Other Information:  
Discord - <https://discord.gg/arW9qFsHpT>  
Server Store - <https://illusivemc.craftingstore.net/>  
Twitter - <https://twitter.com/Illusive_MC>  
Website - <https://web.illusivemc.com/>  
  
  
![](https://media.discordapp.net/attachments/918054246509854720/1368668192829866034/spawn_1.jpg?ex=68263e15&is=6824ec95&hm=1972be9db611e13e4438258c66095b7601e3020ea7c0ba610f5dab937d13beca&=&format=webp&width=1533&height=800%20)', 'IllusiveMC.com:25581', 25565, 'mc_java', 'active', true, NULL, 'https://web.illusivemc.com/', NULL) ON CONFLICT (slug) DO NOTHING;
