INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'zenpvp', 'ZenPvP', 'We are a Minecraft Network that was established in 2021, striving to provide our players with the "Ultimate Experience" every day through daily updates and new content added monthly. We currently offer Skyblock, Gens, Prison, and Survival with plans to expand. Join us today to be a part of the community!  
  
