INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'traizelcraft', 'TraizelCraft', 'We are a massive long term project that started on the Xbox 360! Our current server is CrossPlay and CrossVersion meaning you can play on both Bedrock and Java, and can play any version from 1.9 up to the current version!  
  
These are some of our Key Features:  
  
  
  
  
Our RPG Survival server has a vast open world to explore, collect loot, complete quests, find secrets and Easter eggs, learn about our massive story, and defeat powerful enemies! We have a ranking system so players can unlock new areas as they level up with even better gear, secrets to find, and mobs to fight! Complete Quests, complete new mazes and parkour, create or join a Guild, unlock more areas to become Legend!  
  
  
  
  
  
The RPG Survival maps are 100% custom terrain maps with custom mobs and drops! There are Nether and End Survival maps as well for gathering dimensional resources as well as resource gathering in the zones to help gather certain resources, since our main map is custom terrain!  
  
  
  
  
  
On ALL Servers, we have a large selection of carefully made and quality Parkour that ranges from Easy mode for beginners to Expert mode for hardcore Parkour masters! All parkours grant money, XP, or class levels on completion!  
  
  
  
  
  
The RPG Survival has challenging Dungeons that range from basic "Guns a Blazin" dungeons to Objective based Dungeons. There are also Incursions that are extremely difficult dungeons with a big boss! Level up your Dungeon Rank and unlock newer and harder Dungeons that are more rewarding!  
  
  
  
  
  
On the RPG Survival, we offer a very COMPLEX RPG and Character Leveling system! Choose a class, level up your character, and unlock new skills and abilities! There are 5 Classes to choose from, each with unique stats and gear to unlock! We also have a wide range of custom gear and weapons with special abilities that can be earned in activities or crafted in the Forge!  
  
  
  
We have tons and tons of custom Loot and Mobs! There are over 10 different mob factions/species and over 400 different kinds of mobs! All of them level up and become harder to kill! Using the world scaling mechanic, the further you wander from spawn, the higher level mobs you will find, and the better loot you will find!  
  
  
  
  
  
The RPG Survival Server has an extremely complex RNG loot system! With over 300 unique weapons and 50 sets of Armor, you will never stop the grind! This system is similar to games like Destiny, where every item you get is rolled with different stats and abilities. Try and get a God Roll! We also have a ton of crates and kits that can be bought! Use these to help you along your journey, and maybe find something really cool!  
  
  
  
  
  
We use a plugin that integrates our Discord Chat and our In Game Chat so you can talk with Discord and vise-versa! It is very useful when you are not online and want to talk with online players. Players can also show off their items, inventory, and more in game and on Discord using a fancy chat item plugin! Join the Discord using Code qWssnBP or go to at discord.TraizelCraft.net!  
  
  
  
  
  
  
  
We have a TON of cosmetics on ALL Servers! Your cosmetics are shared between all servers, buy once and get access everywhere! Go to our store, or just be active and vote daily to get some coins and save up!  
  
  
  
On top of all of this, we also have:  
Mazes  
Tutorials  
700+ Quests  
Minions and Automated Farms  
Hourly Server Events  
Casual and Competitive PvP Arenas  
RTP System  
Gambling Games  
Auction House and Lottery  
Daily, Weekly, and Monthly Rewards  
Discord Events ran by Traizel and other Collabs  
A great community that has been growing for over 5 years  
11+ Years of experience, perfection, and history  
In the future, we plan to add:  
A Full Story Campaign - Coming Soon to the RPG!  
More game modes, mechanics, and servers!  
  
Join the community! Discord- Use Code qWssnBP or go to discord.TraizelCraft.net  
Current Server Version: 4.4.9', 'traizelcraft.net', 25565, 'mc_java', 'active', true, NULL, 'https://traizelcraft.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'homesteadcraft', 'HomesteadCraft', 'If you''re looking for an adult only (21+) server with no map resets, no drama and no kids, try Homesteadcraft. The map is 4 years old, it is a small and chill community. We have some amazing builders and huge projects because the map does not reset, it only expands with every update. JAVA 1.21.10 , with a few QOL plugins.  
  
There are resource worlds for the overworld, nether as well as the End, which resets weekly.  
  
There is no required playtime, and most of the plugins can be toggled off if you prefer.  
  
* One player sleep  
* Normal difficulty  
* Java only  
* Aura skills  
* Acuteloot plugin  
* Anti grief / claims  
* Player-run shopping District  
* Gaming Island', 'play.homesteadcraft.com:25654', 25565, 'mc_java', 'active', true, NULL, 'https://homesteadcraft.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hylexmc', 'HylexMC', 'HylexMC is a cracked Minecraft network! Open to both Premium and cracked players, our server''s player base has been intermittently growing since it was first released, with users all over the world playing our amazing game modes and enjoying their time here with our beloved community. Can''t wait to play? Join play.HylexMC.net now! We have the most famous and amazing games with our style & touch: BedWars, Parkour, Duels, KnockbackFFA, Lifesteal SMP, Oneblock, Survival and more fun games! We aim for a fun and enjoyable player experience, with lag-free and non-p2w game modes as much as possible! We also support cross-play which means you can play with your friend at bedrock with the ip: br.hylexmc.net port: 19132 Isn''t this awesome? What are you waiting for? Join now at play.hylexmc.net', 'MP.HylexMC.net:25565', 25565, 'mc_java', 'active', true, NULL, 'http://store.HylexMC.net', NULL) ON CONFLICT (slug) DO NOTHING;
