INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'frostarea-net-netzwerk-minecraft-netzwerk', 'FrostArea.net Netzwerk - Minecraft Netzwerk', 'Wir haben ein sehr umfangreiches Netzwerk was der Bestandteil Minecraft ist.  
