INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'smpearth', 'SMPEarth', 'SMPEarth (SMPE) was originally a private, whitelisted Minecraft server, featuring a custom-generated 1:3000 scale map of the Earth. It commenced on November 2019 and exclusive to a group of selected popular Minecraft creators and streamers such as WilburSoot, Technoblade, TommyInnit, CaptainSparklez, Ph1LzA and many more. In this survival multiplayer server, the players were given the chance to create factions, forge alliances and declare enemies between one another.  
  
Now, following the footsteps of the creators server which had ended in April 2020, SMPE is now publicly accessible on Java Edition where anyone can join. Boasting a community of 7000+ members at the moment and 3 main servers to choose from and experience (casual towny, seige towny and factions), SMPE''s primary goal is to become the most advanced Earth server in Minecraft.', 'play.smpearth.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.smpearth.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'haliacraft', 'HaliaCraft', 'HaliaCraft Network es un servidor Hispano enfocado en la Supervivencia, el PvE y algo de PvP, nos tomamos nuestro trabajo muy enserio para ofrecer una calidad de juego buena, trabajamos en mejorar cada día más. ¡Únete y disfruta de una experiencia juntos! no olvides invitar a tus amigos.', 'mc.haliacraft.com', 25565, 'mc_java', 'active', true, NULL, 'https://tienda.haliacraft.com/', NULL) ON CONFLICT (slug) DO NOTHING;
