INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'avatarmc', 'AvatarMC', 'We are a community-supported Minecraft server aiming to recreate the Avatar universe in Minecraft. This server opened on January 16, 2015 and has been running strong ever since.  
  
