INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cherry-blossom-smp-1-20-4', 'Cherry Blossom SMP 1.20.4+', '🌸 Cherry Blossom 🌸 was created to give players a feeling of progression and accomplishment while staying simple and close to vanilla, while offering a variety of plugins that enhance the minecraft experience such as /sethome, /tpa, /rtp, chest/door locks, and /rest. We have constant updates and active staff! Come give us a try!  
  
