INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'xcraft-survival-mining-since-2013', 'XCraft Survival | Mining Since 2013!', 'XCraft Survival is celebrating 10 Years of providing a nice escape! Since 2013, we''ve been working hard to create a server that allows you to play with ease. We''re all about the old-school survival experience, with a few fun twists! From custom enchantments and tweaked crafting recipes to fighting Herobrine and using Flight Feathers, you''ll find your niche!  
  
We are a play-to-win server, the only way that you''re going to get farther than anyone else is by putting in the work, which means NO P2W. Our ranks are purely cosmetic, letting you earn everything you have in-game with our Perks system. You can upgrade yourself to have more set homes, player vaults, portable workstations, and more!', 'play.xcsurvival.com', 25565, 'mc_java', 'active', true, NULL, 'https://xcraftsurvival.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hardcore-smp', 'Hardcore SMP', 'Hardcore SMP is the go-to server for hardcore survival multiplayer, for both **Java Edition and Bedrock Edition**. No world resets, no pay-to-win garbage, no teleporting to other players; just a vanilla hardcore multiplayer experience, with some additional features to enhance the multiplayer aspect of Minecraft.  
  
These additional features include:  
  
• 🪙 **A coin-based economy that is 100% player-driven**. We have no admin shops for buying or selling normal Minecraft items. Instead, players trade exclusively with one another, a process facilitated by a trading system and an auction house. Coins enter circulation by defeating mobs and looting chests. 🪙  
  
• 🏠🔐 **A comprehensive land claiming system**. Players can claim areas of land for their bases, farms, and other builds, fully protecting them from griefing. You can log out of the server safe in the knowledge that your claims will still be there when you log back in. However, if you die, your claims are deleted, leaving the land unprotected! Our land claiming system is very comprehensive - come and check it out! 🏠🔐  
  
• ✨ A one-time-use "**/randomtp** " command, which teleports you, and others if you choose to invite them, to a random location in the overworld, so you don''t have to manually travel tens of thousands of blocks out to find fresh terrain. There is also "**/home** ", which teleports you to your respawn point, and "**/spawn** ", which teleports you to Spawn. These are the only teleport commands on the server. ✨  
  
Hardcore SMP is **100% non-pay-to-win**. We feature a single rank, VIP, on our store, whose perks are purely cosmetic, and do not provide any form of advantage over other players. Our store also features a revive, which when used is like a full account reset - it is pretty much **equivalent to logging into the server on a fresh Minecraft account**. This has the benefit of not requiring you to buy a new Minecraft account in order to be able to play again, which is what you would have to do on other hardcore servers (as well as change your IP address in the case of death-IP-ban servers). **Hardcore SMP will never become pay-to-win**.  
  
To join the server, you can use the server address "**hardcore-smp.com** ". However, if you don''t have the option to add a server, such as on consoles, you can instead add "**HardcoreSMP** " as an Xbox/cross-platform friend, after which you will be able to join the server through the "**Social** " tab in-game, or by joining the account''s game session.  
  
We also have a Discord server - be sure to join and become part of our community! Invite link: <https://discord.gg/fmwvGGR>', 'hardcore-smp.com', 25565, 'mc_java', 'active', true, NULL, 'https://store.hardcore-smp.com', NULL) ON CONFLICT (slug) DO NOTHING;
