INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lifesteal-smp', 'LifeSteal SMP', 'We are a semi-vanilla Minecraft server with an additional feature where you can steal hearts from other players. When you kill another player, you gain +1 heart, while the killed player loses -1 heart.  
  
PvP is allowed on our server and players are free to steal or raid other bases. There is a total limit of 20 hearts on the server, which can be reached by killing other players. You only lose hearts when other players kill you and you cannot have less than 5 hearts. This means that if you kill someone while having 20 hearts, you do not gain any more hearts and the killed player does not lose any hearts either.  
  
We usually host events at weekends for in-game prizes with no risk of losing your hard-earned items. Sometimes we also organize giveaways for interesting items, such as Discord Nitro and more.  
  
Join us and enjoy the best public lifesteal gamemode in a free to play semi-vanilla Minecraft environment today.  
  
🌐 IP: mc.lifestealsmp.com  
🔗 Discord: https://discord.gg/lifestealsmp', 'mp.lifestealsmp.com', 25565, 'mc_java', 'active', true, NULL, 'https://store.lifestealsmp.com', NULL) ON CONFLICT (slug) DO NOTHING;
