INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rising-dragon', 'Rising Dragon', 'Looking for a small family-friendly crossplay server? Join Rising Dragon a survival server for players of all ages and skill levels. Offering a vanilla like experience with some exciting features like:  
