INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rulercraft', 'RulerCraft', '**What RulerCraft offers:**  
  
**Earth:**  
- Full scale world of Earth with all continents, ores and different biomes.  
  
**Towny:**  
- Can start your own towns and nations or you can join another town or nation.  
  
**Cultures & Religions:**  
- Custom set of realistic cultures and religions to choose from for all your roleplay needs.  
  
**Economy & Trading Posts:**  
- Dynamic and fair economy: automatic price changes and Trading Posts scattered around Earth.  
  
**Perks:**  
- Custom system that gives you different perks based on your choices. You have 54 different perks and bonuses to choose from. Many fun perks such as Flying in Towns, Custom Warp, Personal Hologram, Automatic Chest Sorting, Night Vision, Fire Resistance and more!  
  
**Senate:**  
- Players vote on things such as new features, staff promotions, ban appeals and more.  
  
**Good community:**  
- Toxic behavior and excess drama is not tolerated.  
  
**Righteous staff:**  
- Staff are chosen by the players and follow our staff guidelines.  
  
**Optional PvP:**  
- You choose whether to turn on PvP or not. Those with red name have PvP on and can be killed.  
  
**SiegeWar & War System:**  
- We use SiegeWar combined with our custom War System for casual and less toxic warfare.  
  
**Quarries & Treasure Ships:**  
- Nations can fight over production sites that grant your nation money each day.  
  
**Dungeons:**  
- Custom dungeons such as Aztec Temple, End Temple, Creeper Tomb and Underwater Temple with plenty of cool mobs to kill for your EXP and loot needs. Challenging custom Bosses like Creeper Lord, Master Evoker, Michael Mamoa and King Goliath with good endgame loot as drops.  
  
**Java & Bedrock support:**  
- play on any device you want.  
  
Visit our website to see more features and information.  
Join RulerCraft today! **play.rulercraft.com**', 'play.rulercraft.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.rulercraft.com', NULL) ON CONFLICT (slug) DO NOTHING;
