INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bridgerland', 'BridgerLand', 'The server is called "Bridger Land" which by itself, kind of explains the server. Our server is bridging related! We offer a unique and special way for people to learn bridging, and to simply have fun playing within our server in general! Some of our features are: Trainer AI which is found inside of the Fast Bridger Server, Reducers names and skins could be changed to your liking, as well with a level selector, you can choose from Easy, Medium or Hard mode. We have a few game modes to choose, such as a unique bridge racing game, where you and your opponent race to the end of the map! But there are challenges, some maps include pearl clutching and landing on checkpoints.', 'bridger.land', 25565, 'mc_java', 'active', true, NULL, 'https://bridger.land/', NULL) ON CONFLICT (slug) DO NOTHING;
