INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'anomaly', 'Anomaly', 'Kingdom of Anomaly is more than just a Minecraft server, we are a lgbtq community of gamers that share a love for a large variety of games. Our love of games spreads across many genres, including adventure, RPG, strategy, survival & more. Our mission is to develop our server with the community in mind and implement mechanics from each of these genres without the use of mods. If you are concerned these mechanics would make the game too complex, most of these features are optional and are designed to work with the default mechanics of Minecraft. To create these mechanics we use several plugins, many of them are free and some of them purchased. We believe in supporting the developers of these plugins so they have more time to maintain them or even make new plugins. Our ko-fi helps support these developers as well as essential server maintenance & security. Subscription tiers give monthly server boosts & major discounts on several shop items, such as server boosts, tool item skins and weapon item skins. We will never sell items that give players unfair advantages, we believe in playing to win, not paying to win, we also believe that every item we sell should be obtainable without having to purchase it. While maintaining the physical side of the server is important, there is no server without players like you spending time with us. This is your server to play however you wish and we will never require you to pay money to get the full experience. Freedom to play how you wish is very important to us, which is why we select our staff members very carefully, we do not tolerate members of staff that use their position for anything other than their job. Our permission system will also help by preventing staff from having more permissions than they need to do their job, only approved mediators will have the permission to ban, kick or mute other players. If a staff member does misuse their position we want you to let us know. Your feedback helps inspire us to add new content, and we prioritize what we work on based on how you play on our server. The more players interact with a feature of the server, the more we will improve or add to it. This is our mission, and we hope to see you be a part of it.', 'Anomaly.zapto.org', 25565, 'mc_java', 'active', true, NULL, 'https://ko-fi.com/anomalymc', NULL) ON CONFLICT (slug) DO NOTHING;
