INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'enchantedmc', 'EnchantedMC', 'We are an innovative Minecraft Network, we strive to make the best possible and most optimized gameplay experience for our community. We have many gamemodes you may enjoy such as Skyblock, Prison and Gens. You can join today to see what we have to offer.  
  
