INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'realm-of-aureus', 'Realm of Aureus', 'Welcome to the Realm of Aureus, Traveler!  
  
Looking for an adventure? A unique server not quite like all the others? Look no further. A mix of RuneScape, Terraria, classic Minecraft, AdventureCraft, World of Warcraft, and with inspiration from both WynnCraft and Hypixel Skyblock, our community focuses on extending the vanilla experience as far as possible while still retaining the feeling of simple, basic gameplay. With over 400+ new items, armors, enchantments, tools, and NPC''s to explore and experiment with, as well as a vault full of planned content already designed, you will always have something to do, a goal to work towards, and a community to bring it all together.  
  
Rest assured; when you join the Realm of Aureus, it will be simple. Unlike other servers of similar design, we focus on making the game as understandable as possible for the average player. No excessive leveling system, no items with lore and information that extends off the screen, no need to read a manual to figure out what keybinds to use. We only use recognizable formats for items, a straightforward level progression system, and enchantments that feel natural, as if they belong in the base game. All expansions use assets already in the game, so don''t worry; If you are familiar with vanilla, you will be able to start off strong. When you join, you will start with nothing. How you progress is entirely up to you: we won''t hold your hand any more than you want us to.  
  
We are not a Pay-to-Win server, and we never will be. We have a secure line of funding to ensure only the best hosting, software, and code is utilized for the best possible player experience. Our success is determined by how the community responds to the quality and quantity of our updates. We also firmly believe that the integrity of the in-game economy is of the utmost importance, and will do our best to ensure free and fair gameplay among all members. Hacking and exploiting the network will get you banned, no questions asked. Other rules are posted in our Discord ( discord.aureusmc.net ), where our community resides outside of the network.  
  
So, now you know a little about us and our game philosophy. Why don''t you come give us a chance to know you? Join us at play.aureusmc.net !', 'play.aureusmc.net', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mc-pathisorb-com', 'mc.pathisorb.com', 'Season VII began on July 11, 2025. Pathis Orb has existed since 2018.  
  
