INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'waffles-smp', 'Waffles SMP', 'The Waffles SMP is a Minecraft Java Edition server that anyone can join, however you WILL need to be in our Discord, just so the admins can easily talk to anyone who is found to be breaking the rules. If you''re in the Discord, you''re automatically whitelisted!  
  
The Waffles SMP is a mostly-vanilla server, meaning the gameplay is mostly just normal, un-modified Minecraft, with the exception of plugins to prevent griefing, and a few custom-textured items (like waffles).  
  
There are a few server-wide rules, such as no hacking or x-raying or cheating in any other way. However, most rules are controlled by player-run governments on the server. Anyone who joins can make a country, so anyone can own at least part of the server. The countries are all listed on our website, where you can also find information about our server''s 4-year history. We have the Dynmap plugin as well, so it''s easy to tell what country you''re in at all times: <http://wafflessmp.mcserver.us:8123/>   
  
Overall, the SMP has a pretty nice community, since any unkind players are banned from both the Discord and Minecraft server. If you need any help with anything or if someone is bothering you, you can contact me (WafflesAreBetter), or anyone with the Minecraft Admin or Discord Police roles at any time!', 'wafflessmp.mcserver.us', 25565, 'mc_java', 'active', true, NULL, 'https://wafcorp.org/smp/', NULL) ON CONFLICT (slug) DO NOTHING;
