INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bucketry-minecraft', 'Bucketry Minecraft', 'Welcome to the most epic Minecraft adventure of your life! 🌟  
Are you ready to embark on a journey like no other? Step into our extraordinary Survival server with a twist that''s perfect for players of all ages. We''ve taken the classic survival experience and cranked up the excitement to a whole new level!  
🌍 Explore a world filled with endless possibilities and challenges, where survival is just the beginning. Here''s a taste of what awaits you:  
🏰 Progression System: Climb the ranks, conquer challenges, and become a legendary player.  
🛒 Shops Galore: Build your empire with server and player shops, where treasures and riches await!  
💼 Jobs & Skills: Take on exciting jobs and hone your skills to stand out in the world of survival.  
🎮 Minigames: Take a break from survival with action-packed minigames that''ll keep you entertained for hours.  
🌟 Custom Spawners: Create your own unique creature kingdom with custom spawners.  
🔮 Enchantments Galore: Unlock over 170 advanced enchantments to craft legendary items that will make you the envy of all!  
📦 Envoy Crates & Voting Crates: Open crates filled with surprises and rewards for your loyalty.  
🗺️ Custom Claiming: Protect your territory with style and finesse using our custom claiming system.  
💰 Banking: Manage your riches with ease and watch your wealth grow!  
The adventure is yours to shape! Will you rise through the ranks to become the ultimate server legend? Or will you amass wealth beyond your wildest dreams?  
Join us now and embark on the Minecraft journey of a lifetime. Whether you''re a seasoned player or just starting your blocky adventures, there''s something here for everyone. Let''s create unforgettable memories together, one block at a time! 🌟🎮', 'mc.bucketry.net', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/eZXqDPj3kE', NULL) ON CONFLICT (slug) DO NOTHING;
