INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'the-world-of-maria', 'The World of Maria', 'The World of Maria is a medieval and fantasy server created on April 5th, 2012. Maria is a Medieval and Fantasy server that includes many plugins to help the experience as well as great builds! Our main RP additions include Magic, Kingdoms and titles, custom mounts, alcoholic beverages (and the ability to brew them) quests, npc''s, custom bosses and monsters, and more. Our website is WorldOfMaria.com where our forums, application areas, and PSA''s are! Feel free to join, adventure through our server dungeons, settle in with our towns, or fight using our custom weapons!  
