INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'simply-vanilla-anarchy-no-hacks-pvp', 'Simply Vanilla - Anarchy | No Hacks | PvP', 'We have been **online since 2019** with a strong discord community and 10-30 active players. No hacking/duping allowed. _Vanilla world-borders and Nether-roof is accessible._  
  
Want to experience anarchy without everyone hacking or long queues or low tps? Join Simply Vanilla! The server prides itself with having only very few plugins installed to keep things as Vanilla and Anarchy as possible. The server has never been reset and never will be, the current **6 TB map size** speaks for itself.  
  
We are **hosted in EU** giving all players in Europe an excellent ping while still being reasonably good for North American players.  
  
_Join Today!_', 'simplyvanilla.net', 25565, 'mc_java', 'active', true, NULL, 'https://simplyvanilla.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'capecraft-minecraft-survival-at-its-best', 'CapeCraft - Minecraft survival at its best', 'CapeCraft is a server dedicated to keeping Minecraft''s core aspect alive. We are a survival server where you''ll be encouraged to work, trade and share with other players. CapeCraft is a survival server with No PVP, No Griefing and No Abuse of any type. We try to keep our server family friendly which is why we ask for no swearing and an English only chat on the server. All of our staff are friendly but firm and rule breakers will be swiftly dealt with.  
  
The community will thrive and develop into small communities each having their own village name and shops. Certain people will be in charge of each village and this will be entirely up to the people who run them. Players can start their own shops and villages just by building them and inviting people over, they can grow from there. All these villages will be player run and no commands will be used to set any villages up, nor will any ranks be given to players who own a village. Each village can have their own rules and it''s completely up to the players to run and maintain them!  
  
Of course, there is always the option to live on your own, not in a village which is always as fun! You can just visit the public shop to buy/sell items and enjoy survival from there.', 'play.capecraft.net', 25565, 'mc_java', 'active', true, NULL, 'https://capecraft.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'crystalgemcraft', 'CrystalGemCraft', '🌟 Chào mừng bạn đến với "CrystalGemCraft" - Trải nghiệm Minecraft hoàn hảo đúng nghĩa! 🌟  
  
🌍 Khám phá một thế giới Minecraft mới đầy thú vị và cơ hội thăng tiến không giới hạn tại "CrystalGemCraft". Với hàng loạt chức năng tiêu điểm như sau:  
  
🏙️ Hệ thống Towny: Xây dựng và quản lý thị trấn của riêng bạn! Hợp tác với bạn bè để phát triển thị trấn, mở rộng lãnh thổ, và bảo vệ căn cứ khỏi sự xâm nhập của người chơi khác. Cùng nhau tạo nên một cộng đồng thịnh vượng và vững mạnh.  
  
✨ Enchant Đặc Biệt: Trang bị của bạn sẽ trở nên mạnh mẽ hơn bao giờ hết với hệ thống enchant đặc biệt của chúng tôi. Khám phá và chế tạo trang bị có sức mạnh đặc biệt để chinh phục thế giới.  
  
📜 Nhiệm Vụ: Hãy tham gia vào các nhiệm vụ thú vị để kiếm phần thưởng và phát triển tài năng của bạn. Sẵn sàng đối mặt với thách thức và trải nghiệm những câu chuyện độc đáo.  
  
🧙‍♂️ Class và Profession: Lựa chọn lớp nhân vật và nghề nghiệp của bạn để xác định con đường phát triển riêng của bạn trong thế giới này. Có vô số cơ hội để bạn tạo ra hình ảnh nhân vật độc đáo của mình.  
  
📈 Cấp Độ: Tiến bộ qua các cấp độ để trở nên mạnh mẽ hơn và mở khóa các kỹ năng mới. Hãy theo đuổi đỉnh cao và trở thành một trong những người chơi hàng đầu.  
  
🛡️ Trang Bị RPG: Tìm kiếm và chế tạo trang bị RPG độc đáo. Điều chỉnh trang bị của bạn để phù hợp với chiến thuật của bạn và chinh phục mọi thách thức.  
  
👾 Quái Vật và Boss Đa Dạng: Đối đầu với một loạt quái vật đáng sợ và boss đầy thách thức. Sẵn sàng đối mặt với những cuộc chiến cam go để kiếm lấy phần thưởng hoặc khám phá các kỹ năng chiến đấu của bạn.  
  
⚔️ Hệ thống Dungeon: Khám phá các dungeon đầy rẫy quái vật và cạm bẫy. Chiến đấu và vượt qua những thử thách cam go để giành lấy những phần thưởng quý giá và nâng cao kỹ năng chiến đấu của bạn.  
  
🛒 Shop: Mua và bán hàng hóa với thông qua hệ thống shop đa dạng của chúng tôi. Kiếm tiền và xây dựng tài sản của bạn!  
  
🎁 Crate: Mở các crate độc đáo để nhận được phần thưởng quý giá và trang bị hiếm có. Cơ hội trúng lớn đang chờ đợi bạn.  
  
🌄 Thế Giới Tài Nguyên Vô Hạn: Khám phá một thế giới tài nguyên bao la và không giới hạn. Khai thác tài nguyên, xây dựng và sáng tạo mà không cần lo hết tài nguyên.  
  
🔥 Hãy tham gia "CrystalGemCraft" ngay hôm nay và khám phá một thế giới Minecraft đẳng cấp với các tính năng độc đáo không thể tìm thấy ở bất kỳ nơi nào khác. Sẵn sàng trải nghiệm một cuộc phiêu lưu Minecraft đích thực chưa từng có! 🔥', 'mc.crystalgemcraft.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.crystalgemcraft.com/', NULL) ON CONFLICT (slug) DO NOTHING;
