INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mithrilmagic', 'MithrilMagic', 'Welcome to MithrilMagic! We are a new 1.18.2 Towny server. We have many plugins including Mcmmo, Brewery, Jobs Reborn, ChestShop, Player Warps, Slimefun 4, Magic, Dynmap, Duels, and many more! Come play with us for a great time building nations, towns, and growing as a community! Lose track of time exploring the map for our fabled underwater fruit trees all while leveling up your magic skills! Create the largest shop on the server or sell you goods on the auction house to become the richest player! Use your newfound wealth to purchase our ranks and make the best town on the server! Whether you want to automate every item in the game with Slimefun, fly around the map in your Movecraft, or become the most powerful Wizard, MithrilMagic has everything you are looking for.  
  
This server also allows people who use Bedrock Edition.  
  
