INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lands-of-minearchy', 'Lands of Minearchy', '**Lands of Minearchy**  
Hello Heroes, and welcome!   
We are the Minearchy Team and want to tell you about our passion project.  
  
Our server has two goals:  
_- Create an active and friendly community that brings people together  
- Make sure that everyone has fun, whether they play often or not so much_  
  
We currently focus on SMP & Minigames.   
With regular events and in-game activities! Stay with us to find out more.  
  
**Survival / SMP**  
Take a break from fast-paced game-modes and play something more relaxing.   
Introducing Minearchy SMP! Here, you can enjoy an unfiltered survival experience that includes Quality-Of-Life improvements among others. We have Chest Shops, Auctions, Safe Zones, Warps, Grief Protection, and more. — We even have a Dynmap!  
  
**Minigames**  
Combining popular games with beautiful builds and appealing gameplay.  
  
We have a wide selection of minigames:  
_- TNT Run  
- TNT Tag  
- BombLobbers  
- Parkour  
- Splegg  
- Prophunt  
- TempleRun  
- TheLab  
- Party Games  
- Block Party  
- KitPVP  
- Quake  
- Mini Walls  
- Zombies  
- MineKart_  
  
Our team is working to make more activities available soon.  
_Upcoming Games: ElytraRace & Bedwars_  
  
**Join Now**  
  
_Java IP_  
play.minearchy.com  
  
_Bedrock IP_  
bedrock.minearchy.com  
  
We are open to the public and work hard to ensure everyone has a good time.  
Hope to see you there soon!  
- Minearchy Team  
  
**Looking for Staff**  
We''re currently looking for passionate individuals to join our staff team!  
Whether you''re a creative builder, a skilled moderator, or a tech-savvy developer, there''s a place for you here:  
https://landsofminearchy.com/apply ﻿  
  
**Helpful Links**  
[Discord](https://discord.gg/QrJ6wubA3E) | [Website](https://landsofminearchy.com) | [Subreddit](https://www.reddit.com/r/LandsOfMinearchy) | [YouTube](https://youtube.com/@jonaas13/)', 'play.minearchy.com', 25565, 'mc_java', 'active', true, NULL, 'https://landsofminearchy.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rambomc', 'RamboMC', 'RamboMC is een Nederlandse minecraft server geschikt voor zowel java als bedrock spelers!  
  
Onze gamemodes zijn altijd op de nieuwste versies beschikbaar waardoor jij nooit de nieuwste features van Minecraft mist!  
  
Onze geschiedenis:  
RamboMC is opgericht op 6 januari 2021 en is sindsdien niet meer te stoppen, in ondertussen al 2 jaar hebben wij ons steeds verder ontwikkelt en een enorme groei mogen meemaken. Zo hebben wij 78.000 unieke spelers mogen verwelkomen op ons netwerk en staan wij al lange tijd #1 in de Nederlandse top lijst.  
  
Wat ons uniek maakt:  
Wij hebben veel unieke features te ontdekken in de server, hierdoor raak jij vrijwel nooit uitgespeeld omdat er altijd wel iets te doen is. Loop je ergens tegen aan? Ons staff-team staat altijd voor jou klaar, binnen onze support tijden heb je altijd binnen een aantal minuten reactie en streven wij naar een goede oplossing voor jouw probleem. Onze community zal je bij binnenkomst al direct verwelkomen, hierdoor voel je je direct thuis!   
  
Veiligheid:  
Wij streven naar een veilige server, hierdoor worden onze servers continue in de gaten houden door vrijwillige moderators. Ook hebben wij regels opgesteld die gevolgd moeten worden, hierdoor is het altijd duidelijk waar jij je aan moet houden om de omgeving veilig te houden voor iedereen.   
  
Gamemodes:  
Survival & Oneblock  
  
Natuurlijk kan je pas echt kijken of RamboMC wat voor jou is wanneer je het ervaart, dat kan via de volgende gegevens:  
IP: play.rambomc.nl  
PE PORT: 19132', 'play.rambomc.nl:25565', 25565, 'mc_java', 'active', true, NULL, 'https://rambomc.nl', NULL) ON CONFLICT (slug) DO NOTHING;
