INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'meadow-smp', 'Meadow SMP', '🌷 Welcome to Meadow SMP - Your new Minecraft home!  
Whether you’re building, exploring, or creating content, Meadow SMP has everything you need and more! It’s the perfect place for players and creators alike, with plenty of options to make the experience perfectly suited just for you.  
  
🌱 Why Choose Meadow SMP?  
  
🎮 Play on your preferred platform, as our server fully supports both Java and Bedrock editions.  
  
🌸 With an already awesome playerbase and tons of friendly players, Meadow offers a warm and welcoming atmosphere along with a wide range of quality of life features, completely free for everyone to use.  
  
🌎 Explore a massive world filled with stunning custom generated biomes that stay true to vanilla Minecraft mechanics.  
  
🏡 Build without limits using protected land claims that let you create your own plots, safely play with friends, and manage everything through a clean, user friendly menu.  
  
🌳 Enjoy a seamless automatic questing system with a huge library of tasks that progress naturally as you play and reward you with awesome loot.  
  
💰 Shape the economy with community driven features like shops, orders and an auction house. Buy, sell, and trade to your heart’s content!  
  
🦅 Across the server, players can enjoy optional dash and double jump abilities for even more fun while exploring!  
  
⚔️ PvP is completely optional, allowing you to decide whether or not you want to engage in player versus player combat, you choose your playstyle!  
  
🎤 We support proximity voice chat for immersive gameplay, with installation instructions available in our Discord.  
  
🗺️ View the entire world and player creations anytime on our live online world map.  
  
🌀 A separate arena world is available for players to create custom kits, practice, and PvP without affecting the main world.  
  
🔥 Stay excited with Meadow SMP always running the latest Minecraft updates for fresh content and endless exploration.  
  
🌟 Calling All Content Creators!  
If you’re a creator, you can apply for FREE Media Rank, unlocking all rank perks on the server as well as promotion opportunities to help grow your community!.  
  
✨ Join Meadow SMP today and become a part of a growing, creative community!  
  
🌐 IP: meadowsmp.com  
📱 Bedrock Port: 19132  
🛒 Website: store.meadowsmp.com  
💬 Discord: discord.gg/4NQugAEPg3  
🗺️ World Map: map.meadowsmp.com', 'play.meadowsmp.com', 25565, 'mc_java', 'active', true, NULL, 'https://store.meadowsmp.com/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minevane-new-zealand', 'Minevane New Zealand', 'Minevane is an NZ based Survival server aiming to provide a chill, relaxed server with minimal rules (common sense applies). We offer a bunch of different features which make survival just that little bit more fun!   
  
Our server is geo-locked so only players from New Zealand and Australia can join! If you''re outside these countries but want to join our server, join our Discord and ask a Staff member how to become apart of our community! https://discord.gg/xMfB2WcyuG  
  
We have friendly staff so don''t be afraid to sing out.  
  
Check us out today :)  
  
Connect with: minevane.nz, minevane.co.nz, or minevane.com', 'minevane.nz', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'astrocraft-survival', 'AstroCraft - Survival', 'SURVIVAL SEASON 1! NEW SPAWN! ASTRO SMP is protected with land claim (grief prevention), and you gain more as you play. We try to keep it as close to normal vanilla survival as possible. There are FREE in game ranks that you work towards by voting and unlock more land claim and chest shops. Keep inventory is enabled everywhere besides pvp areas. The world border is set at 30k x 30k. Everything is pre-generated, so it is lag free.  
  
In ASTRO SMP, the economy is community based. Player build chest shops or sell in auction house for money. There are also Jobs which you can make money but also get points. You can use those points to by Vehicles (Planes, Trains, Cars, etc.) You can also use points to buy spawners. There are also custom enchants for the PvP areas. ASTRO SMP has quick shop for selling to other players. Use player warps to get to players shops.  
  
Newly added custom fishing and voting system! Find new types of fish and bait. There are also daily fishing tournaments at certain times of the day for rewards. We also just changed the vote system. Vote for vote points which you can redeem in the vote shop. You can get claim blocks, money, keys, and bunch of other cool stuff. There are also lucky votes which has a chance to give you rare keys.  
  
Newly added resource worlds and events! The resource world resets every month and is limited with a 10k x 10k world border. The nether resource world is the same. The end resource world resets everyday. We also added in /events and with these there will be daily, weekly, and monthly events. If you are in the top 3, you will get a few good rewards (Keys, Job Points, Money, Diamonds). The weekly and daily events will be changed once a week, so that you have fresh events to compete in.', 'mcmp.astrocraft.org', 25565, 'mc_java', 'active', true, NULL, 'https://www.astrocraft.org/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'us-eu-au-playcdu-network', '[US, EU, AU] PlayCDU Network', '![](https://cdn.playcdu.co/Banner.gif)  
  

**CHECK OUT ALL THE MODPACKS WE CURRENTLY HOST ON OUR SERVER LIST:<https://www.craftdownunder.co/server-list>**
  
  
**Our Links:**   
Server List: <https://www.craftdownunder.co/server-list>  
Website: <https://www.craftdownunder.co>  
Discord: <https://discord.gg/playcdu>  
Forums: <https://forum.playcdu.co/>  
  
**About Us:**  
Craft Down Under is a gaming community that specializes in hosting and playing Minecraft modpacks. Our servers, located in Australia, the United States, and Europe, offer a wide variety of modpacks to suit different playstyles and preferences. We''re dedicated to providing a welcoming environment for all players, regardless of their skill level, to come together and enjoy the unique experiences that modpacks provide. Join us today and see why Craft Down Under is the go-to destination for Minecraft modpack enthusiasts!  
  
**Key Features:**  
★ Community Choice: Our community chooses which modpacks we host by suggesting and voting on our custom built platform - Modpack Voter <https://modpacks.playcdu.co/>  
★ We are always looking to host new modpacks which are sought after by our community!  
★ Multiple Locations: We are currently hosting our servers in 3 locations: Australia, USA and Europe (Germany). This allows players, no matter where they are from, to play on our servers with minimal ping.  
★ Always Online: Our dedicated servers are online 24/7 so you can play whenever you like!  
★ Chat Synchronisation: Global chat between the same modpack on AU/US/EU servers are synchronised so you can talk to players on either server. Discord chat integration is also available on all servers!  
★ Regular Backups: All our servers are backed up regularly to ensure maximum reliability and stability  
★ Voting: Vote for our servers to receive rewards! Make sure you are in-game when you vote to receive the rewards. Vote links can be found here: playcdu.co/vote', 'nohub.playcdu.co', 25565, 'mc_java', 'active', true, NULL, 'https://www.craftdownunder.co/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'emortalmc', 'EmortalMC', 'EmortalMC is the first minigames server created with Minestom.  
  
