INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'royalemc', 'RoyaleMC', '**RoyaleMC | Survival | 1.21.X | Java + Bedrock**  
  
**Java IP:** play.royale-mc.com  
**Bedrock IP:** play.royale-mc.com:19132  
  
**About Us**  
  
RoyaleMC is the ultimate Slimefun network for Minecraft players seeking a unique and engaging experience. With Slimefun add-ons integrated into every aspect of our server—from crates to rank upgrades—we offer the most immersive Slimefun grind available. Whether you''re a Slimefun enthusiast or just curious, our expert staff and welcoming community are here to guide you through your adventure. Not a fan of Slimefun? No problem! You can fully enjoy our server with minimal Slimefun interaction, only needing it for minor item unlocks to access exciting rank perks.  
  
We proudly champion a non-pay-to-win philosophy. All perks, including /fly, are accessible to every player through our innovative vote-to-win system. By voting daily on supported voting sites, you earn vote points that can be spent in our Vote Point Shop to unlock premium features, ensuring a fair and rewarding experience for all players. Join us for a fun, lag-free, and community-driven adventure!  
  
**Key Features**  
  
✘ **Lands Plugin** – Protect your builds and collaborate with others.  
✘ **Slimefun + Add-ons** – Dive into a vast array of custom items and mechanics.  
✘ **Vote-to-Win System** – Earn vote points through voting to unlock donor-like perks.  
✘ **Balanced Economy** – Enjoy a fair and sustainable in-game economy.  
✘ **Active Community & Staff** – Our dedicated team, including an ever-present owner, ensures a vibrant community.  
✘ **1300+ Quests** – Including Slimefun-specific challenges for endless gameplay.  
✘ **mcMMO & Jobs** – Level up skills and earn rewards through various professions.  
✘ **Dynmap** – Explore our world in real-time at <http://map.royale-mc.com>.  
✘ **Brewery + Custom Recipes** – Craft unique brews with exclusive recipes.  
✘ **Player Shops & Auction House** – Trade and thrive in our player-driven economy.  
✘ **Cosmetics & Pets** – Personalize your experience with fun extras.  
✘ **Pyro Fishing & Pyro Mining** – Enhanced fishing and mining experiences.  
✘ **Events & Monthly Collectors** – Participate in regular events and collect exclusive items.  
✘ **100% Lag-Free** – Optimized performance for seamless gameplay.  
✘ **DiscordSRV & Chat Tags** – Stay connected and express yourself with custom tags.  
  
**Slimefun Add-ons**  
  
Our server features a curated selection of Slimefun add-ons, including:  
✘ Networks ✘ SfChunkInfo ✘ FNAmplifications ✘ DynaTech ✘ InfinityExpansion2 ✘ SfHeadConverter ✘ SlimeHUD ✘ Supreme ✘ SFCalc ✘ SlimeVision ✘ SlimyTreeTaps ✘ SlimeTinker ✘ FlowerPower ✘ TranscEndence ✘ FluffyMachines ✘ EcoPower ✘ HotbarPets ✘ ExoticGarden ✘ HeadLimiter  
  
**Available Servers**  
  
**Hub** – Your gateway to all RoyaleMC experiences.  
**Survival** – 1.21.4 (Reset July 2025)  
  
**Community Info**  
  
RoyaleMC is a non-profit community where all donations directly support server maintenance and growth. Running strong since 2019, we’re committed to delivering frequent updates, new features, and exciting events. Our active owner and staff are always available to assist, and our Discord is the perfect place to connect with fellow players. Visit our wiki for detailed guides and information at <https://wiki.royale-mc.com>.  
  
**Java IP:** play.royale-mc.com  
**Bedrock IP:** play.royale-mc.com:19132  
**Website:** <https://www.royale-mc.com>  
**Discord:** <https://discord.com/invite/69cqBHD>  
**Wiki:** <https://wiki.royale-mc.com>', 'play.royale-mc.com:25565', 25565, 'mc_java', 'active', true, NULL, 'http://www.royale-mc.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rpdnd-5th-ed-d-d-rp-16-only', 'RPDND | 5th ed. D&D RP | 16+ Only', 'RPDND is a 5th edition dungeons & dragons roleplay experience using Minecraft as our gameboard. Live out your characters day to day life following the path of a civilian (non-combatant roleplay character) or an adventurer (combatant-d&d character). With a 1 to 1 d&d economy, all your items in-game for you to hold, racial abilities to flavor your roleplay and a 15,000x map to explore what is stopping you? A whitelist isn''t... we have been a graylist since the beginning welcoming new players from all levels of roleplay/dnd experience.  
  
