INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'furry-refuge-community-server', 'Furry Refuge Community Server', 'We’re a small but growing community of Furries with a community server that is welcome to anyone and everyone who wants to join! We’ve got landclaiming, a bit of an economy going, along with Slimefun! We try to foster a a friendly encronment with players on daily. Lands will allow you to claim a property by doing “/lands claim”.. you can also use the little menu book we’ve provided. Slimefun book is also very easy to use and uses xp to unlock tech stuff. If you want a more vanilla play, you can definitely do that without having to worry about tech stuff. On the other hand, you can delve deep into tech without mods, allowing even players with crappy computers to play on our server and have just as much fun. Remember, you can save your xp by using a empty bottle item in a crafting table. keep “soulbound” items in your inventory upon death, and other stuff! Join us on telegram at telegram.furryrefuge.com or our discord which is discord.furryrefuge.com. We hope to see you in-game, and if not, you can use the bot to chat to people in-game from telegram or discord minecraft chats!', 'mc.furryrefuge.com', 25565, 'mc_java', 'active', true, NULL, 'http://furryrefuge.com', NULL) ON CONFLICT (slug) DO NOTHING;
