INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'fyremc', 'FyreMC', 'A csatlakozáshoz a saját minecraft kliensünk telepítése szükséges, melyet megtalálsz a weboldalunkon.  
  
A szervert 2019-ben Rolix és Nexuser hozta létre, hogy egy új szintre emelje a Minecraft többjátékos élményt. Mi hiszünk a minőségben, az egyedi építményekben, pluginok-ban és természetesen a legfrissebb verzióban.  
