INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'vergamed-de', 'Vergamed.DE', 'Hallo liebe Minecraft-Community,  
  
Vergamed.de ist ein Minecraft Multiserver der verschiedene Spielserver anbietet. Dadurch ist man nicht an einen festen Spielmodus gebunden, sondern kann auswählen und wechseln zwischen Hard-Survival-Server (PVP), Survival-Server, CityBuild. Zudem verfügen wir über einen Eventserver und einer großen Lobby.  
  
Nach Monaten langer Arbeit wagen wir es nun die Alpha zu eröffnen.  
  
Unser Serverangebot verfügt über nachfolgende Spielformen:  
  
-Survival 1.19 - viele tolle Plugins, Farmwelten, versteckten Ruinen usw.  
-Hard-Survival 1.19 - keine kaufbaren Vorteile, nur nötige Plugins  
-Citybuild 1.19 - Baue in deinem Plot, Farmwelten, tolle Features  
-Event-Server geöffnet an Feiertagen  
-BedWars – Öffnet Bald  
  
  
  
  
Vorteile der Alpha:  
-Ein Monat Supreme (Höchster Rang) kostenlos  
-Kostenlose Starterkits im Shop  
-Shop Angebote mit 80% Rabatt  
-Finde behebbare Fehler und erhalte Pixel  
-Du bist von Anfang an mit dabei  
-Aufstieg ins Team möglich (Supporter, Developer, Webdesigner, Builder werden aktuell gesucht)  
-Beanspruche die besten Plätze  
-Teste neue Features  
-Werbe Freunde an und erhalte extra Claim Blöcke  
-Erreiche 100 Spielstunden und erhalte einen Monat Premium kostenlos  
-Bedrockspieler können uns über mc.pixelmatrix42.de Port 19132 erreichen.  
  
  
  
Nachteil der Alpha:  
-Fehler können auftauchen, welche auch einen Neustart nötig machen.  
-Kurzfristige Wartungsarbeiten können nötig sein  
  
  
Kommt bei Fragen einfach in unseren Discord: https://discord.gg/minecraft-germany-vergamed-938947907351093328  
  
Wir freuen uns auf euch 😊  
  
PixelMatrix42/Vergamed steht in keiner Verbindung mit Minecraft oder Mojang oder ist von diesen genehmigt.', 'vergamed.de:25565', 25565, 'mc_java', 'active', true, NULL, 'https://shop.vergamed.de/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ventureblockmc', 'VentureBlockMC', 'Arcadia (1.21.8 – Season 1) – A dynamic season-based survival experience with PvE/PvP, player shops, dynamic pricing, custom brewing, custom spawners, McMMO, and more. Worlds, stats, and economy reset with each major Minecraft update, keeping gameplay fresh and competitive!  
  
