INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'au-craft-down-under-all-the-mods-10', '[AU] Craft Down Under | All The Mods 10', '![](https://cdn.discordapp.com/attachments/455359036540321804/975393973931769916/Banner.gif)  
  
