INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'foundation-craft', 'Foundation Craft', 'Are you looking for a new survival server where you can build, hang out, and make friends? Look no further than Foundation Craft, a new SMP server for Minecraft: Java Edition with a unique blend of survival, economy, and role-playing features including a skills system, dangerous uncharted worlds to explore, claimable land, and a realistic real-estate economy!  
  
The cool thing about Foundation Craft is that it accommodates all different kinds of play styles. There are two main areas on the server: The Wilderness and The Frontier. The Wilderness is a dangerous and unprotected realm where griefing, stealing, and combat are allowed. The Frontier is a safe and peaceful world for building, hanging out, and role playing.  
  
Players can claim land in The Frontier by creating settlements. Settlements are claimed areas of land where homes and shops can be created. Homes can be rented or sold to other players, while shops can be used to trade items with other players. The economy is based on emeralds, so you can work your way up the economy by trading with villagers and then use your emeralds to claim land and buy items. The server is family-friendly and the community is very welcoming. Come check it out!', 'play.foundationcraft.com', 25565, 'mc_java', 'active', true, NULL, 'https://foundationcraft.com', NULL) ON CONFLICT (slug) DO NOTHING;
