INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'topstrix', 'TopStrix', 'טופסטריקס הוא המקום שבו מיינקראפט באמת נהיה כיף. נכנסים לשרת אחד ומוצאים עולם מלא במשחקים שונים, אתגרים, הפתעות ותוכן חדש שמגיע בלי הפסקה.  
כל משחק בנוי בצורה ייחודית וכל פעם שמתחברים מגלים משהו חדש להתמכר אליו.  
  
זה השרת שמתאים לכל מי שאוהב לגוון: רגע אחד אתם נלחמים מול שחקנים, רגע אחר מגלים שהבסיס שלכם נחרב ורגע אחר קוטפים צמחים מהגינה שלכם, חוקרים או פשוט משתוללים עם חברים - הכול מיוחד יותר, עם סאונד מרשים, נראות כיפית וחוויה מיוחדת במיוחד, בטופסטריקס ממשיכים להשקיע מ-2013 ולהיות ה-שרת של ישראל.  
  
מחכים לכם בשרת, צוות טופסטריקס.', 'play.topstrix.net', 25565, 'mc_java', 'active', true, NULL, 'https://store.topstrix.co.il', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'avatarverse-open-world-avatar-rpg-bending-nations', 'Avatarverse | Open-World Avatar RPG | Bending | Nations', 'Welcome to Avatarverse, an open-world Minecraft server based on the world of Avatar: The Last Airbender and The Legend of Korra. Avatarverse is an RPG (Roleplaying Game) server, in which each player creates a character through which they interact with the world.  
  
Avatarverse offers a full, custom, and large-scale recreation of the Avatar world. We have almost all the locations from the shows and other canon content, plus more. You''ll be able to walk through the streets of Ba Sing Se or Republic City, go swimming at Kyoshi Island, meditate in any of the five Air Temples (including Korra''s Air Temple Island), and pretty much anything else you can think of.  
  
Avatarverse is dedicated to reproducing the world of Avatar in Minecraft in every possible way. Your character will be able to do things real people in the Avatar world could do, like bend the four elements or use unique weapons/block chi if you''re a nonbender, run nations, participate in governments, join a military, fight in wars, etc. The roleplay of Avatarverse is open-ended, and you are free to choose your own story.  
  
On Avatarverse, you can actually bend the four elements: water, earth, fire, air. Avatarverse also has dozens of bending abilities found nowhere else. We also offer custom mobs like the sky bison, which you can even ride on and fly around, and the dragon, which is ridable and can even breathe fire to roast people alive. There are several other custom mobs and we are always trying to add more.  
  
One of the most interesting aspects of Avatarverse is its player-run nations and politics. Real canon nations like the Water Tribes, Earth Kingdom, and Fire Nation are all run by real players who are playing the game just like you. They govern whole countries and need people to help them do so. Maybe your character will be suitable for that! Nations have also gone to war and conquered each other from time to time. Almost anything is possible!  
  
The server has been continuously developed for over two years now, and we are deciding to advertise again for the first time in a while because the server is actually stable now. We are always adding new features and trying to improve the experience of our players. Our community is welcoming, and everyone has been itching for the server to expand to its full potential, so people will try their best to help you out! You just have to actually want to try out new things. There''s a place for everyone here on Avatarverse, and we''re so excited for you to join', 'play.avatarverse.net', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/amqJTaqH9X', NULL) ON CONFLICT (slug) DO NOTHING;
