INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'astro-smp', 'ASTRO SMP', 'SURVIVAL SEASON 1! NEW SPAWN! ASTRO SMP is protected with land claim (grief prevention), and you gain more as you play. We try to keep it as close to normal vanilla survival as possible. There are FREE in game ranks that you work towards by voting and unlock more land claim and chest shops. Keep inventory is enabled everywhere besides pvp areas. The world border is set at 30k x 30k. Everything is pre-generated, so it is lag free.  
  
In ASTRO SMP, the economy is community based. Player build chest shops or sell in auction house for money. There are also Jobs which you can make money but also get points. You can use those points to by Vehicles (Planes, Trains, Cars, etc.) You can also use points to buy spawners. There are also custom enchants for the PvP areas. ASTRO SMP has quick shop for selling to other players. Use player warps to get to players shops.  
  
Newly added custom fishing and voting system! Find new types of fish and bait. There are also daily fishing tournaments at certain times of the day for rewards. We also just changed the vote system. Vote for vote points which you can redeem in the vote shop. You can get claim blocks, money, keys, and bunch of other cool stuff. There are also lucky votes which has a chance to give you rare keys.  
  
Newly added resource worlds and events! The resource world resets every month and is limited with a 10k x 10k world border. The nether resource world is the same. The end resource world resets everyday. We also added in /events and with these there will be daily, weekly, and monthly events. If you are in the top 3, you will get a few good rewards (Keys, Job Points, Money, Diamonds). The weekly and daily events will be changed once a week, so that you have fresh events to compete in.', 'mc.astrocraft.org', 25565, 'mc_java', 'active', true, NULL, 'https://www.astrocraft.org', NULL) ON CONFLICT (slug) DO NOTHING;
