INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'amity', 'Amity', '🎮🌟 Introducing the Ultimate Minecraft Survival Server: Amity! 🌟🎮  
  
Are you ready for an incredible and immersive Minecraft experience? Welcome to Amity, a server crafted just for you! 🏰  
  
✨ Experience Vanilla Survival with a Twist! ✨  
Our server is tailored to bring you the purest, true-to-the-core Minecraft experience, enhanced with convenient teleportation and base protection. It''s time to rediscover the essence of Minecraft Survival mode!  
  
🏠 Easy Teleportation with Home System 🏠  
Set up multiple homes with ease, allowing you to teleport back to your cozy abode or favorite mining spot in no time. Explore the vast world without worrying about getting lost!  
  
🛡️ Safeguard Your Base with Our Claiming System 🛡️  
Protect your hard-earned possessions and spectacular creations with our intuitive claiming system. No more griefing, theft, or unwanted visitors. Your base, your rules!  
  
🚀 Lag-free Gaming, Powered by UK Server 🇬🇧  
Say goodbye to lag! Our top-notch server is hosted in the UK, providing you with a smooth, seamless gaming experience. Perfect for those epic build sessions or intense PvP battles!  
  
🎒 Keep Inventory: The Choice is Yours! 🎒  
Amity offers the option to enable or disable Keep Inventory any many more. Customize your gameplay experience to suit your preferred level of challenge!  
  
🤝 Friendly, Supportive Community 🤝  
Join a warm, welcoming community of fellow Minecraft enthusiasts. Share your creations, exchange tips, or just chat with new friends - it''s all here at Amity!  
  
🏆 No Pay to Win - Just Pure Fun! 🏆  
We believe in fairness and equal opportunities for all players. That''s why our server has a strict no pay-to-win policy. Enjoy a balanced gaming experience, where skill and creativity are the only factors that matter.  
  
🎉 Exciting, Regularly Hosted Events 🎉  
Participate in thrilling events hosted by our dedicated staff, from building contests and treasure hunts to PvP tournaments and more. There''s always something happening at the Amity!  
  
So what are you waiting for? Join Amity today and embark on your greatest Minecraft adventure yet! 🌐 IP: play.amitymc.net', 'play.amitymc.net', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'project-azoth', 'Project AZOTH', 'The AZOTH Network is a growing community project that features a faithful but wholly unique Pokemon MMO based on the Pokmon series games as well as a handful of other Minecraft servers that aim to combine the best of both series. It has been in the works since 2011. While the project has gone through many different phases and servers since its humble beginnings, it finally began to take shape in 2020 after making its way back to the original community that started it all and rebranding into what it is today.  
  
We strive to provide a definitive experience that pulls in ideas from all the best places, without resorting to Pay-2-Win practices that so many other communities have fallen prey to. ABSOLUTELY NO LOOTBOXES, CRATES, GAMBLING, MONEY-GRUBBING OR MICROTRANSACTIONS WHATSOEVER! Our experienced staff aims to keep the environment as fair and balanced for each and every player as possible; the era of P2W Cobblemon servers and PokeMMO knock-offs ends with us.  
  
-Fully-Featured Pokemon Adventure Map  
-Adventure through Kanto, Johto, Hoenn, Sinnoh, Unova, Kalos, Alola, Galar, and beyond!  
-Origins-Style Gym scaling that alters a Gym Leader''s Team based on your party strength and number of Badges.  
-Interconnected world woven together with areas from the unreleased Spaceworld Beta.  
-Shadow Pokmon storyline in the Orre region from Colosseum.  
-CustomNPCs with tailored scripts for item storage, usable TM Cases, Game Corner games, and more!', 'play.projectazoth.net', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/ac9VAQrdNN', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'aquasmp', 'AquaSmp', 'Very Friendly Staff and player base  
