INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lus-adascraft', 'LusíadasCraft', 'Desde março de 2023, o LusíadasCraft junta a comunidade portuguesa num Survival com temática da nossa cultura.   
