INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'totalcraft-skyblock', 'TotalCraft SKyBlock', 'Bem-vindo ao TotalCraft SkyBlock - Uma Experiência Épica de Sobrevivência no Céu!  
  
