INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'survivalkreis-de', 'Survivalkreis.de', 'Wir sind ein kleiner, aber feiner Server. Bei uns kann jeder spielen und sich frei entfalten. Wir haben ein paar wenige Regeln, aber auf die legen wir großen Wert.  
  
Der Server wurde am 19.03.2021 erstellt und finanziert sich durch 4 Personen vom Team von ganz alleine, so das Spieler nicht gezwungen sind bei uns Spenden oder sonstiges zu hinterlassen außer die Zeit die sie zum Spielen hier lassen.  
Unser Team besteht aus Erwachsene Spielern, welche sich durch Hilfsbereitschaft und Fairness auszeichnen.  
  
Wie kann ich bei Survivalkreis.de spielen?  
  
Wir spielen nur auf Java 1.21.4  
  
Welcher Spielmodus ist bei Survivalkreis.de vorhanden?  
  
Wir haben Survival, und schauen das wir bei größerer Veränderung auch Regelmäßig das wir die Welten resetten!  
und im ca.4-8 Wochen Rhythmus wird End und Nether resettet.  
Aber wir planen auch Neuerungen und hin und wieder gibt es einen Modsserver.  
  
Informationen:  
  
Wir sind eine Kleine Community mit Jungen und Älteren Spielern, die ihren Feierabend und ihr Hobby in diesem Spiel ausleben.  
Wir laden euch Herzlichst dazu ein uns und unser Projekt kennen zulernen.', 'survivalkreis.de:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
