INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hoobs-live', 'Hoobs Live', 'Are you tired of the same old Minecraft Servers? Is it putting you to sleep? Well, you''re in luck! Welcome to the worlds most interactive Minecraft server ever created. Hoobs brings you the best integration between your already favorite game and Youtube! You can play on our server by using the ip: hoobs.live or just hang out in the chat. There are tons of things to do in the chat, but the most important is to collect Hoob Loot! Get on our YouTube Channel and type !shop to get started.', 'hoobs.live', 25565, 'mc_java', 'active', true, NULL, 'http://hoobs.live', NULL) ON CONFLICT (slug) DO NOTHING;
