INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'augustatowny', 'AugustaTowny', 'Augusta Towny is a Minecraft server that offers a unique and immersive experience for players who enjoy town-building, player interaction, and the economy side of things. With the popular Towny plugin, players can join or create their own towns, and work together with other players to build, protect and grow their community. We offer custom world generation to allow your creativity to skyrocket. Our server also offers a friendly and welcoming community, where players can enjoy a variety of activities such as mining, farming, trading, and crafting. We have an economy system that allows players to earn money by selling their resources and items, and use it to take over baltop #1.Our staff team is dedicated to providing a safe and enjoyable environment for all players, and are always available to assist players with any questions or concerns. So come join us on Augusta Towny and experience the fun and excitement of town-building, exploration, and community interaction!  
  
Java Server IP: play.augustatowny.com  
Bedrock Server IP: play.augustatowny.com | Bedrock Port: 25565', 'play.augustatowny.com:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rede-saint', 'REDE SAINT', 'Descubra a diversão e aventura nos nossos servidores de Survival e Skyblock, disponíveis da versão 1.8 até a mais recente, pirata e original, computador (java) e mobile (bedrock). Nossa rede oferece uma experiência de jogo dinâmica e envolvente para todos os tipos de jogadores:  
  
Survival: Sobreviva e prospere em um dos 4 mundos personalizados. O servidor tem mcmmo, itens personalizados, temporadas, eventos, duelos, passe de batalha, torneios, clans, liga e muito mais! Disponível a partir da versão 1.16.5x até a mais recente. Suporte mobile.  
  
Skyblock: Comece em uma pequena ilha e use sua criatividade e habilidades para expandir, construir e dominar o céu. O servidor está disponível da versão 1.8x até a mais recente. Suporta mobile.  
  
IP (java) - redesaint.com  
