INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'tekno-mc', 'Tekno MC', 'Eğer klasik survival sunucularının sunduğu sıradan deneyimlerden sıkıldıysan ve gerçekten heyecan verici bir şeyler arıyorsan, işte aradığın yer tam olarak burası! Sunucumuz, seni sıradanlıktan uzaklaştıracak ve nefes kesici bir deneyime adım atmanı sağlayacak şekilde özel olarak tasarlandı.  
  
Gelişmiş sistemlerimiz, her adımında yeni keşifler yapmanı, zorlu görevlerle sınanmanı ve güçlü rakiplerle mücadele etmeni sağlayacak. Dinamik hava koşulları, zengin kaynak çeşitliliği ve yenilikçi mekanikler seni gerçek bir survival uzmanı olmaya davet ediyor.  
  
Burada, her köşede yeni bir macera seni bekliyor. Hadi, bu eşsiz dünyaya adım at ve sıradanlığa veda et! Hazır ol, çünkü bu deneyim seni ekran başından kaldıracak!', 'oyna.teknomc.net:25565', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/teknomc', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mystian-fields-modded-network', 'Mystian Fields Modded Network', 'At Mystian Fields, we strive to provide our players with an exceptional gaming experience. We pride ourselves on having no downtime and minimal lag, allowing you to fully immerse yourself in the game. Our servers are equipped with custom plugins, and we are constantly adding new features to enhance your gameplay.  
  
