INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ratonii-network', 'Ratonii Network', 'Ratonii Network este mai mult decât un simplu server de Minecraft românesc, este o comunitate vibrantă care oferă experiențe de joc pe versiunile de Java și Bedrock Edition. Ne străduim neîncetat să aducem un gameplay extraordinar și să creăm o atmosferă prietenoasă și plăcută pentru toți jucătorii noștrii pasionați.  
