INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'magbungkal-mc', 'Magbungkal MC', 'Magbungkal MC is a Filipino-based Minecraft server created to bring players together in one exciting and immersive world. Designed for both casual players and dedicated Minecraft enthusiasts, the server features three main game modes: Survival, Vanilla, and SkyBlock. Each mode offers a different style of gameplay, giving players the freedom to explore, build, and compete in ways that suit their preferences. Whether you enjoy gathering resources and thriving in Survival, experiencing the classic mechanics of Vanilla, or testing your creativity and strategy in SkyBlock, Magbungkal MC delivers a fun and engaging experience.  
  
The name “Magbungkal” comes from the Filipino word “Magmina,” which means “to mine.” This reflects the core element of Minecraft—mining and crafting—while also emphasizing the server’s Filipino identity. Magbungkal MC proudly highlights local culture and language, creating a familiar and welcoming environment for Filipino players while still being open to gamers from around the world.  
  
Magbungkal MC focuses on creating a friendly and cooperative atmosphere where players can connect, collaborate, and form lasting friendships. The server encourages teamwork through trading, community builds, and player-led events that keep the gameplay fresh and enjoyable. It is more than just a place to play; it is a space where players can express creativity and share memorable adventures.  
  
With optimized performance and active moderation, Magbungkal MC ensures smooth gameplay and a fair environment for everyone. The staff team works continuously to maintain balance, listen to player feedback, and introduce improvements that enhance the overall experience.  
  
Magbungkal MC is not just a server—it is a growing hub for creativity, teamwork, and endless Minecraft adventures.', 'play.magbungkal.com:20000', 25565, 'mc_java', 'active', true, NULL, 'https://magbungkal.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'solar-realms-generator-server', 'Solar Realms | Generator Server', 'Solar Skies is a custom generator tycoon packed with smooth gameplay, unique systems, and nonstop events. Build powerful generators, unlock upgrades, and explore unique features as you grind, progress, and compete to become the #1 player!', 'play.solarskies.net:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'valon-towny-keepinv-pyrofarming-pyrofishing-elitemobs', '⭐ Valon - Towny,KeepInv,PyroFarming,PyroFishing,EliteMobs', '**
📢 Welcome to Valon Towny!
**  
  
_Start a survival adventure focused on community, exploration, and creativity. Valon Towny offers classic Minecraft gameplay enhanced with AuraSkills, PyroMining, PyroFarming, PyroSpawners, and a variety of jobs, all within a unique and immersive world. Our worlds are generated with Terralith, featuring beautiful and open landscapes to explore on your adventures._  
  
**🔗 Connect Now:**   
Java: [t.valon.gg](http://t.valon.gg)   
Bedrock: [bt.valon.gg](http://bt.valon.gg)  
  
**🌟 Why Play on Valon Towny?**  
  
**🌍 Unique Generated Maps**   
The first time you step onto our maps, you''ll be amazed by the different biomes and big mountains. In the Overworld, Nether, and End, you''ll discover new areas and different places to explore, all created with Terralith and other world generator datapacks like Structory, Nullscape, and Incendium.  
  
**⚒ A Better Mining Experience**   
Mining is a big part of Minecraft, and on Valon Towny, it’s different. Discover hidden treasures and loot, and with PyroMining, access unique resources like Gemstones and Fluxes. Explore randomly generated dungeons and structures from our datapacks and BetterStructure addons. Uncover rare items and enhance your mining with AuraSkills such as Mining Luck and Mining Skill, and use mana abilities like Speed Mine.  
  
**💰 Balanced Economy**   
Buy and sell spawners, set up your own shops, and create warps to your stores. Our economy is fair and balanced, supported by activities like fishing, mining, and a variety of jobs such as Farmer, Hunter, Assassin, and Lumberjack. You can take on multiple jobs as you’re advancing through the ranks.  
  
**✨ Custom Enchantments & Elite Mobs**   
Enhance your gear with over 100 unique enchantments, allowing you to apply 8 to 13 different abilities to each item. Create the most powerful and personalized equipment to suit your playstyle, and use these enchanted items to conquer EliteMob dungeons and arenas, battling the toughest mobs Valon Towny has to offer.  
  
**🔥 Why Two Servers?**   
We run **Valon Towny** and **Kingdom**, our dedicated Slimefun server, to cater to different playstyles.   
_Ask a Slimefun player to build a town—you might get a town, but there''ll be no residents, just farms and machines! 😂_  
  
**Other Valon Features**   
- 🪵 _Resources_ - Explore custom structures and terrain, mine hidden treasures, and enjoy better chest loot.   
- 🏰 _Towny_ - Claim land and create a community of your own.   
- 🏨 _Apartments (Quarters)_ - Expand Towny to develop your own hotels, apartments, and more.   
- 🌟 _AuraSkills_ - Experience an improved version of McMMO, with abilities, skills, and mana.   
- 💀 _EliteMobs_ - Battle high-level bosses, conquer premium dungeons, discover shrines in the resource world, and win amazing loot, including custom enchanted gear and weapons.  
  
**🔗 Connect Now!**   
Java: [t.valon.gg](http://t.valon.gg)   
Bedrock: [bt.valon.gg](http://bt.valon.gg)  
  
**
✨ What are you waiting for? Jump in and have fun on Valon Towny! ✨
**', 't.valon.gg', 25565, 'mc_java', 'active', true, NULL, 'https://valon.gg', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'astrosmp', 'AstroSmp', 'AstroSMP is een gloednieuwe server met als doel de grootst vriendelijke survival server van Nederland te worden! Samen met onze community doen wij er alles aan om steeds next level te gaan en onze content te blijven verbeteren en regulier updates uit te voeren. Verdien gratis ranks, maak zoveel mogelijk geld, voer leuke opdrachten uit en word de rijkste op de server!  
  
