INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'fnafsisterserver', 'FNaFSisterServer', 'Welcome back to everyone who played on here before! A small part of our community has worked together to create a reboot of the server with all new maps, plugins, and game modes! at the moment the server is still a work in progress and is in its beta stages, but feel free to stop by and maybe find someone you used to play minecraft with after all these years! Good luck and have fun!', 'mc.fnafsisterserver.net:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'pure-vanilla-vanilla-survival', 'Pure Vanilla | Vanilla Survival', '![](https://i.imgur.com/KCx7DCC.png)   
🎉 **PureVanilla is now the first large SMP to support vanilla v26 (tiny takeover!)** 🌱✨ Come check it out!   
  
![](https://i.imgur.com/0MosSVE.png)   
🛡️ **True Vanilla Experience!**   
We have a **0-plugin vanilla gamemode** where you can enjoy Minecraft in all its glory—just as it was meant to be played! 🎮   
✅ No economy   
✅ No teleporting   
✅ No claiming   
✅ No nothing—just pure vanilla!   
  
⚠️ **This is NOT an anarchy server!** We have rules to keep the community fun and fair: **No hacking, no toxicity.** 💖 We’re a **friendly and peaceful** community, with plenty of players who will help you get started! 🤗   
  
💡 We also have a semi-vanilla gamemode with claims if you don’t want your base to be griefed! This gamemode ''chill'' just launched and has a _brand new world_!  
  
![](https://i.imgur.com/X3zn33H.png)   
💰 **The Ultimate Economy Experience!**   
We also have a **separate economy gamemode** featuring a **100% original** economy system **unlike anything you’ve seen before!** 🚀   
  
🏗️ Designed from the ground up to feel like Mojang itself added it to the game!   
🔔 Earn money drops with **satisfying bling bling sounds** 🤑   
🏪 Spend your money at **player-designed shops** (No virtual shopping—everything is in-game!)   
  
This gamemode is **newcomer-friendly** and allows you to:   
✔️ Claim land 🏡   
✔️ Teleport to other players 🌍   
✔️ Easily gather materials ⛏️   
  
![](https://i.imgur.com/Fk2jmQS.png)   
🕰️ **A Server with History & Stability!**   
PureVanilla has been running since **2019** , with **over 150,000 players** having joined us! 🌎✨   
  
🔒 We **never** reset unless the community votes for it (usually every **3-4+ years**), and even then, we **preserve** all world data! 🏛️   
  
💪 To achieve this, we run on **top-tier server infrastructure** , ensuring your creations and memories **stay safe and accessible** for years to come! 🖥️⚡', 'mp.purevanilla.co', 25565, 'mc_java', 'active', true, NULL, 'https://purevanilla.co/discord', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'suurvaal', 'Suurvaal', 'Server ei ole soovitatav neile, kel puudub huumorisoon, maitse, mõttevabadus ja muud head iseloomujooned. Närvilistel inimestel palume hoiduda mängimisest rohkem kui 3 tundi järjest.  
  
  
