INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'indian-mc', 'Indian Mc', 'Join IndianMC - India''s Largest Minecraft Server Network!  
  
IndianMC is one of India''s largest Minecraft server networks, offering a thrilling anarchy-style Crystal PvP experience with a dynamic economy. Our server is packed with enticing features such as Parkour, Practice, and BedWars, providing endless entertainment for all Minecraft enthusiasts.  
  
