INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'boxxynetwork-multiple-modded-minecraft-servers', 'BoxxyNetwork - Multiple Modded Minecraft Servers', '**BoxxyNetwork**  
  
