INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lifesteal-smp-practice-oneblock-bedwars', 'Lifesteal SMP - Practice - Oneblock - BedWars', 'Welcome to Twerion.net – your Minecraft server for all player types!  
Join without a premium account and dive into an epic Minecraft experience. Supports all versions from 1.8 to 1.21.11 and even 26.1.  
  
🔹 Our Game Modes at a Glance:  
  
⚔️ BedWars  
Play action-packed team battles where you must protect your bed and destroy enemy islands. Strategic building meets intense PvP duels.  
  
🚀 FastBuilders  
How fast can you build? This mode demands not only precision but also speed. Perfect for ambitious BedWars players!  
  
⚡ Kitrush  
Pure action with random kits! Every death gives you a new kit – master chaotic fights with constantly changing challenges!  
  
⚔️ Duels  
1v1 or 2v2 – prove your skills in direct combat. Choose from various kits and maps to enjoy fair and exciting PvP duels.  
  
🛡️ Practice  
Perfect your skills in professional training modes:  
  
Classic (1.8): MLG-Rush, BedWars-Practice  
Modern (1.21): MacePvP , CrystalPvP , SwordPvP  
Also choose from NoDebuff, BuildUHC, Sumo, Bow, and more!  
  
🏙️ Citybuild  
Build your own plot – alone or with friends. Economy system, shops, land protection, and many features await you!  
  
🧱 BuildFFA  
Free PvP in a buildable arena. Combine creativity with combat skills – every match is unique!  
  
🧬 Lifesteal SMP  
Gain one heart per kill, lose one per death. In this hardcore survival mode, every decision matters – will you craft or fight?  
  
✈️ ElytraPvP / BOXPVP  
Fight in the air using Elytras and bows. Only those who master aiming, flying, and combat will survive.  
  
🌌 SkyPvP  
Spawn on floating islands, fight for resources, and dominate your enemies. PvP meets vertical maps!  
  
🪨 OneBlock & SkyBlock  
Start on a single block and build your own world from it. Each destruction spawns new blocks, enemies, or surprises.  
  
🌍 Join now for free – whether Premium or Cracked!  
🔗 IP: mp.twerion.net  
📦 Version: 1.8 – 1.21.11 - 26.1  
🏆 Votes, rewards, and events – become part of our active community!', 'mp.twerion.net', 25565, 'mc_java', 'active', true, NULL, 'https://www.twerion.net/', NULL) ON CONFLICT (slug) DO NOTHING;
