INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hydronixmc', 'HydronixMC', 'Welcome to HydronixMC, the ultimate destination for Minecraft players seeking adventure!  
  
Survival Server:  
Step into our survival world and experience the thrill of survival. Build your own base in our custom survival world. In our shop menu, you will find everything you need to make your adventures a little easier. Want to discover new places without having to walk for hours? Use the RandomTP function to be surprised by a new location!  
  
Creative Plot Server:  
Would you rather be free to build without limitations? On our creative plot server, you get your own plot where you can design to your heart''s content. We''ve added some cool custom features, such as sparkling particles and the TrainCarts plugin, with which you can build and bring your own rollercoaster to life. Let your creativity run wild and surprise us with your masterpieces!  
  
Have fun in the lobby!  
In our cosy lobby, we regularly organise fun events to bring the community together. Think quizzes where you can test your knowledge and win fantastic prizes. Keep an eye on our Discord and website so you don''t miss out on any events!  
  
Disneyland Paris Server:  
We''re currently working on something magical: a Disneyland Paris server! Soon, you will be able to virtually explore the world of Disney, visit attractions and experience the iconic atmosphere of the park, all from your own Minecraft client. We are working hard to make this dream a reality soon, so follow us for updates!  
  
Become a team member at HydronixMC!  
Are you passionate about Minecraft? Do you enjoy helping others and creating beautiful builds? Dan zoeken we jou! Whether you''re interested in helping on the survival server, building our future Disneyland Paris world, or working on another project, create a ticket on our Discord server or send us a message.', 'play.hydronixmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://hydronixmc.com/', NULL) ON CONFLICT (slug) DO NOTHING;
