INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'slownerd', 'SlowNerd', 'SlowNerd is an adult community of gamers that want to play in a safe, inclusive, and helping environment working towards a common goal of being an amazing community. We established in 2018 from a group of gamers also looking for adults who share in our passion of gaming, building, inclusiveness, and community and have only grown since that time.   
  
