INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'incremental-paradise', 'Incremental Paradise', 'At Incremental Paradise, players are welcomed into an immersive experience based on exponential progression. Our server introduces many unique features, including custom mining, farming, spear fishing, bug catching, and hunting. Fight unique bosses including a giant flying whale and a queen bee to obtain rare armor, pets, and accessories.  
  
Players will complete a set of tasks to level up. As you level up, you''ll earn skill points to use on unique abilities. These abilities can be used to complete tasks at a faster pace. At level 30, players will have the opportunity to prestige, resetting their progress while gaining a prestige point to use in the prestige shop. Players will then unlock a second, more difficult world. As you prestige, you will be able to complete tasks and prestige faster.  
  
Join our vibrant community in group boss fights, quests, and explore the vast worlds the server has to offer. Level up, prestige, and grow exponentially stronger. We look forward to seeing you!  
  
Discord: https://discord.gg/Sut9G5qYsK', 'incrementalparadise.com', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cheesecake-smp', 'Cheesecake SMP', 'Cheesecake SMP is a cross-play Minecraft server for both Java and Bedrock players, home to a friendly and active community of over 4,000 Discord members. The server offers many unique features such as a reworked fishing system where you can reel in bosses, rare loot, custom enchantments, as well as a mining system that reveals glowing treasure blocks with cool rewards.  
  
We''ve got a balanced economy, player-run shops, land claiming, and a huge variety of enchantments to improve your overall Minecraft experience. Players can compete in many different ways, whether it''s through competing for leaderboard spots, fighting others in PVP, or participating in our PVP, build, hide & seek, parkour, etc events.  
  
Our server stays up-to-date with the latest Minecraft versions whenever possible, bringing fresh content, regular updates, and tons of tweaks to keep gameplay engaging. We also take pride in offering multiple support channels within our Discord server to help you get started. Whether you prefer clicking a few buttons for quick answers or speaking directly with our staff, your questions and concerns will be addressed.  
  
Make sure to join our Discord server at discord.gg/cheesecakesmp and check out or socials @cheesecakesmp.', 'mc.cheesecake.gg', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/cheesecakesmp', NULL) ON CONFLICT (slug) DO NOTHING;
