INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bumblecraft-castaway-1-21', 'BumbleCraft | Castaway [1.21]', 'We''re a group of communities, featuring a network of multiple servers all with unique experiences. Giving our players the best chance to find the gamemode & community they will enjoy the most. Working together to create cross-network events with awesome interactions, welcoming feel & the number one place to make friends online! Striving to be a safe place for young people to grow, learn and have fun! We offer a variety of experiences from Survival, Earth, Lifesteal, Prison & BorderSMP. We offer the ability to play on both bedrock & java with unique texture experiences for both platforms! We look forward to seeing you in-game, join us today!', 'mmp.bumblecraft.net', 25565, 'mc_java', 'active', true, NULL, 'https://bumblecraft.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'n-madas', 'Nómadas', 'En NÓMADAS, creemos en la experiencia original de Minecraft. Nuestro Servidor Survival Semi-Vanilla PvE te ofrece un juego casi puro, sin modificaciones que alteren la jugabílidad esencial. Aquí, la colaboración y la creatividad son las reinas. Ahora en la versión 1.21.11', 'entrar.nomadas.me', 25565, 'mc_java', 'active', true, NULL, 'https://www.nomadas.me', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lifesteal-1-8-1-9-1-19-1-20-1-21', 'Lifesteal 1.8 1.9 1.19 1.20 1.21', '**🔗 IP: mp.heartsmp.net, Bedrock port: 19132** _HIRING STAFF!_  
**🎮 Version:** 1.7 - Latest  
**Welcome to HeartSMP - The Ultimate LifeSteal Adventure!**  
![](https://i.imgur.com/BSiYomb.gif)  
  
❤️ **Game Style:** LifeSteal + Creative  
🔥 **Available for:** Java & Bedrock Players   
💬 **Discord:** <https://discord.com/invite/KSKExKC8>   
🌎 **Map:** <https://map.heartsmp.net/>📜 **Website:** <https://heartsmp.net/>  
📖 **Wiki:** <https://wiki.heartsmp.net/>   

  
  
Lifesteal + Creative  
  
🤔 **What is LifeSteal?**   
In **HeartSMP** , every time you take down another player, you steal one of their **hearts**! But watch out – if you lose all your **hearts** , you’ll be **jailed** at the spawn point for a while. **Fight, raid, trade, and survive**. Every life counts!  
  
💥 **_Exciting Features:_** 💥   
  
⚔️ **PvP & Raiding**   
● **Lifesteal combat** with **anti-combat-log**   
● **Duels** , **Clan Wars** & buildable **Crystal PvP Arena**   
● **sPvP** & **cPvP** support   
● Real **raiding** with **TNT** , **creepers** & **claim fights**   
  
🛡️ **Clans, Lands & Raiding**   
● Build or join a **Clan** , **level up** & **team together**   
● Protect bases with **Lands** , but beware: **no claim is 100% safe**   
● Live **map** with **claims** & **players**   
  
💰 **Economy & Market**   
● **Shops** , **Auction House** & rentable **market stalls**   
● Upgradable **spawners** , **boosters** , **farming** , **coinflips** , **casino** , **sellwands** , **mob cash**   
● **Cheap economy** with surprises for **grinders** & **risk-takers**   
  
🎮 **Duels & Events**   
● **Daily** & **weekly events** : **KOTH** , **KOTL** , **Airdrops** , **Capture Points** , **Gladiator** , **Dragon Fight** , **Map Expansions** , **Giveaways**   
● Regular **Minigames & Events** like **BedWars** , **SkyWars** , **Paintball** , **Spleef** , **Parkour** , **Maze** & 100+ more   
  
🎁 **Rewards & Progression**   
● **BattlePass** with **daily/weekly quests**   
● **Daily rewards** , **playtime streaks** , starter **kits** , **chat games**   
● **Voting keys** , **VoteParties** & **top voter ranks** with bonuses   
● **Clan quests** & **event prizes**   
  
🎀 **Cosmetics & Extras**   
● **Crystals** & **Wraps** to customize your gear   
● Natural **Disasters** , **LuckyBlocks** with 1000+ outcomes   
● **Tags** , **trails** , **disguises** , **seasonal cosmetics** & **AFK rewards**   
  
📚 **Wiki & AI Helper**   
● New here? Use **/ask** anywhere or visit our **Wiki** for instant guidance   
● Learn features as you play, **no need to know everything up front**   
  
✨ **HeartSMP** combines **survival excitement** with **endless adventures**! **Come join the fun!**   
  
🤔 **What is Creative?**   
In **HeartSMP Creative** , you can build without limits. Design **massive landscapes** , create **detailed cities and interiors** , decorate with **advanced tools** , or make your own **playable minigames** in **custom worlds**. No grinding, just **pure creation**.  
  
💥 **_Exciting Features:_** 💥   
  
🌍 **4 Unique Gamemodes**   
● **Plot World** : Claim a safe, flat **80x80 plot** and build with friends   
● **Own Worlds** : Generate a **custom world** to make maps and create minigames   
● **Claim World** : Build on **natural terrain** in the wilderness   
● **Anarchy** : A chaotic zone with destruction, scaled mobs and rideable creatures   
  
🏗️ **World-Class Builder Arsenal**   
● Massive editing with **WorldEdit (FAWE)**   
● Shape mountains and terrain using **VoxelSniper**   
● Paint gradients with **GoPaint** and **GoBrush**   
● Paste **10,000+ community builds** instantly with **BuildPaste**   
  
🎨 **Detailing & Game Design**   
● Decorate with **10,000+ Custom Heads** and detailed **3D Furniture**   
● Display **web pictures** and **animated GIFs** with **Custom Images**   
● Pose **Armor Stands** and generate huge **Player Statues**   
● Build playable minigames with **visual coding blocks** and **AI Generation**   
  
🧰 **Quality of Life & Co-op**   
● Use **Shared Stats** to sync inventories and health for co-  
  
![](https://i.imgur.com/K96gyMz.png)', 'mp.heartsmp.net', 25565, 'mc_java', 'active', true, NULL, 'https://heartsmp.net/?utm_source=Minecraft-Mp.com', NULL) ON CONFLICT (slug) DO NOTHING;
