INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'planetbrunei-reborn', 'PlanetBrunei Reborn', 'Welcome to PlanetBrunei Reborn! Are you tired of the same Minecraft survival servers that don''t add much? Are you a hardcore survivalist who wants to help each other fight against difficult mobs and challenging disasters? You found the right place!  
  
