INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'dincraft', 'Dincraft', 'Dincraft – Serveren som nekter å dø!  
  
Dincraft sine funksjoner:  
  
Et ranking system, basert på serien Vikings der du går fra å være en simpel Kriger, til en stor Legende. Ranking systemet gir deg masse fordeler etter hvert, så du har alltid noe å se frem til. Beste av alt, Ranken din vil aldri forsvinne.  
  
Hard server, tilrettelagt for bygging. På serveren er det PVP i Wild, men du kan claime områdene dine og stenge folk ute. Da har folk mer frihet. Om du vil PVPe eller om du vil Bygge i ditt område.  
  
WIKI, Innpå vår Discord så vil du finne masse Wiki innlegg som forklarer deg masse av funksjonene serveren har. Plugins, Dincraft har masse stilige plugins som utvider spillet. Alt fra teleport blokker til broer som kan stenge og åpne seg.  
  
Bedrock Støtte, På serveren kan du spille med Bedrock Edition! Da kan til og med spille på serveren med mobilen i bussen.  
  
Fly, På serveren så kan du fly med kommandoen /val | Da får du mulighet til å fly med flyspeed 0.4 – Da blir det mye lettere å lage kule bygg, og utforske områder. Men pass på! Om du angriper mobs/spillere, eller mobs/spillere angriper deg så faller du ned som en murstein.  
  
Minigames, om det er over 7 spillere på serveren så kan det dukke opp tilfeldige minigames i chatten. For å joine skriver du bare /revent join i chatten, blir med på minigamet og da spillet er ferdig så kommer du tilbake akkurat der du var før spillet starta.  
  
Om du er en som liker å bygge, eller ser etter en server å spille med venner så er dette serveren for deg.  
  
Historie:  
  
Dincraft har en lang historie. Dincraft starta opp i begynnelsen av 2014 og holdt på til midten av 2016. I midten av 2016 gikk Dincraft sammen med Ragefox for å skape Dinfox. Der samarbeidet serverne til Dincraft splitta fra Ragefox, og åpnet Dincraft igjen en liten periode før serveren ble nedlagt. I November 2018 så åpnet Dalskap Dincraft. Serveren var da åpen nøyaktig ett år før den stengte. Dalskap hjalp da blant annet Hyzt3ria, TrollMorIda, APTminer og GhostSlay3r og lage MidgardMC med Dincraft 2018-2019 som ryggrad. Imens MidgardMC kjørte så lagde Nils_Helge en ny Dincraft som åpnet opp i 2020, å holdt på til starten av 2023 da serveren rebranda til WolfPack. 17. Juni 2023 så åpnet GhostSlay3r Dincraft igjen. Det er den Dincraft som er operativ den dag i dag. Den serveren er bygd fra VikingMC, som er bygd på MidgardMC som er bygd på Dincraft 2018-2019. Full sirkel!', 'mc.dincraft.no', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'blazecraft-si', 'Blazecraft.si', 'SLO Minecraft server: Blazecraft.si  
