INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'servidor-magnatas', 'Servidor Magnatas', 'Servidor Magnatas é o lugar perfeito para quem busca uma experiência única em Minecraft! Com os modpacks ATM10, ATM10TTS e Magnatas Original, você mergulha em um mundo repleto de magia, tecnologia e aventura, explorando dimensões, criando máquinas poderosas e descobrindo segredos místicos. Convide seus amigos para jogar e juntos desbravarem desafios épicos, construir impérios e se tornarem verdadeiros magnatas dentro do jogo.', 'jogar.servidormagnatas.com.br', 25565, 'mc_java', 'active', true, NULL, 'https://servidormagnatas.com.br', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'landgames-ro-quality-quantity', '☁️ LandGames.ro | Quality > Quantity 🌸', '**Probabil te gandesti, de ce ai intra pe LandGames?**
  
Nu este acesta un server la fel ca celelalte?   
  

**Iti raspundem noi:**
  
Nu este un server precum celalalte, incat toate sectiunile noastre sunt unice.   
  
**Iesim la suprafata** prin functii unice pe comunitatea de Minecraft din Romania:   
• un **Survival hardcore** ca gameplay,   
• **SkyBlock Hard** unde nu exista economie — te bazezi doar pe grass block si poti face trade cu ele,   
• **Empires** , o sectiune noua si unica unde ai ca scop imperii pe harta lumii,   
• si intr-un final **Minigames** unde regasesti jocuri precum **Splegg, TnT Run, TnT Tag, Block Party** etc...   
  
**Suntem diferiti** de serverele copy-cat unde isi promoveaza serverul pe retelele sociale.   
Noi ne facem jucatori si ii pastram stiind ca le plac unicitatea.   
  

Deci, daca te-ai intrebat vreodata care este diferenta intre LandGames si celelalte,
  

raspunsul ar fi motto-ul nostru:
  

**Quality > Quantity**
  
  

Va asteptam sa descoperiti mai multe despre noi pe **<https://landgames.ro>**
  
  

**_Serverul este cross-play: Java & Bedrock_**
  

_Totusi recomandam folosirea Java pentru a va conecta_
  
  
![](https://i.imgur.com/CcD3CoG.png)', 'play.landgames.ro', 25565, 'mc_java', 'active', true, NULL, 'https://www.landgames.ro', NULL) ON CONFLICT (slug) DO NOTHING;
