INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'shadowblade', 'ShadowBlade', 'ShadowBlade is an economy-based co-op survival server that was established in 2011. This server is full of both the new and the old. Surrounded by the ShadowBlade Gaming Community, we have been able to keep this gem running for over 10 years.  
  
Along with survival, there are also WEEKLY EVENTS and opportunities for players to collect rare, assorted items. We are currently working on a Museum on the History of ShadowBlade due to finding evidence of being up since pre-2011! Come make history with us and write your own story.  
  
But wait… there’s more! ShadowBlade also offers 20 Ranks which you can get with in-game currency! This means you can eventually use /fly and silk touch spawners without having to pay real-life money for it!  
  
Shadowblade is 100% EULA compliant and non-pay-to-win!  
Even though we do have Buycraft...every Rank, command, and item can be earned in-game. All money earned through Buycraft is put back into server upkeep and future plugins.  
  
Join us on Minecraft shadowblademc.com or on Discord https://discord.gg/3BRue3gEqV  
  
Plugins  
-----------------  
MCMMO  
Jobs Reborn  
Genesis Shop   
Chest Shops  
Advanced Enchants  
Pyro Fishing  
Ranks  
Cosmetics  
Silk Spawners  
Slimefun  
& More!', 'shadowblademc.com', 25565, 'mc_java', 'active', true, NULL, 'https://sbmc.info/', NULL) ON CONFLICT (slug) DO NOTHING;
