INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'pinoycraft', 'PinoyCraft', 'Welcome to PinoyCraft - Your Ultimate Minecraft Adventure!  
  
Embark on an extraordinary journey in the immersive world of PinoyCraft, where creativity meets excitement! Our server is designed to deliver a unique and enriching Minecraft experience, filled with custom features that set us apart. Here''s a glimpse into what awaits you:  
  
Custom Enchantments:  
Unleash the power of enchantments like never before! Dive into a realm of exclusive, custom-crafted enchantments that add depth and strategy to your gameplay. Whether you''re a seasoned warrior or a master builder, PinoyCraft''s enchantments will elevate your skills and make your adventures truly legendary.  
  
Dynamic Jobs System:  
Forge your path in the PinoyCraft economy by choosing from a variety of dynamic jobs! Whether you''re mining, farming, or exploring, our job system rewards your efforts with in-game currency, creating a vibrant and player-driven economy. Rise through the ranks, accumulate wealth, and become a force to be reckoned with!  
  
Player-Centric Economy:  
Experience a thriving in-game economy where your actions directly impact the world around you. Buy, sell, and trade resources with fellow players to build your empire. Invest in businesses, create markets, and shape the economic landscape of PinoyCraft. The possibilities are endless!  
  
Friendly Community:  
At PinoyCraft, we believe in fostering a welcoming and inclusive community. Join forces with like-minded players, form alliances, and embark on epic quests together. Our dedicated staff ensures a safe and enjoyable environment for everyone.  
  
Weekly Events and Challenges:  
Stay engaged with our server through weekly events and challenges! Test your skills, compete with friends, and earn exclusive rewards. From epic PvP battles to creative building contests, PinoyCraft constantly provides new ways to keep the excitement alive.  
  
Are you ready to immerse yourself in the magic of PinoyCraft? Join us now and experience Minecraft like never before! The adventure awaits, and so does your destiny. PinoyCraft - Where Legends Rise!', 'play.pinoy-craft.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.pinoy-craft.com', NULL) ON CONFLICT (slug) DO NOTHING;
