INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'dunesmp', 'DuneSMP', 'Join our Discord community at discord.dunesmp.com and become a part of the DuneSMP family. We''re not just a server; we''re a place where you can make new friends, create your very own warps, find your dream job, build your wealth, unwind, and simply have a blast! We''d love for you to be one of our original pioneers and experience the magic from the very beginning.  
