INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mc-soulcraft-tc-minecraft-servers-in-turkey', 'MC.SOULCRAFT.TC Minecraft Servers In Turkey', 'SoulCraft 2014 yılında temelleri atılmış ve bir yıllık özlemin ardından 2021''de tekrar sevenleriyle kavuşmuştur. 2014 yılından süregelen bir birliktelik ve çalışma ortamına sahip olan yönetim ekibimiz yedi yılı aşkın bir süredir sizlerin çoklu oyunculu minecraft oynama arzunuzu gerçekleştiriyor.  
  
