INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ecomc-towny-server', 'EcoMC Towny Server', 'Now in open public Beta release!  
After nearly 8 years, EcoMC is back and better than ever with a newly calibrated economy and all of the old favorite activities with some new options to spice up your gameplay!  
  
EcoCases A CS:GO inspired case-opening system featuring 7 different cases each containing a themed set of items.  
McMMO An attribute progression system to enhance gameplay while offering perks as you level-up.  
Towny A plugin that allows players to create and manage towns, residents, and nations.  
Jobs A plugin which allows you to pick a profession to earn money by performing activities associated with the picked profession.  
Custom world generation focusing on more balanced ore generation.  
Exp Bottling plugin to allow bottling exp for later use. Either store all of your exp into a custom bottle item, or convert into bottles o'' enchanting.  
SilkSpawners plugin to allow the mining of spawners. Be sure to have silk touch!  
Our custom dynamic price admin shop plugin which has dynamic supply/demand price updating  
Our custom QOL Pickup Filter plugin which allows you to whitelist and black what ground items you pickup  
Our custom Player Warps plugin which allows you to create your own warps  
Our custom Donor rank system which revolves around an in game donor currency called EcoCredits which are attainable even if you never donate a dime  
Our custom Scrolls plugin which allows you to craft 1 time use "scrolls" which have different one-time use features  
  
And much much more...  
EcoMC offers a unique towny survival experience that you will find on no other server driven by our numerous custom plugins as well as some of the best public plugins. We strive to create toxicity free environment where our well trained staff team and mature community will have you feeling right at home. So what are you waiting for? Come check it out today at Play.EcoMC.us', 'play.ecomc.us:25565', 25565, 'mc_java', 'active', true, NULL, 'http://www.ecomc.us', NULL) ON CONFLICT (slug) DO NOTHING;
