INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'us-playcdu-fantasy-mc-fabric', '[US] PlayCDU | Fantasy MC Fabric', '![](https://cdn.playcdu.co/Banner.gif)  
  

**WE HAVE NO HUB, CONNECT TO THE IPs FOUND ON OUR SERVER LIST:<https://www.craftdownunder.co/server-list>**
  
  
**Our Links:**   
