INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'zuminel', 'ZUMINEL', 'ZUMINEL terbuka untuk umum ini menjadi rumah bagi para penggemar Minecraft dari berbagai platform. Di sini, pemain dapat merasakan petualangan tak terbatas dalam mode survival yang penuh tantangan dan kegembiraan. Server ini tidak hanya dapat diakses melalui PC, tetapi juga melalui perangkat mobile, memungkinkan pengalaman bermain yang seru bagi semua orang.  
  
Server ini menawarkan berbagai fitur menarik yang membuat setiap sesi bermain menjadi pengalaman yang unik dan tak terlupakan. Salah satu fitur yang paling menonjol adalah keberadaan komunitas yang ramah dan bersemangat, siap untuk menjelajahi dunia bersama dan saling berinteraksi. Pemain dapat bergabung dengan teman-teman lama atau bahkan membuat pertemanan baru.  
  
Di dalam server ini, tersedia beragam tantangan dan aktivitas untuk dinikmati. Mulai dari membangun rumah impian, menjelajahi gua-gua yang misterius, hingga bertarung dengan bos-bos yang menantang. Selain itu, terdapat pula event-event menarik yang diselenggarakan secara berkala, seperti perlombaan memancing, pertarungan PvP, dan banyak lagi.  
  
Salah satu hal yang membuat server ini menjadi favorit adalah sistem ekonomi yang dinamis. Pemain dapat mengumpulkan uang dalam permainan dengan berbagai cara, seperti menjual barang-barang yang mereka kumpulkan atau memenangkan perlombaan. Uang ini dapat digunakan untuk berbagai keperluan, mulai dari membeli barang-barang langka hingga membangun infrastruktur yang megah.  
  
Dengan kombinasi antara fitur menarik, komunitas yang ramah, dan sistem ekonomi yang dinamis.', 'mc.zuminel.id:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'siyntra-studios-pixelmon', 'Siyntra Studios Pixelmon!', 'Welcome to Siyntra''s Pixelmon!  
  
