INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'kaminaricraft', 'KaminariCraft', 'Experience the magic of KaminariCraft, where innovation meets adventure in the world of Minecraft. Our server offers a seamless and immersive experience for both Java and Bedrock players, ensuring everyone can enjoy the wonders of our custom-crafted world.  
  
Key Features:  
  
Custom Terrain Generation:  
  
Embark on epic journeys through breathtaking, hand-crafted landscapes. Our advanced terrain generation creates diverse biomes, from enchanted forests and majestic mountains to expansive deserts and hidden caves, each filled with unique secrets and challenges.  
  
Unified Java and Bedrock Support:  
  
Connect and play with friends across platforms. Whether you’re on Java or Bedrock, KaminariCraft provides a seamless gaming experience, bringing everyone together in one dynamic world.  
  
Smooth 20 TPS, Zero Lag:  
  
Enjoy a flawless gaming experience with our optimized server performance. KaminariCraft maintains a steady 20 ticks per second (TPS), ensuring zero lag and smooth gameplay, even in the most intense situations.  
  
Dynamic Animations:  
  
Immerse yourself in a visually stunning environment with custom animations that bring every aspect of the server to life. From fluid character movements to animated landscapes, our world feels vibrant and alive.  
  
Custom Shop System:  
  
Dive into our unique economy with a fully custom shop system. Buy, sell, and trade exclusive items and resources to enhance your gameplay. Our intuitive shops make managing your inventory and finances a breeze.  
  
Innovative Custom GUIs:  
  
Navigate our server effortlessly with beautifully designed custom graphical user interfaces. From inventory management to trading, our GUIs are user-friendly and visually appealing, enhancing your overall experience.  
  
Play-Time Ranks:  
  
Progress through 16 exciting play-time ranks. Earn rewards and unlock new abilities simply by playing. Every moment spent in KaminariCraft brings you closer to the next rank, adding an extra layer of motivation and achievement to your journey.  
  
Join Our Community:  
  
Java: play.kaminaricraft.com  
  
Bedrock: pe.kaminaricraft.com  
  
Version: latest  
  
At KaminariCraft, we are committed to providing an unparalleled Minecraft experience. Our server combines cutting-edge features, stunning visuals, and a vibrant community to create the perfect environment for adventure and creativity.  
Join us today and discover why KaminariCraft is the ultimate destination for Minecraft enthusiasts!', 'play.kaminaricraft.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.kaminaricraft.com', NULL) ON CONFLICT (slug) DO NOTHING;
