INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'reveriecraft', 'ReverieCraft', 'ReverieCraft is a towny based server with multiple worlds, mini games, an economy, and expanded Minecraft content. The server has MMO elements that allow for different playstyles to shine in unique ways. The Agate world is a survival world based on building for creative players, while the Opal world which is reset every week with a different theme is for resource gathering and adventuring. The server has somewhere near over 500+ custom items with custom enchantments, over 200+ different enemy variants, and tons of tough bosses spanning over several worlds with quests! With lootcrates, shops, quests, and present codes, this server is not pay to win but rewards dedication and skill as you and your friends can tackle different challenges and obstacles or just chill and relax as you build your very own towns with towny!', '172.240.87.54:48072', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'swiftsmp', 'SwiftSMP', 'SwiftSMP is a dedicated Crystal PvP server designed to provide an optimal gaming experience for players across Asia. Our server is strategically hosted in Singapore, allowing us to offer exceptionally low ping and ensuring minimal latency. This ensures that players from all over Asia can engage in fast-paced, competitive gameplay without experiencing any lag or connectivity issues.  
  
At SwiftSMP, we understand the importance of a smooth and responsive gaming environment, especially in PvP scenarios where every millisecond counts. Our state-of-the-art server infrastructure is tailored to meet the demands of high-speed combat, allowing you to fully immerse yourself in the game and perform at your best.  
  
Whether you''re a seasoned PvP veteran or a newcomer looking to hone your skills, SwiftSMP provides the ideal platform for all players seeking intense and thrilling Crystal PvP action. Join our community and experience the difference that a truly dedicated server can make in your gaming journey.  
  
discord.gg/swiftsmp', 'swiftsmp.net', 25565, 'mc_java', 'active', true, NULL, 'http://swiftsmp.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'greeceearthmc', 'GreeceEarthMC', 'Live Your Greatest Adventure in Greece!  
_Macedon was a nation of vision and ambition, but all great stories have twists._  
Due to unforeseen circumstances, Macedon’s leadership has transitioned, and we are now collaborating with **Greece** —our closest ally and friend.  
**Join us in Greece, where the spirit of Macedon lives on and new opportunities await you!**  
  
What Happened?  
Macedon’s journey took an unexpected turn when one of its leaders, **Gris** , faced a ban for violating server rules.  
As a result, the nation was reassigned by EarthMC staff to new players.  
_However, Macedon’s legacy continues in Greece,_ where we are welcoming all former Macedon citizens and those seeking a vibrant community.  
  
A Few of Greece’s Features:  
**Nation Building & Towny:** Claim land, build cities, and expand your influence in the EarthMC world.  
**Community Engagement:** Participate in public opinion polls, tier lists, and educational Minecraft content.  
**Competitive Gaming:** Practice and compete in games like Bedwars, with opportunities to join our official teams.  
**Factions & Leadership:** Join or create factions, companies, or neighborhoods, and rise to leadership.  
**Family-Friendly Atmosphere:** Enjoy a safe and welcoming environment for all ages.  
**Custom Minigames:** Design and play unique minigames with inspiration from our past successes.  
**McMMO Training:** Hone your skills and become a master in your field of work.  
  
Join Us Today!  
**Greece is ready to welcome you with open arms,** offering a supportive community and countless ways to grow.  
Our Discord server is the hub for everything you need: citizen registration, community events, and access to exciting features.  
  
➡️ **Join the Greece Discord here:** <https://discord.gg/CzEy78HypA>  
  
_Introduce yourself, fill out forms, and start your new adventure with us. Don’t be afraid to take that first step—practice builds confidence, and Greece is here to guide you every step of the way._', 'org.earthmc.net', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/CzEy78HypA', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ger-de-black-sirius-minecraft-server', '[GER/DE] Black Sirius Minecraft Server', '**Willkommen Minecraft Server des BSS!**  
  
