INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'leftypvp', 'LeftyPvP', 'LeftyPvP is a premier cracked Minecraft Skyblock server featuring custom dungeons, advanced skills systems, and stunning custom textures since 2019. Originally founded as LeftyMC by LeftCross, this free Minecraft server offers exceptional Skyblock experiences with challenging dungeon raids, RPG-style progression, unique visual enhancements through custom textures, and innovative features without requiring a premium account. Join thousands of players on our stable cracked server for endless adventure, community events, and top-tier Minecraft Skyblock gameplay enhanced by beautiful custom textures that''s kept players engaged for over 5 years - experience why LeftyPvP is the ultimate destination for free Minecraft server enthusiasts seeking quality Skyblock content, dungeon exploration, and skill mastery with enhanced visuals.', 'play.leftypvp.net', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
