INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'meridian', 'Meridian', '**Welcome to Meridian!**
  
  
Meridian is a thriving community dedicated to crafting exceptional Minecraft servers.  
  
We currently operate three distinct servers, each designed to provide unique experiences for our players:  
  
