INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cyan-realms', 'Cyan Realms', 'Embark on a journey through a vast, procedurally generated world where you can level up a wide array of skills and stats to create a highly personalized gaming experience. Encounter unique bosses within dynamic structures and dungeons, exploring new biomes along the way. Customize your arsenal with enchanted tools and weapons, crafting setups that are uniquely yours. Engage in innovative fishing, farming, and mining activities, enhancing your daily routines with advanced Pyro features. Collect rare pets, undertake quests, delve into mysterious dungeons, and refine your gear through the Reforge system, all contributing to a rich, immersive adventure unlike any other.  
  
