INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'smithcraft', 'SmithCraft', '🌐 IP: play.smithcraft.cc  
📣 Discord: https://discord.gg/5D7V8AA7ms  
  
Welcome to SmithCraft – A Sophisticated Survival Minecraft Experience  
  
  
SmithCraft is a survival Minecraft server that sits somewhere between the gameplay styles of Towny and Factions.  
  
  
Like Towny, you can:  
  
Claim and manage land  
Create towns and nations  
Set taxes  
Divide your land into plots and zones  
  
But unlike most Towny servers where griefing and conflict are disabled, wars and political conflict are a real part of the SmithCraft experience.  
  
  
At the same time, SmithCraft is not a Factions-style raiding server.  
  
Raiding and constant warfare are not the goal of the game.  
  
  
Instead, the goal is to build prosperous lands, grow your influence, and participate in a player-driven economy.  
  
A Real Economy  
  
  
SmithCraft avoids “magical” money systems.  
  
There are no jobs plugins printing money out of thin air  
Money exists as physical currency items  
Wealth is created through production, trade, and cooperation  
  
  
If you want to pay another player, you must actually give them the money.  
  
  
SmithCraft creates a world that is:  
  
Welcoming but unforgiving  
Peaceful at times, dangerous at others  
Driven by players, not automated systems  
  
Build a town.  
  
Form a nation.  
  
Trade with your neighbours.  
  
Or fight them.', 'play.smithcraft.cc', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
