INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'manacity-de-citybuild-java-bedrock-1-20-x', 'ManaCity.de | Citybuild | Java & Bedrock | 1.20.x', 'Willkommen bei ManaCity - einem 1.20.4 Citybuild Server für Java & für Bedrock Spieler!  
  
