INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bizzcraft-freebuild-survival', 'BizzCraft Freebuild Survival', 'BizzCraft is a calm, anti-grief, economy, SMP server where we value community above all else. We allow light swearing, but we have a Zero-Tolerance Policy for harassment and disrespect (for more details, please review our Rules page). The server is running 1.21+, and everyone is welcome as both Java and Bedrock players are free to join! We strive to have a Semi-Competitive Environment which is achieved by allowing PVP, which you are able to toggle on and off, and a competitive /baltop. We also highly encourage player shops, and towns using TownyAdvanced.   
  
