INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'meliosmp-whitelisted-community-survival', 'MelioSMP: whitelisted – community – survival', 'We are Melio, a whitelisted survival server on Java Edition with no land-claiming or chest locks. We''ve been building this community for folks who joined in search of a **mature, drama-free, and inclusive server**. If that''s your thing, Melio can be where you end your search.  
  
**WE:**  
- use a whitelist system to weed out the bad apples.  
- avoid features like warps, McMMO, teleporting, money plugins, etc.  
- operate on a trust-based system. No chest locks or land-claiming!  
- like keeping it simple. Our rules list is very short, but we enforce them strictly to maintain "no grief & no theft"!  
- run on a Fabric server located in Europe.  
  
**FEATURES:**  
- Districts: special-themed districts for everyone to build in; featuring marked banners on our world map website!  
- VanillaTweaks (recipes): minor additions & changes to recipes  
- Ledger: logs everyone''s actions, to catch griefers and thieves  
- Simple Voice Chat (optional): for in-game proximity voice chat  
- Resource Worlds: we''re hoping to run for the long term; this will fix issues with non-renewables in a finite world.  
  
Whether you''re a builder, a technical player, an explorer, or everything in between, you are welcome here. We welcome players from all origins and all backgrounds, aiming to be an inclusive safe-space as best as we can be.  
  
**INTERESTED?**  
Apply through our Discord: <https://discord.gg/z9ezzKBR6t>  
Filling the application form takes 5-10 minutes, and will be reviewed within the same day.  
Also check out our website & handbook: <https://meliosmp.com>', '127.0.0.1', 25565, 'mc_java', 'active', true, NULL, 'http://www.meliosmp.com', NULL) ON CONFLICT (slug) DO NOTHING;
