INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'dinoworld', 'DinoWorld', '_**About This Server**_  
Welcome to DinoWorld! We are offering ultimate experience with Dinosaurs and Towny pvp, with some RPG elements such as gaining Technologies or just simply taming dinosaurs which you can upgrade as well .   
  
DinoWorld: (Latest Version : Adds over 120 Dinosaurs,hundreds of custom recipes to Minecraft) This version of DinoWorld runs on Minecraft 1.20.x to be able join our DinoWorld server you just need to enable resource pack .  
Please check our discord for all recipes and guides .  
  
Server IP: **mc.elitegamesmc.com**  
Discord: **https://discord.gg/E443thHMhz**  
  
What is the server IP for DinoWorld?  
The IP address of DinoWorld Minecraft server is mc.elitegamesmc.com  
_**How do I play on the DinoWorld Minecraft server?**_  
  
Open the Minecraft launcher, next click the "Play" button, then select "Multiplayer" from the main menu.  
Click the "Add Server" button to open the server information form then copy & paste the IP Address mc.elitegamesmc.com in the "Server Address" box then press click on "Done" button and set the resource pack as Enabled .  
Once the connection to the server is verified by Mojang session servers and is available, the connection icon will turn green and you can click on the "Join Server" button to play on DinoWorld.  
  
_**What Minecraft game version does DinoWorld server support?**_  
DinoWorld supports Minecraft version: 1.20.x.  
  
Keep in mind that many Minecraft servers might allow players to use older or newer versions, so we invite you to check on their Discord server or Website for more information on version compatibility.  
  
_**Where is the DinoWorld Minecraft Server being hosted?**_  
The DinoWorld server is currently hosted in Germany with an uptime of 100%.  
  
_**What are the features you can expect on the DinoWorld Minecraft Server?**_  
You can Expect: Towny, Dinosaurs, Ranged weapons (bows,balistic range weapons) , Bosses, TechTree, Ships, Siege Weapons, Furniture and Many Events on the DinoWorld server.', 'mc.elitegamesmc.com', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'coldgames-latest-java-bedrock-lifesteal-smp-randomki', 'ColdGames - LATEST - Java/Bedrock - Lifesteal/SMP/RandomKi', 'We are a new network based on a pvp network which existed for 8 years, we create unique experiences of the most popular gamemodes. All our servers supported the latest version of minecraft java & bedrock!', 'coldgames.fun', 25565, 'mc_java', 'active', true, NULL, 'https://coldgames.fun', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'flancraft-survival', 'FlanCraft Survival', 'Si te encuentras buscando una experiencia diferente al momento de jugar Minecraft, entonces necesitas entrar a FlanCraft !  
  
🔸 Survival Custom 1.21.11 (1.16.x - 1.21.11)  
  
¡Muchas novedades y características!  
Por lo demás, FlanCraft Survival es considerado uno de los mejores servidores de Minecraft no premium, pues garantizamos lo siguiente:  
  
✔ Buena conexión para América del Sur y Europa.  
✔ Actualizaciones diarias de todo.  
✔ Rangos extremadamente baratos.  
✔ Excelente rendimiento y sin lag.  
✔ Staff activo, maduro y en constante crecimiento.  
Además, según la modalidad en la que juegues, al votar puedes recibir rango gratis.  
  
¿Preparado para vivir una experiencia nueva?  
