INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minehive', 'MineHive', '"MineHive is a vibrant and welcoming Minecraft community offering a wide range of diverse and thrilling game modes tailored to every type of player. Whether you’re into survival adventures, creative building, or competitive challenges, Realms provides an engaging and exciting experience for everyone. Join us now to explore worlds filled with challenges, participate in exclusive events, and be part of a growing community. Experience the fun of playing with new friends and showcase your skills across unique game modes that you won’t find anywhere else but Realms!"', 'minehive.id', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/minehive', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'quilt-anarchy', 'Quilt Anarchy', 'QuiltAnarchy, vanilla hayatta kalma oyun modunda çok az değişiklik yaparak, herkes için kuralsız bir PvP ortamında dünyayı asla sıfırlamamayı amaçlayan bir Minecraft sunucusudur. QuiltAnarchy, Türkiye’deki en eski anarşi sunucularından birisi olup, köklerini Ocak 2021''de açılan Cobblestone Anarşi sunucusundan almaktadır.  
  
Sunucumuzun Özellikleri:​  
Hiçbir Kural Yok: Sunucuda hiçbir kural yok. (Hile açmak* vs. dahil.)  
Eski Klasik Minecraft Tadı: Eski Minecraft hayatta kalmalarının tadında.  
Kimse Banlanmıyor: Sunucuda kural olmadığı için kimse banlanmıyor. Ne yaparsan yap.  
Dünya Hiç Resetlenmiyor: Dünya, dün ya da geçen sene farketmez, sonsuza kadar nasıl bıraktıysan aynı kalıyor.  
Gerçek Hayat Gibi: Faction serverlarındaki gereksiz ve fazla kolay komutlara bağlı kalmadan evini kendin yap, kendin savun. İyi korumazsan yağmalanıp talan edilir, korursan sonsuza kadar ayakta kalır.  
DÜRÜST Bir Ortam: Cafcaflı komutlar yok! Kazanmak ya da rütbe için para vermek yok! Rütbeyi insanlar arasında iyi tanınarak kendin kazan!  
Yapaylık YOK: Hiçbir şey komutlara bağlı değil! Bir şey istiyorsan gidip kendin yapacaksın! Savaş mı istiyorsun? Arkadaşlarını topla, ve düşmanlarını ez!  
Olasılıklar Sınırsız: Sonuçta burası Minecraft. Tek sınır yaratıcılığın. Yeterince insan toplayıp kendine ülke bile kurabilirsin. Her şey sana bağlı!  
QuiltAnarchy’ye Katılın:​  
İkna olduysan ve hemen katılmak istiyorsan: IP Adresi: quiltanarchy.freeddns.org (Domain sunucu betadan çıkınca bağlanılacak)  
  
Kapasite: 75 oyuncu', 'mc.quiltanarchy.xyz:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
