INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'kobbledkarp-cobblemon-1-7-3-fabric', 'KobbledKarp Cobblemon 1.7.3 (Fabric)', 'Discover all the exciting new features we’ve added to enhance your gaming experience:  
  
WonderTrade 🎉: Dive into thrilling trades with players globally! Experience the excitement of exchanging Pokémon for free with our WonderTrade system.  
  
New Biomes 🌋✨: Explore fresh biomes in the Nether and End, all seamlessly integrated with Terralith in the Overworld. Uncover new terrains and unique resources!  
  
Gyms 🏋️‍♂️: Test your skills in our newly introduced Gyms. Earn money, ranks, and exclusive kits as rewards for your victories!  
  
Purchasable Enhancements 💎: Elevate your gameplay with purchasable commands, tokens, and claim blocks. These items enhance your Free-to-Play experience!  
  
Pokédex Milestones 📚🎁: Complete your Pokédex and unlock rewards for reaching milestones. Track your progress and enjoy exclusive benefits!  
  
Vote Rewards and Parties 🗳️🎊: Support us by voting and join Vote Parties for exciting rewards and community events!  
  
Wild Pokémon Size Variation 🐾📏: Discover Pokémon of various sizes in the wild. Find rare and unique variants to expand your collection!  
  
Boss Pokémon 🏆💥: Face off against powerful Boss Pokémon that drop valuable items, including Megastones, to strengthen your team.  
  
Pokémon-Themed Structures 🏠🧩: Explore unique Pokémon-themed structures across the world. Find hidden treasures and special features!  
  
PokéBuilder 🛠️: Customize and perfect your Pokémon with our advanced PokéBuilder. Earn it through Vote Keys, by defeating Bosses, or purchase it with in-game currency!  
Join the discord - https://discord.gg/qSUDeYyVpM', 'play.kobbledkarp.com', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mysticraft', 'MystiCraft', 'Introducing MystiCraft, A cracked and free to play minecraft network which supports both Java & Bedrock with version support from 1.16 to the latest. We have three main gamemodes currently, Lifesteal, Vanilla & FFA. We hope to see you on the server!', 'play.mysticraft.xyz:25565', 25565, 'mc_java', 'active', true, NULL, 'https://mysticraft.xyz', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hyperion', 'Hyperion', 'Welcome to Hyperion!  
  
JUST LAUNCHED PRISON SEASON 10! COMPLETELY REBALANCED! PRIVATE MINES! CUSTOM FISHING! Hyperion is an OP Prison server with unlimited prestige’s and 25+ COOL OP Pickaxe upgrades. Every player gets their own private mine and the mine size is upgradable through mine tickets found in crates. Crates give OP rewards like: mine bombs, multiplier armor, robots, pouches, drills, pickaxe levels, keys, and so much more! Store all your loot and build cool builds with shop on your plots. There are leaderboards for pretty much everything. Also, there are a few types of in game stores. There is player rewards system to buy premium items in a shop using gems. Then, a micro transaction store using meteorites. Everything can be obtained by playing the game. This is not a pay to win server.   
  
In Hyperion, we have a custom plugin that handles payouts for every day, week, month, and season. After the event ends, it will automatically reward the winners when they log into the server. You must join each event manually with the command /e. The only event that automatically joins you is the season payouts. The season payouts gives you meteorites, which if you remember is, for the micro transaction store. Something to note is the only currency that transfers to the new season is meteorites, so save those meteorites for the new season!  
  
Lastly, there’s so much more to do than just mining. If you want to switch it up, you can go fishing or PvP to be the top player. With fishing, we have a custom fishing plugin with a bunch of activities to complete. At the end of the spawn area there is an ocean where players can fish and level up their fishing skills. You can make deliveries to receive special items. You can also sell fish, gut fish for entropy, and so much more. There are also custom enchants just for the fishing rod, which are called augments.  
  
In the Warzone, keep inventory is off, there is scheduled KOTH’s, and Envoy’s. They each have pretty OP Rewards. For KOTH’s if you win one, there is a crate key you will receive, that you can open at the warzone spawn, and in that crates has a bunch of cool items and op weapons and armor. There are also mineable blocks in the Warzone. Mine any of the visible magma blocks to receive a varying chances of extra cash, coins, and XP. You can also have a very small chance of receiving some meteorites. The magma block regenerate after a certain amount of time. There are also cow spawners in the Warzone to farm more XP and get some food.  
  
EXP is used to enchant weapons and armor with custom enchants. Use /ce to open the menu to purchase 50+ custom enchants using levels. White scroll is to protect the item from being destroyed by the enchant. Black scroll is to remove a random enchant. The success dust is to increase the chance of it enchanting the item. The destroy dust is to decrease the chance of it destroying the item. Use custom enchants to dominate and become the top player in the Warzone. There is a PvP tier system in place as well.', 'play.astrocraft.org', 25565, 'mc_java', 'active', true, NULL, 'https://www.astrocraft.org', NULL) ON CONFLICT (slug) DO NOTHING;
