INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'ironclad-lifesteal-factions', 'Ironclad - Lifesteal Factions', 'Ironclad Lifesteal Factions - Java + Bedrock - McMMO  
  
  
🚨 Brand New World as of 8/22/24 🚨  
  
🌐 Bedrock Supported! Port: 25555  
  
💬 Join our community on Discord: Ironclad Network  
  
  
  
Welcome to Ironclad Factions!  
  
Step into the ultimate Lifesteal Faction server, where every decision counts, and every battle could be your last. With a dynamic blend of Lifesteal mechanics and intense faction warfare, Ironclad Factions promises an action-packed Minecraft experience that will test your strategy and survival skills.  
  
  
  
🔥 What Sets Us Apart:  
  
  
Lifesteal Mechanics: Lose a heart for every defeat and gain one for every victory. But be careful—if you lose all your hearts, you''ll face a 8-hour ban. It''s high-stakes survival at its finest!  
  
  
Faction Warfare: Utilize all default faction commands to claim territory, form powerful alliances, and wage war against rivals. Dominate the battlefield and build your legacy.  
  
  
Open-World PVP: The world is your arena. Build, fight, and conquer in a relentless battle for supremacy.  
  
  
Quick Sell with /sellhand: Manage your resources efficiently with our /sellhand command. Integrated with our comprehensive /shop, trading and item management have never been easier.  
  
  
McMMO: Level up your skills with McMMO and unlock powerful perks that enhance your abilities. Whether you''re mining, fishing, or fighting, there''s always something new to achieve.  
  
  
Auction House: Buy, sell, and bid on rare items with other players in the Auction House. Find that elusive treasure or turn your loot into profit. /ah  
  
  
  
🛡️ Server Rules:  
  
  
No Hacking/Xray: Fair play is essential. Cheats and hacks, including Xray mods, are strictly forbidden.  
  
  
No Duping: Play fair—duplicating items is against the rules.  
  
  
No Homophobic/Racist Language: Respect is key. We enforce a zero-tolerance policy for hate speech.  
  
  
No Exploits: Glitches and exploits are not allowed—play the game as it was meant to be played.  
  
  
No Advertising: Keep the focus on the game—advertising other servers or external links is not allowed.  
  
  
Respect Staff: Our staff work hard to keep the server running smoothly. Follow their guidance to ensure a great experience for everyone.  
  
  
  
Ready to conquer, build, and dominate?  
  
Join Ironclad Factions today and embark on your next epic Minecraft adventure. Whether you''re a master strategist or a fearless warrior, your journey begins here.', 'pvp.ironcladnetwork.us:25555', 25565, 'mc_java', 'active', true, NULL, 'https://www.ironcladnetwork.us', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'circus-craft', 'Circus Craft', 'Launched in June 2024, we’re a small but growing circus-themed Minecraft server full of fun, adventure, and creativity. We''re proudly non-pay-to-win. Every crate, even seasonal ones, can be opened for free with in-game keys that are not impossible to obtain!  
  
