Latest version. Fully optimized. Ready to play.  
  
  
📥 How To Join  
Download this modpack  
  
Open Minecraft  
  
Click Multiplayer  
  
Join: mc.poke-legends.com  
  
Then hop in Discord and introduce yourself.  
  
Join Our Discord to Become a Member of Our Community! (Check the Right Side)', 'mc.poke-legends.com', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/sy8azkdWYj', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bluecraft', 'BlueCraft', 'BlueCraft is a medieval fantasy–themed, season-based Minecraft Survival server featuring full cross-play support for both Java and Bedrock players. The server offers a mostly-vanilla experience enhanced with pets, craftable furniture, and multiple unique worlds to explore.  
  
Enjoy a wide range of features, including an economy system, PvP, quests, minigames, vote rewards, and custom items. BlueCraft SMP also supports offline-mode (cracked) players, making it accessible to everyone!  
  
It’s a friendly community where players from any platform can easily join using the same IP and port.  
  
Join our adventure today and become part of the BlueCraft world!  
Discord: https://www.discord.gg/XezR6tbcXn  
  
And don’t forget to check out the server trailer for a quick sneak peek of the fun waiting for you!', 'mc.bluecraft.net:20000', 25565, 'mc_java', 'active', true, NULL, 'https://bluecraft.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'speedvanilla', 'SpeedVanilla', 'Welcome to SpeedVanilla, the ultimate destination for fast-paced, pure vanilla Minecraft gameplay! Here, the thrill of Crystal PvP takes center stage, where agility and strategy are key to dominating the battlefield. At our specially designed spawn area, players can engage in intense Crystal PvP and sword PvP battles, honing their skills before venturing out into the wild.  
  
No land claims, no mercy—just raw, unfiltered Minecraft at its finest. Forge your path in a world where every player is your rival. Raid, loot, and battle your way to the top, testing your survival skills in an unforgiving environment. Will you rise to become the most formidable force in the server, or will you be another casualty in the relentless pursuit of victory?', 'speedvanilla.com', 25565, 'mc_java', 'active', true, NULL, 'http://store.speedvanilla.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'dealertjerick', 'DealertjeRick', 'Welcome to DealertjeRick, a One Chunk SMP where you can only see one chunk at a time.   
  
