INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'luckygem-smp', 'LuckyGem SMP', 'Welcome to LuckyGem – Where Minecraft Comes Alive!  
