INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cozy-realms-1-21-just-released-fresh-survival', 'Cozy Realms 1.21🌿Just Released! 🌍 Fresh Survival', '🌟 A peaceful, relaxing, and chill place to play Minecraft! Cozy Realms is a family-friendly survival server where players of all ages can build, explore, and make new friends in a brand-new world. 🌍  
  
🏠 Key Features:  
