INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'gigacraft', 'Gigacraft', 'Bienvenido a Gigacraft, un servidor de supervivencia vanilla alojado en España.  
  
Para acceder a este servidor es necesario disponer de una copia legítima de Minecraft.  
  
Al unirte al servidor, aceptas las siguientes normas:  
  
1. Sé respetuoso con los demás jugadores.  
2. Trata de pasarlo bien.  
3. Está prohibida la promoción propia o ajena sin autorización previa.  
4. Está prohibido cualquier comportamiento u difusión de contenido de carácter sexual, ofensivo, discriminatorio u ilegal según la legislación española y de tu país de residencia. Denunciaremos cualquier ilegalidad ante las autoridades pertinentes.  
5. Si observas cualquier comportamiento que incumpla alguna de estas normas, debes notificarlo de inmediato al personal de Gigacraft mediante el servidor de Discord o escribiendo un correo a contacto [arroba] gigacraft.es.  
6. El incumplimiento de las normas puede conllevar la prohibición permanente del infractor para acceder a nuestros servidores.  
7. Si tienes cualquier duda o sugerencia, puedes contactar con nosotros mediante nuestro servidor de Discord (enlace en el servidor de Minecraft) o enviando un correo a contacto [arroba] gigacraft.es.', 'mc.gigacraft.es:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
