INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'realm-of-rhaya', 'Realm of Rhaya', 'Welcome to the Realm of Rhaya! Our server is based in the geopolitics of a victorian fantasy era!  
  
