INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'anarchy-network', 'Anarchy Network', 'Anarchy Network is a Semi-Anarchy Minecraft Server created to provide players with the freedom to play Minecraft however they choose. There are no map resets, no tpa/sethome, and griefing/killing is allowed. Since this server is tailored to be a Vanilla experience, exploits, lag machines, and duping will not be tolerated. You''re on your own here, make an adventure worth remembering!  
  
