INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'moderncraft', 'Moderncraft', '⚔️ ModernCraft — The Ultimate Job Class Survival Server ⚔️  
  
Welcome to ModernCraft, the survival world where jobs define your destiny! This isn’t just survival — it’s a job class adventure like no other.  
  
🌟 Choose from 10 Unique Classes  
Pick your path: Dwarf, Vampire, Lumberjack, Elf, Wizard, Blacksmith, Assassin, Farmer, Pirate, Siren — each with its own powers and abilities:  
  
Dwarves swing OP tools for insane mining power.  
  
Lumberjacks fell whole trees with a single chop.  
  
Wizards wield magic; Assassins strike fast; Vampires thrive in the dark.  
Every class feels powerful, and as you rank up, you begin to inherit abilities from other jobs, stacking power until you become a true legend.  
  
🌀 Exclusive Side Quests & Mini-Games  
From custom adventures to our fan-favorite Maze Runner challenge, there’s always more to do than just survive. Few servers have this — but we do.  
  
🏡 Claim Your Own Zone  
Secure protected land, mark your borders, and fly freely inside your zone. Build safely, expand as you grow, and create the home base of your dreams.  
  
💰 A Real Player Economy  
No pay-to-win shortcuts. Coins come from time and effort, with thriving player-run shops fueling the marketplace. Climb to Overlord, Legendary, or Titan, where every rank earned is a badge of honor.  
  
🎉 The Community You’ve Been Looking For  
We’re more than a server — we’re a vibe. Good laughs, good energy, and a Discord community always ready to hang out, joke, and squad up. If you’ve been looking for a place to chill, grind, and make memories, this is it.  
  
🔥 ModernCraft is survival reimagined: job classes, powers, quests, zones, shops, ranks, and endless fun. This is THE server to be on. Will you rise, unite, and carve your legacy?', 'moderncraft.gamename.net', 25565, 'mc_java', 'active', true, NULL, 'https://www.tiktok.com/@moderncraft.gamename.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'aetheria-cobblemon', 'Aetheria: Cobblemon', 'Welcome to Aetheria, a strange and mystical region!  
