INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'casual-minecraft', 'Casual Minecraft', 'Casual Minecraft is the ultimate server for players who want to relive the classic Minecraft experience. With a focus on simplicity, community, and survival mode, we bring the game back to its nostalgic roots. Our close-knit community thrives in a pure survival environment, where collaboration, creativity, and exploration are at the heart of the gameplay. No flashy gimmicks, no over-complicated features—just the original Minecraft you fell in love with. Whether you''re a veteran or new to the game, you''ll feel right at home in Casual Minecraft, where every player is part of the adventure. Join us and rediscover the magic!  
  
