INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'arab-throne', 'Arab Throne', 'Welcome to Arab Throne — the place where players come together to play and enjoy!  
