INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'angelic-mc', 'Angelic MC', 'Join ANGELIC MC, the #1 Survival Server, and experience the ultimate Minecraft adventure! With a thriving player base, dedicated staff, and exciting features, our community is the perfect haven for crafters and explorers alike. Enjoy customizable player vaults, shops, and competitive leaderboards, plus regular events and tournaments that will put your skills to the test. Connect with hundreds of active players, forge lasting friendships, and build your Minecraft legacy. Dive into the action today at ip: angelicmc.org and discover your new gaming home!', 'angelicmc.org:25565', 25565, 'mc_java', 'active', true, NULL, 'https://store.angelicmc.org/', NULL) ON CONFLICT (slug) DO NOTHING;
