INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'trappedmc', 'TrappedMC', 'If you''re feeling nostalgic and are tired of Minecraft prison servers that are too OP, are heavily P2W, and focus on things like gambling instead of community, this is the server for you.  
  
TrappedMC is a modern take on a classic prison server. We strike the right balance of grind and progression while emphasizing play-to-win and community above what other prison servers focus on. We are the exact opposite of servers that might rhyme with Murple Brison.  
  
The entire experience has been carefully crafted by former players of the great OG prison servers from 2011 while focusing on high-quality and deeply integrated custom gameplay. The owner server owner is a developer who focuses on providing a fun, balanced, and engaging experience with over 100 custom plugins and years of testing.  
  
Some features we love:  
  
**Secret Chambers** : If you''ve ever played an old Ssundee server, you might be familiar with hidden loot that shows up in the mines. We created a unique and modern rendition with exclusive and rare loot.  
  
**GPUS & Crypto**: Find rare GPUs and GPU parts while mining, and equip them in your GPU rack to earn passive income as you mine.  
  
**RNG Meter** : Our rare drop system focuses on fairness and grind versus just dumb luck. Your chances of finding rare items increase over time and you can track your progress.  
  
**Contraband** : Plant and harvest illicit growables in your cell to earn illegal money, which you can use to purchase unique items from the Black Market.  
  
**Custom Enchants** : Are you tired of seeing the same enchants on all the servers you play? We have spent years creating an entirely custom system unique to our server featuring over 100 custom enchantments across ten different rarities. These enchantments, and how many you can use, unlock over time and feel very progressive and natural.  
  
__  
  
IP: trappedmc.com  
  
Bedrock IP: bedrock.trappedmc.com:19132  
  
Version 1.20.2-1.20.4 & (Bedrock Compatible)  
  
Discord: https://discord.gg/trappedmc  
  
Voted Top 10 on Prison Servers of 2024, being the only classic prison server on the list  
  
https://www.sportskeeda.com/minecraft/10-best-minecraft-prison-servers-2024  
  
Please consider joining our community and checking it out for yourself! We hope to see you soon.', 'trappedmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://trappedmc.com', NULL) ON CONFLICT (slug) DO NOTHING;
