INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'disc-realms-network', 'Disc Realms Network', 'Disc Realms is a Network Server that offers two game modes: Towny and Semi-Anarchy!  
  
