INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'nrp-new-roleplay', 'NRP × New RolePlay', 'New RolePlay ist ein Projekt, das sich auf die Fahne geschrieben hat, Minecraft-Rollenspiel wieder ansprechend zu gestalten. Eine große Community war bisher entweder auf veraltete Server angewiesen oder musste sich durch Mods und Erweiterungen bis zur Unkenntlichkeit überzeichnete Server suchen, um ihre eigenen Geschichten interaktiv in Minecraft erleben zu können. Das soll sich jetzt ändern. Unser erfahrenes Team hat sich der Herausforderung gestellt, die Vorzüge des klassischen Minecraft-Roleplay-Genres mit innovativen Neuerungen aufzuwerten und dadurch ein neues, spannendes Projekt an den Start zu bringen. NewRoleplay stellt mit der fiktionalen Stadt den Schauplatz und die Kulisse für die Geschichten und Abenteuer dar, die unsere Spieler selbst entwickeln und umsetzen. Schließ dich einer stetig wachsenden Community an und finde deinen Platz in einer Gemeinschaft, die auf unserer liebevoll gestalteten Map gemeinsam Zeit verbringt. Du kannst dabei völlig frei entscheiden, wie du deinen Weg bei uns beschreiten möchtest: Schließt du dich einer bereits bestehenden kriminellen Organisation an und versuchst, dich bis an ihre Spitze zu kämpfen?', 'new-roleplay.de:25565', 25565, 'mc_java', 'active', true, NULL, 'https://www.new-roleplay.de', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'kaario-network', 'Kaario Network', 'Sunucumuzda Bulabileceğiniz Oyun Modları:  
