INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'four-nations-mc', 'Four Nations MC', 'Four Nations is a bending roleplay server; we feature a map based directly off of Avatar: The Last Airbender and The Legend of Korra. You are able to join a nation and rise through the ranks, you can also bend the elements!  
  
