INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'crispy-network-crossplay', 'CRISPY NETWORK | CROSSPLAY', 'Crispy Network is an Indonesian Minecraft server that has been running since 2018. Designed to offer a unique experience, the server features a Survival Fantasy theme, blending RPG survival gameplay with elements of magic, adventure, and advanced technology.   
  
