INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'fusion-network', 'Fusion Network', 'Fusion Network is an Asian offline mode (aka cracked) Minecraft server network offering support for versions 1.9 and above. It currently features Lifesteal SMP and Practice PvP game modes. Other features include duels, kits, economy, leaderboards, and more. Fusion Network''s online store allows you to buy various things for each game mode, like ranks, addons, and crate keys. You can also buy Fusion Coins, a network-wide currency for spending in its in-game Coin shop. Join today and discover dozens of the network''s other incredible features, and be sure to join its official Discord for updates, support, giveaways, events, and more!', 'fusion-network.xyz:25565', 25565, 'mc_java', 'active', true, NULL, 'https://fusion-network.xyz/', NULL) ON CONFLICT (slug) DO NOTHING;
