INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'slime-throne-tensura', 'Slime Throne | Tensura', 'What is Slime Throne and why should you join it? Slime Throne is a carefully crafted kingdom server with custom GUI''s, GUI artwork, custom prefix artwork that goes beside your name in chat, buyable cosmetics made with Armourer''s Workshop... "But someone can pay to look cooler than me?" Well not exactly. You see, we''re going to have raid bosses. These bosses will drop cosmetics added through the ItemsAdder plugin. ItemsAdder can add a lot cooler stuff than anything you can make with Armourer''s Workshop. To fight the raid boss you''ll have to farm mobs and they have a chance at dropping a key, you can also buy these keys, but will still have to fight the raid boss. The keys open the door to an instanced dungeon with a party of up to 4, or you can go solo.   
  
No PAY TO WIN! None. No reset scrolls inside of crates or anything like that.   
  
Plushies! We''ll have crates that will give you a chance at a Tensura themed plushy! Balloons! The crate will also give you a chance at a Tensura themed balloon. Every plushy set and every balloon set comes with a galaxy version that has a 1% drop rate... heheh. That is how we monetize. NO PAY TO WIN.   
  
Start your own kingdom, build your own legacy, rule the server. Go to war and earn rewards. Both parties who go to war will earn rewards to encourage actual war.', 'play.slimethrone.net', 25565, 'mc_java', 'active', true, NULL, 'https://slimethrone.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cloud-smp', 'Cloud SMP', 'Cloud SMP adalah sebuah server minecraft yang berdiri sejak 2021. Cloud SMP pertama kali di rilis oleh Chairawan Channel pada Youtube nya. Cloud SMP Pertama kali di buat untuk user minecraft bedrock, dan mulai masuk untuk user java pada Season Baru nya, yaitu Cloud SMP | New Era.', 'cloudsmp.xyz', 25565, 'mc_java', 'active', true, NULL, 'https://store.cloudsmp.xyz', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'creative-central', 'Creative Central', 'Creative Central is a work in progress Creative Plots, Towny Survival Terralith Map, Skyblock MMO, and MMORPG Style Custom Roleplay Server with nearly 10 years of dedicated lore and worldbuilding put into it.  
  
CC Plots [Released]  
Creative Central Plots offers a sizeable 512x512 plot with free world-edit and low limitation on many block and command configurations. CC Plots also offers VoxelSniper to its Sponsors, a one time purchase.  
  
CC Plots also offers /headdatabase and /armorstandtools for no extra charge, to allow for full customization of builds and accessories.   
  
CC Earth [Released]  
A 1:500 scale Earth Map with a custom data pack driven Nether and End dimension. Create towns to claim land and use the in-game economy to upkeep your settlement. Resources are geographically linked with real life deposits. Create nations to ally with friends or strangers under the same name and expand your territories.   
  
PvP is enabled in some aspects of the world however is not a main focus and does not inhibit gameplay or progression. Utilize McMMO to gain passive skills and perks while playing.  
  
CC Battles [Open Beta]  
A simple KitPvP gamemode with a custom arena. Fight against players or team up to take down a powerful foe. More features to come.  
  
CC Islands [WIP]  
A WIP Skyblock gamemode utilizing MMO Style Classes that offer unique goals and challenges to master. Prestige to make mastering your current class easier or to start a new class entirely. Progress is saved across all classes. Fight in a PVP Arena or delve into a PVE Arena and fight off waves of monsters to test your classes abilities and prowess.  
  
CC Roleplay World [WIP]  
A WIP fully custom built fantasy style roleplay with MMORPG elements and character customization. Mechanics such as magic and attributes are planned and we fully believe a manually balanced story to provide a unique experience and character creator for each player who decided to join the roleplay.  
  
~~~~~  
  
Creative Central is a strictly non pay-to-win or microtransaction server. A monetary donation is kindly accepted (WIP).  
  
Creative Central is an affiliation of Project Everything, a collaboration of different worldbuilding, stories, and lore collections of individual people under the same canon.  
  
Join our Discord to view our socials!https://discord.gg/Hpg5K7wgUb', 'play.creative-central.net:25565', 25565, 'mc_java', 'active', true, NULL, 'https://creative-central.net/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minezinho', 'Minezinho', '━━━━━━━━━━━━━━━━━━  
