INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'all-the-mods-10-community-atm10-servers', 'All the Mods 10 Community - ATM10 Servers', 'Why play our ATM10 Server?  
  
Active Community: Join over 10,000+ members on our Discord, with active chats, helpful guides, and friendly players.  
Lag-Free Gameplay: We optimize our servers with lag fixes and mod patches to ensure smooth gameplay.  
