INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'straight-up-survival-vanilla', 'Straight Up [Survival] [Vanilla]', 'Straight Up is a vanilla Minecraft: Java edition server open to all players. We offer a laid back survival experience that is as close to vanilla as possible. The overworld has never been wiped since our founding date of April 1st, 2019, and we intend to keep it that way. With a rich history spanning over 5 years, there is much to explore and many adventures to be had.   
  
