INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'the-perch', 'The Perch', '**Looking for a new Minecraft home?**
  

**Welcome to The Perch! ❤️**
  
  
The Perch is a server that separates itself from other servers by truly focusing on what the community wants and needs. We work hard to create and maintain a place that players can call a second home, without toxicity or drama.  
  
**✨Tailored Experience✨**  
On The Perch, you won''t feel like you''ve played the same thing before. Whilst our feature-set is very similar to other servers, we go above and beyond to deliver features in a tailored manner, making them easier to use, better, or more balanced.   
  
**💬Community Engagement💬**  
We are in constant communication with our players to make sure their feedback is heard. We do this through various means, including a suggestions channel, tickets, and our bi-monthly feedback forms! Along with that, we publish weekly change-logs in which all changes made to the server can be read. We also hold monthly events to bring the community together!  
  
**🌿Survival Feel🌿**  
We put effort into making sure players don''t lose that ''''Survival Feel''''. We think of the consequences in the day-to-day of players with every change we make, making sure that the experience will never feel bloated. Any feature you don''t like, can be toggled off. This also means that our server puts major effort into making sure that farms and redstone contraptions behave as they would in the base game.  
  
**_Without making this post too long, here are some more important features:_**  
⌛A ranking system based on playtime, allowing you to unlock perks simply by playing on the server.  
💰An economy that''s fair and balanced, with plenty of player-ran shops!  
🔧Small tweaks to game-play to make the game just a bit nicer to play.  
🗺️A web-map where you can view all worlds!  
❤️Last but not least, our lovely community!  
  
Check these out, too!  
**Stats** https://map.the-perch.net/stats/  
**3D Map** https://3dmap.the-perch.net/  
**2D Map** https://2dmap.the-perch.net/  
**Rules** https://rules.the-perch.net/  
  
**We hope to see you log on soon!** ❤️', 'mp.the-perch.net', 25565, 'mc_java', 'active', true, NULL, 'https://3dmap.the-perch.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'skyblockclassic-java-bedrock', 'SkyblockClassic+ Java&Bedrock', 'Hey! Are you looking for a vanilla Skyblock server without MagicCobbleGens or something like this? We are a classic Skyblock server. You can play with friends and do some challenges to get items you could normally not get in the normal way. Just check it out!', 'skyblock.702Netzwerk.de', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
