INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'craftergang-12-jahre-online', 'Craftergang | 12 Jahre Online!', 'Wir bieten dir übrigens diese Minigames an:  
