INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cobblemon-dystoria', 'Cobblemon Dystoria', '🌟 Welcome to Dystoria 🌟   
Your ultimate Cobblemon adventure server!   
  
🔹 Free-to-Play and Unique:   
Dystoria is a family-friendly server that is completely free to play. Our goal is to bring together a dedicated, supportive, and growing community where you can embark on your Pokémon trainer journey in a vibrant and dynamic world!   
  
🔹 Pioneering Innovation:   
We’re proud to be the first server in the world to introduce the brand-new Shiny Rarities system – featuring Shiny, Shinier, and Shiniest Pokémon. Are you ready to catch them all?   
  
🔹 An Immersive Cobblemon World:   
Explore stunning biomes, challenge powerful Gym Leaders, and catch rare Pokémon in special areas like the Safari Zone. But that’s not all – we regularly host exciting events such as Maze Runs, Spleef Tournaments, and seasonal specials!   
  
🔹 Fairness and Fun First:   
Dystoria is 100% F2P! Players can earn unique rewards like cosmetic ranks and Pokédex milestones simply through skill and dedication.   
  
🔹 Exclusive Features:   
- Hunting System: Earn Hunting Coins and exchange them at the Huntsman Store for rare items!   
- PokéLures: Boost the spawn rates of specific Pokémon types to enhance your hunting strategy.   
- Dystoria Stories: Discover deep lore, thrilling quests, and hidden secrets crafted by our talented writers and architects.   
- Custom Content: Enjoy new evolution methods, custom Pokédex challenges, and more.   
  
🔹 A Community That Cares:   
Our players often say Dystoria feels like a second home. With active moderation, a helpful community, and regular updates, you’ll always feel welcome here.   
  
🌐 Join the Dystoria Family!   
Experience a Cobblemon adventure like no other. Build your dream team, conquer challenges, and make history in the world of Dystoria.', 'play.dystoria.org:25565', 25565, 'mc_java', 'active', true, NULL, 'https://www.dystoria.store/', NULL) ON CONFLICT (slug) DO NOTHING;
