INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'pokemasters', 'PokeMasters', 'PokeMasters: Your Ultimate Pixelmon Adventure!  
  
