INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'prestigiousmc-pgmc-world', '🌟 PrestigiousMC | pgmc.world 🌟', 'PrestigiousMC (pgmc.world) is a towny and survival focused server. You can either join a town or wander off into the survival world and set up a home somewhere!   
  
**You can use /rtp to teleport to random locations in the:**  
> Main World (For survival and player protections)  
> Towny World (Purely for Towns and Nations)  
> Resource World (A regular world that resets once a month)  
> Nether Resource World ^  
  
  
👑 Minecraft server IP: pgmc.world  
➥ Direct Survival server IP: survival.pgmc.world  
➥ Direct Creative server IP: creative.pgmc.world  
➥ Direct Vanilla server IP: vanilla.pgmc.world  
  
🛏️ Bedrock Port: 19132 (Link bedrock to java account: /linkaccount)  
  
🌐 LiveMap: http://144.217.10.67:8100/  
  
👾 Discord Invite: https://discord.gg/GuFbJGxBjn  
  
  
**- Self-serve protection and anti-grief:**  
Use the protection menu (/ucp) to set up a protection without having to type any commands! If you forget to protect land and do get griefed, the staff at PGMC can help fix everything and ban the griefer!  
  
**- Custom PvE content:**   
Take on a new challenge with our dungeons with unique mobs. There are also world bosses for you to kill. Each boss has unique drops such as Speed boost gear, health boost shield and collectable chat tags!   
  
**- Keep items on death:**  
You will not lose your hours worth of mining by falling into lava or losing your items from a sneaky creeper. You keep all of your items on death.  
  
**- Economy with player shops:**  
Choose a job and earn money from doing tasks or earn money by setting up your own store!  
  
**- Immersive Skill system:**  
Level up skills to gain extra powers or Become #1 on skills leaderboard. Each skill greatly improves your playing experience in those skills. For example, Alchemy gains access to haste and health boost potions at level 65.  
  
**- Friendly community:**  
We strongly believe that the community is the heart of a server, Our community members come first and we will make sure everybody feels like they are part of it! We also listen strongly to community suggestions.', 'pgmc.world', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/GuFbJGxBjn', NULL) ON CONFLICT (slug) DO NOTHING;
