INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'jerdjen-republic', 'Jerdjen Republic', 'Welcome to Jerdjen Republic''s Voting Page!  
  
Jerdjen Republic is a City-Based Minecraft Server. Drive Vehicles across vast Towns and Cities, trade with People through an extensive Economy, ride the (currently free) Public Transport or farm for Resources!  
  
Jerdjen Republic also has a No P2W commitement and everything will be currently run through donations. After game updates a store may release, however, it will not sell any elements or items that make you better than other players. Everyone gets the same fair treatement.  
  
Have you liked what you read so far? Then this Server is for you. Go ahead and try it now!  
  
  
Jerdjen Republic is currently in Early Access. Expect things to change over the coming months.', 'play.jerdjenrepublic.net', 25565, 'mc_java', 'active', true, NULL, 'https://jerdjenrepublic.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minecraft-evopixel', 'Minecraft EvoPixel', 'Minecraft EvoPixel is a high-performance Minecraft server designed for a seamless and immersive gaming experience. With powerful hardware and advanced protection, our server remains lag-free even under extreme conditions, handling attacks up to 480GB/s without affecting performance. Enjoy a 24/7 online server with minimal downtime, only requiring quick restarts during updates. Our custom-built medieval maps and unique gameplay systems create a world full of adventure and originality.', 'mc.evopixel.ro:25565', 25565, 'mc_java', 'active', true, NULL, 'https://minecraft.evopixel.ro', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cavemc', 'CaveMC', 'Welcome to CaveMC, Minecraft''s first Semi-Anarchy cave-only World!  
  
Cave MC is an enhanced vanilla, semi-anarchy survival server where the entire world is underground. With custom terrain, no surface, and access to all dimensions, survival is brutal, and only the toughest will thrive.  
  
