INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'fruitville', 'FruitVille', 'Welcome to Fruitville a super friendly 1.21 network! We are a laid back community with oneblock, earth survival, active staff and much more!  
  
