INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mcc-smp-minecraft-crew', 'MCC SMP (Minecraft Crew)', 'MCC SMP is a Minecraft Survival server that aims to bring all different kinds of people together to play Minecraft. We have fun events every now and then which are run by everyone on the server. We also have a really kind and creative community that is eager to bring in some new people for new ideas and new personalities. The server is mostly vanilla with a few quality-of-life changes, but overall, you won''t notice much of a difference.  
  
