discord.gg/EjWXnwfYRj', 'MccSmp.myserver.gs', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/EjWXnwfYRj', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'neverwinter-knights', 'Neverwinter Knights', '𝕹𝖊𝖛𝖊𝖗𝖜𝖎𝖓𝖙𝖊𝖗 𝕶𝖓𝖎𝖌𝖍𝖙𝖘 is a Survival RPG where Towny claims are your only safe haven in a ruthless, economy-driven world. Beyond your borders lies true mystery— griefing, raiding, and PvP are always on. Explore the Surface, Abyss, and Underdark, each with unique risks and rewards. Build towns, forge alliances, or wage war to expand your territory. Master industry with Slimefun and InfinityExpansion2, farm riches with Pyrofishing, Pyromining, and Pyrofarming, brew legendary spirits, create and sell art with ArtMap, and trade MCMMO credits. Form guilds or secret societies, dominate trade, or crush rivals in battle. In Neverwinter Knights, gold, power, and cunning rule all — the land you claim is the land you keep. Will you rise as a king, merchant lord, or feared warlord?', 'nwk.gamergod.net:117291', 25565, 'mc_java', 'active', true, NULL, 'https://neverwinterknights.craftingstore.net/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cozycraft', 'CozyCraft', 'Welcome to CozyCraft!   
  
