INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'seven', 'Seven', 'Vous cherchez un serveur minecraft gratuit ? Rejoignez-nous dès maintenant et vos amis aussi. Ensemble, nous allons guerroyer et bâtir ! Prenez Garde, la Nuit Sera Longue !', 'theseven.fr', 25565, 'mc_java', 'active', true, NULL, 'http://theseven.fr', NULL) ON CONFLICT (slug) DO NOTHING;
