INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'demon-network', 'Demon Network', 'Demon Network is an offline-mode (cracked) Minecraft Survival server from India focused on a fun, fair, and long-term survival experience.  
  
This season introduces a complete player economy, allowing players to earn money, trade items, and grow their wealth. A server marketplace lets you buy useful resources, while player-run chest shops allow the community to trade items and build a player-driven economy.  
  
Exploration is more rewarding with a personal loot system, where every player gets their unique rewards from generated chests. Combat and progression are also enhanced with powerful custom enchantments that add new abilities to weapons, tools, and armor.  
  
The world features improved terrain generation for better exploration, along with a clean spawn, helpful NPCs,ranks, and playtime rewards. The server is completely fair with active staff.  
  
Demon Network supports Minecraft versions from 1.8 to 1.21.11  
  
Join Demon Network and start your survival adventure!', 'demon.unfazium.cloud', 25565, 'mc_java', 'active', true, NULL, 'https://demon-network.my.canva.site/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'enderhq', 'EnderHQ', 'Immerse yourself in a brand new ever-changing world that never resets!  
