INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'static-studios', 'Static Studios', 'Static Skyblock offers a fresh, evolved Minecraft experience with a friendly, active community, challenging dungeons, and competitive warzones. Build your island, master new skills, conquer dungeons, and discover unique enchantments and loot while having fun with players from around the server.  
  
