gamebyte.me', 'Gamebyte.me', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minedmc', 'MinedMC', 'MinedMC is een Nederlandstalige server opgericht begin 2025 en draait op de minecraft versie 1.20.6. Laat je fantasie lopen, maak je eigen town nodig je vrienden uit of neem nieuwe spelers aan. Alles is mogelijk als met je eigen town, bouw extravagant en en creëer rijkdom. Of ben je meer fan van oorlogen voeren, dat kan ook! Vanaf heden heeft de server EventWars waarin er verschillende oorlogen worden gevoerd namelijk: - Town VS Town - Nation VS Town - Nation Civil War - Nation VS Nation Towns hebben het heft in eigenhanden om te doen wat ze leuk vinden! Voor een uitdaging experimenteer met Slimefun en de vele addons die de server biedt.  
  
Join nu ook met Bedrock. Gebruik de poort 26931', 'play.minedmc.nl', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/vTqKSZpcvd', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'magnolia-survival', 'Magnolia Survival', 'Welcome to Magnolia Survival! We have friendly staff and community, where you can build your master piece in survival. You have the option to protect it using land claims, so you can show it off to friends and players without the fear of it being blown up. This is not a hand out server, so you will be working for everything you have. NO map resets.', 'Magnolia-Survival.com:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'tulparmc', 'TulparMC', 'TulparMC – Türkiye’nin En İyi 1.21.4 Emek Survival & Skyblock Sunucusu  
Java & Bedrock Cross-Platform Minecraft Sunucusu!  
TulparMC, Minecraft 1.21.4 sürümü tabanlı, Türkiye’nin en popüler emek survival sunucularından biridir. Hem Java hem de Bedrock (mobil ve konsol) oyuncularına destek verir. Oyuncular play.tulparmc.com ve bedrock.tulparmc.com adreslerinden bağlanabilir.  
  
12 yıllık Minecraft tecrübesine sahip iki kurucu tarafından geliştirilen TulparMC, samimi bir topluluk ve adil yönetim anlayışı ile oyuncularına eşsiz bir oyun deneyimi sunar.  
  
Neden TulparMC?  
Cross-platform destek: PC, mobil ve konsol oyuncuları bir arada oynar.  
  
Her zaman güncel: Minecraft’ın son sürümlerinden giriş yapabilirsiniz.  
  
Emek odaklı ekonomi ve pazar sistemi  
  
Günlük ödüller, güncellenmiş spawner ve market sistemi  
  
Düzenli ve ödüllü etkinlikler: Build yarışmaları, PvP turnuvaları ve özel sezonluk etkinlikler  
  
Güçlü ve samimi topluluk ortamı  
  
Hemen katıl, Türkiye’nin en iyi Minecraft survival sunucusunda macerana başla!  
Java: play.tulparmc.com  
Bedrock: bedrock.tulparmc.com', 'play.tulparmc.com:25565', 25565, 'mc_java', 'active', true, NULL, 'https://tulparmc.com/', NULL) ON CONFLICT (slug) DO NOTHING;
