INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mc-forgaming-ro', 'MC.ForGaming.Ro', '🎮 Bine ai venit pe ForGaming.Ro! 🚀  
  
ForGaming.Ro este locul unde pasiunea pentru Minecraft prinde viață într-un mod cu totul special! Aici, gameri de toate vârstele se adună într-o comunitate prietenoasă și relaxată, unde fiecare membru este întâmpinat cu voie bună și deschidere.  
  
✨ Ce te așteaptă pe ForGaming.Ro? ✨  
  
Experiență unică:  
Cu sisteme unice asigurate de pluginuri custom, fiecare sesiune de joc devine o adevărată aventură plină de surprize și provocări interesante.  
  
Comunitate vibrantă:  
Un mediu sigur și creativ, ideal chiar și pentru cei mici, unde distracția și prietenia sunt mereu la ordinea zilei.  
  
Atmosferă relaxată:  
Ne place să ne simțim ca acasă – relaxați, inspirați și mereu pregătiți pentru un joc de calitate, în stilul nostru cool și modern. 😎  
  
🌟 Vino alături de noi! 🌟  
  
Dacă ești în căutarea unui server de Minecraft care să îmbine distracția, creativitatea și prietenia, ForGaming.Ro este alegerea perfectă! Intră pe minecraft-mp.com și descoperă un univers vibrant, unde fiecare zi aduce noi aventuri și momente memorabile.  
  
Te așteptăm cu brațele deschise! 🎉  
  
Happy Gaming! 🎮✨', 'mc.forgaming.ro', 25565, 'mc_java', 'active', true, NULL, 'https://tree.forgaming.ro/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'zodiac-craft', 'Zodiac Craft', 'Welcome to Zodiac Craft  
Looking for a chill place to game with other cool folks? Welcome to Zodiac Craft, where we keep it fun, laid-back, and packed with awesome features—no bullshit, no drama, just good times.  
  
We’ve got:  
