INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'xapros-smp-a-vanilla-1-21-11-server', 'xapros SMP - A Vanilla 1.21.11 Server', 'We are **xapros SMP**, a whitelisted Vanilla server with a friendly and active and inclusive community. Here''s some why you should join us!  
  
* We are an international 18+ community! You can meet people from all over the world and play the game with them.   
* We have 20-25 players online at peak time! That doesn''t mean the server is gonna be empty at any time. Due to our international playerbase we have people from many timezones, from Australia to Europe, from Africa to America.  
* We have overkill hardware, you won''t have to worry about lag! Your view distance is 16 chunks, the Render Distance and Simulation Distance are both dynamic and change depending on server performance.   
* No land claims to preserve vanilla feel, but we keep you safe from griefers and thieves! If you worry, you can always check if somebody took anything from you using */ledger inspect*  
* We have a beautiful spawn with a shopping district in which you can trade with diamonds!   
* We have a very useful Nether Highway system keeping everyone connected! No speed limits for the boats on the ice!  
* You can use our [Bluemap](http://map.xaprosmp.xyz/) to look at the whole world!  
* We don''t ask for any money, we are completely free to play. We run the server as a hobby!   
* We have BlazeandCave''s Advancements as a challenge to the dedicated!  
* We run on Fabric. This means that you can build complex farms and enjoy pure vanilla mechanics you don''t have on a server running on Paper/Spigot.  
  
  
Just check us out! Join our [Discord](https://discord.gg/A48UEbZbad) to apply, it''s an easy process! We''ll be happy to have you in our community', 'xaprosmp.xyz:25565', 25565, 'mc_java', 'active', true, NULL, 'https://map.xaprosmp.xyz', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'kingdomsmc', 'KingdomsMC', 'KingdomsMC  
A server designed to offer a brand-new roleplay experience for everyone!  
  
We aim to provide a dynamic playground for all kinds of geopolitical-based roleplaying, where every decision, alliance, and declaration shapes the server in unique ways.  
  
But KingdomsMC isn’t just for roleplayers! Builders will find a home here too, with lasting, grief-protected cities that players can inhabit. Plus, our world is fueled by a player-driven economy, making every trade and transaction meaningful.  
  
Are you ready to be part of the beginning of something huge? Join us!', 'kingdomsmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/j6E8h5Z4UR', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rush-craft', 'Rush Craft', '🌟 RUSHCRAFT 🌟  
  
💎 RushCraft, rekabetin ve eğlencenin sınırlarını zorlayan en iyi BoxMining sunucularından biri! Eğer PvP’de yeteneklerini konuşturmak, kaynaklarını toplayıp güçlenmek ve en iyisi olmak istiyorsan, doğru yerdesin!  
  
⛏️ BoxMining: Kaynaklarını topla, kendi ekonomini oluştur ve güçlen! Ne kadar çok madencilik yaparsan, o kadar gelişir ve PvP’de rakiplerinden bir adım önde olursun!  
🏆 Liderlik Sıralamaları: En iyi savaşçılar, en zengin madenciler ve en güçlü oyuncuların yer aldığı sıralamalarda zirveye ulaş!  
🎁 Ödüllü Etkinlikler & Çekilişler: Discord’da ve sunucuda düzenlenen özel etkinlikler, turnuvalar ve çekilişler ile bedava ödüller kazanma fırsatını kaçırma!  
🛒 Özel Market & Ekonomi Sistemi: Kazandığın kaynaklarla takas ,ticaret yap ve servetini büyüt!  
📢 Aktif & Yardımsever Topluluk: Eğlenceli sohbetler, dostça rekabet ve gelişmiş destek ekibiyle her zaman yanındayız!  
  
🚀 RushCraft’a katıl, efsane olmaya hemen başla!  
🔗 Davet Linki: discord.gg/rushcraft  
İp: play.rushcraft.net  
  
🔥 Rakiplerini ez, servetini büyüt, en güçlü sen ol! 🔥', 'play.rushcraft.net', 25565, 'mc_java', 'active', true, NULL, 'https://rushcraft.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'the-minecart', 'The Minecart', 'Welcome to The Minecart a super friendly 1.21 network! We are a laid back community with oneblock, earth survival, active staff and much more!  
  
Economy Jobs Land claiming Custom items Furniture  
  
How to join The Minecart?  
  
On Java edition, head to multiplayer and click add server, next put play.theminecart.net as the server name and that''s it, you''re ready to join.  
  
On Bedrock edition, click on play and navigate to the servers tab, next scroll down till you see add server and for the server name type The Minecart and for the address use play.theminecart.net, leave the port default and click join.', 'join.theminecart.net', 25565, 'mc_java', 'active', true, NULL, 'http://store.theminecart.net', NULL) ON CONFLICT (slug) DO NOTHING;
