INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'multyplay-distractie-fara-limite', 'MultyPlay | Distractie fara limite!', 'Salutare! Bine ai venit la noi pe server! Probabil te intrebi ce este cu acest server, cand a fost creeat si mai multe curiozitati. Server-ul MultyPlay.Ro, a fost creeat in 2016 Februarie de catre xVicoBT_RO. Serverul a adaptat mai multe sectiuni, precum Survival, SkyBlock-Easy / SkyBlock-Hard / SkyBlock-OP, OP-Prison, SkyPvP si multe altele. In cazul in care ai mai multe intrebari, nu ezita sa intrebi un Membru Staff!', 'fun.multyplay.ro', 25565, 'mc_java', 'active', true, NULL, 'http://discord.multyplay.ro', NULL) ON CONFLICT (slug) DO NOTHING;
