INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'daisydreams', 'DaisyDreams', 'Still looking for the best Minecraft server? Not sure where to play? Come join our server!  
