INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mylifecraft', 'MyLifeCraft', '🌍 Bienvenido a MyLifeCraft – Un nuevo mundo, una nueva vida.  
En algún rincón del universo digital, entre códigos y sueños, nace MyLifeCraft, más que un simple servidor de Minecraft. Es un refugio, una segunda oportunidad, una realidad alternativa construida con dedicación para ofrecerte una nueva vida, lejos del ruido, las cargas y las prisas del mundo real.  
Aquí, cada bloque colocado, cada parcela conquistada y cada aventura vivida tiene un valor que trasciende lo material. Porque en MyLifeCraft no solo juegas… renaces.  
Este mundo ha sido creado con amor por quienes creen que los videojuegos no son una simple distracción, sino una forma de arte, un refugio emocional y una vía de expresión auténtica. No eres uno más. Aquí eres tú mismo, sin máscaras, sin juicios, con la libertad de forjar tu destino desde cero.  
Desde el primer momento que te unes, te abrimos las puertas a una comunidad amigable y creativa. En nuestro servidor, tú decides tu camino: construir, luchar, comerciar, forjar amistades o simplemente encontrar paz. En MyLifeCraft, puedes crear un hogar, una historia y una vida nueva que evoluciona contigo.  
¿Estás cansado de servidores sin alma? ¿De mundos que prometen mucho pero no te dan nada que realmente te toque el corazón?  
Entonces este es tu lugar.  
MyLifeCraft no es perfecto, pero es real. Como la vida misma, está lleno de retos, logros, sueños, metas y emociones. No tienes que ser el mejor constructor, ni el jugador más fuerte. Solo tienes que ser parte de esta historia. Dejar tu huella. Construir algo que te haga sentir orgulloso.  
Porque al final, todos buscamos lo mismo: un espacio donde podamos ser felices. Y quizás, entre píxeles, aldeanos y aventuras, lo encuentres aquí.  
Porque aquí, cada jugador importa. Cada historia cuenta. Y cada día es una nueva oportunidad.  
🕊️ Bienvenido a tu nueva vida. Bienvenido a MyLifeCraft.', 'mylifecraft.net', 25565, 'mc_java', 'active', true, NULL, 'http://www.mylifecraft.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bygoghygmc', 'BygOgHygMC', '✨ Velkommen til Byg&Hyg! ✨  
