INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'downriver-smp', 'Downriver SMP', 'We’re excited to announce that Season 3 is on the horizon, and we can’t wait to welcome you! This season, we’re staying true to what makes our server special: a chill, mature (18+) community where everyone can enjoy the game their way. Whether you’re into building, exploring, redstone, or just hanging out with friends, our Vanilla+ experience is designed to cater to all playstyles. Season 3 will launch March 7th.  
  
