INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lifesurvival2-0', 'LifeSurvival2.0', '¡Atención, aventureros de Minecraft! ¡Life Survival Network ha regresado, más grande y mejor que nunca! Prepárate para una experiencia de juego inigualable, ¡ahora en la versión 1.21.4 y con un montón de novedades!  
  
¿Eres un jugador de Java o Bedrock? ¡No importa! En nuestro servidor No Premium, puedes unirte desde la versión 1.12.X hasta la 1.21.X. ¡La diversión no tiene límites!  
  
¿Qué modalidades te esperan?  
  
**Survival:** ¡Sobrevive en un mundo lleno de desafíos y construye tu propio imperio! ¡Y lo mejor de todo, podrás crear tus propias tiendas virtuales y comerciar con otros jugadores!  
**OneBlock:** ¡Desafía tus habilidades en un mundo donde solo cuentas con un bloque! ¿Podrás expandirte y prosperar?  
**Survival Anárquico 1.20:** ¡Libera tu lado más salvaje! Aquí, las reglas no existen y ¡puedes usar hacks sin restricciones!  
**SurvivalOP** : ¿Aburrido de las clásicas mecánicas del juego? Acá encontrarás un server potenciado que te permitirá llegar a donde nunca has llegado en Vanilla  
  
¿Listo para unirte a la aventura?  
  
JAVA:  
IP: **play.lifesurvival.top**  
BEDROCK:  
