INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lucmedina', 'LucMedina', 'Venha conhecer o nosso **servidor de Minecraft brasileiro** , ele é **de survival, roleplay e economia**.  
  
