INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'craft-of-salem', 'Craft Of Salem', 'Craft of Salem, Salem dünyasında geçen bir RPG Survival Minecraft sunucusudur. 12 meslek, banka ve kredi, dinamik tüccar ve kurye teslimatları, arazi müzayedeleri, demirci hizmetleri ve özel zindanları (Kafatası Zindanları, Fısıldayan Labirent) ile ekonomi ve PvE derinleştirilmiştir. Kafa ödülü tabanlı PvP, 8 oyun tarzı, 12 yetenek, yetenek ağacı ve 60+ özellik karakterini şekillendirir; loncalar, görevler, başarılar ve keşifler ilerlemeyi destekler. Claim, evler, RTP ve oyuncu warp’ları ile keşif ve üs kurma kolaylaştırılır. Craft of Salem, hem ekonomi hem savaş hem keşif arayan oyuncular için tasarlanmıştır.', 'play.craftofsalem.com', 25565, 'mc_java', 'active', true, NULL, 'https://craftofsalem.com', NULL) ON CONFLICT (slug) DO NOTHING;
