INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'petalcraft-1-21', 'PetalCraft [1.21+]', '🌸 Welcome to Our Semi-Vanilla SMP!  
  
Step into a friendly, welcoming community where adventure, creativity, and fun come together!  
  
Enjoy a classic Minecraft experience enhanced with unique custom features — whether you’re building, exploring, or relaxing with friends.  
  
Our goal is to create a space where everyone can make lasting memories and enjoy the journey together.  
  
🌟 What We Offer  
  
💰 Unique Player-Driven Economy  
Experience a creative, trade-based economy that doesn’t rely on in-game money. Exchange, craft, and trade your way through a system built on cooperation and creativity!  
  
🪓 Semi-Vanilla Gameplay  
Enjoy a balanced semi-vanilla experience enhanced with custom twists while keeping the charm of classic Minecraft.  
  
⚔️ Skills System (Non-Competitive)  
Level up personal skills at your own pace!  
  
Our non-competitive skill system promotes growth and fun without leaderboards — perfect for players who love a relaxed, community-focused environment.  
  
🎉 Community Events  
Take part in exciting seasonal and server-wide events designed to bring players together for fun, teamwork, and great rewards!  
  
📜 Quests & Challenges  
Complete starter, weekly, and monthly quests for unique rewards that keep gameplay fresh and engaging.  
  
🪶 Keep Inventory  
Keep your valuable items safe — you won’t lose your gear when you die! Perfect for casual play and relaxed exploration.  
  
🔒 Safe Drop  
Never worry about losing items again! Safe Drop prevents items from being lost in lava or accidentally dropped in dangerous places.  
  
🤝 Friendly & Safe Community  
Join a welcoming and inclusive player base.  
  
We take pride in providing a safe, positive environment where everyone can build, hang out, and make friends.  
  
🧭 Custom Features & Ongoing Updates  
Discover custom items, systems, and new content released regularly — there’s always something new to explore and enjoy!  
  
✨ Settle in, start your adventure, and make your mark on our world today! 🏡', 'mp.petalcraft.org:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'mine-wars', 'Mine Wars', '🔥 MineWars – The Ultimate Battlefield in Minecraft! 🔥  
  
