INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'rocketrealms', 'RocketRealms', 'RocketRealms is a Minecraft Prisons and Dungeons Server with unique features like no other! Experience dozens of fun features on RocketRealms such as OP custom enchants, smooth gameplay and tons of in-game events!  
  
