INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'vanillasurvie', 'VanillaSurvie', 'VanillaSurvie - La survie à l''état pur !  
Un serveur Minecraft Towny au plus proche du Vanilla. Axé sur une survie hard et immersive avec des métiers, des magasins et un système de vies unique !  
  
Caractéristiques principales :  
🌍 Joue comme tu veux : Crée ta propre ville prospère avec Towny, ou choisis de jouer sans protection pour une expérience encore plus difficile. C''est toi qui décides !  
  
  
🤝 Interaction Joueur contre Joueur : Rencontre d''autres joueurs dans un environnement où la confiance est rare. Formes des alliances, créer votre commerce et fondez votre ville ou votre nation magnifique et pleine de vie.  
  
  
🗳️ Vote pour la vie : Tu commences avec 3 vies. Si tu perds toutes tes vies, tu devras attendre 30 minutes avant de pouvoir continuer ton aventure. Achète jusqu''à 6 vies par semaine avec tes points de vote et réduis ainsi le temps d''attente pour reprendre ton aventure sans interruption.  
  
  
🎉Soyez le héros de votre ville: En créant une nation magnifique et pleine de vie, préparez-vous à relever les défis de Minecraft et à vivre une aventure unique !  
  
Pourquoi nous rejoindre ?  
  
- Un serveur stable et optimisé, ouvert aux joueurs passionnés.  
- Une communauté chaleureuse et active, prête à accueillir les nouveaux venus.  
- Un administrateur à l''écoute pour garantir une expérience de jeu optimale.  
  
  
VanillaSurvie, c''est la survie à l''état PUR ! 🎮', 'play.vanillasurvie.fr', 25565, 'mc_java', 'active', true, NULL, 'https://vanillasurvie.fr', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'theseedmc', 'TheSeedMC', 'The Seed was created with one thing in mind - Minecraft. For the players that are looking for a server that has countless custom-coded features, The Seed isn''t for you. While we do have custom features, our goal is to keep The Seed simple and community-based for those that just want to play Minecraft with friends. So, here''s what we offer:  
  
Player Shops | Anybody and everybody is allowed to create their own shop  
Player Warps | Once you are a Nomad (play for one hour), you can create public warps  
User-Friendly Land Claiming | Protect your property with ease  
Rank promotions for playing on the server | Each Rank has it''s own upgrades  
Pets | Every player is able to tame their own pet by killing any animal with a lead  
Player-Driven Economy | The Seed sells a limited amount of items at it''s shop. Go buy and sell  
from other players!  
Friendly Community | Although we are a new server, we encourage our future players to be  
mature, respectful, and friendly!', 'mp.theseedmc.com', 25565, 'mc_java', 'active', true, NULL, 'https://theseedmc.com/', NULL) ON CONFLICT (slug) DO NOTHING;
