INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'wehavetrees', 'WeHaveTrees', '🌲 Welcome to WeHaveTrees – Survival with a Fresh Twist! 🌲  
  
