INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'craftvalley-survival-f-r-java-bedrock', '⭐CraftValley ⭐Survival für Java & Bedrock ❤️', 'Herzlich willkommen auf CraftValley  
Dein Minecraft-Abenteuer beginnt hier  
Liebe Minecraft-Freunde,  
habt ihr Lust auf ein spannendes Survival-Projekt, bei dem ihr eurer Kreativität freien Lauf lassen könnt? Dann seid ihr auf CraftValley genau richtig.  
Unser Server bietet euch ein abwechslungsreiches Minecraft-Erlebnis mit einer aktiven Community, einzigartigen Features und regelmäßigen Events. Dabei legen wir großen Wert auf ein freundliches Miteinander, Fairness und Spaß am Spiel. Ganz gleich, ob ihr noch am Anfang eurer Minecraft-Reise steht oder schon erfahrene Baumeister seid – bei uns findet jeder seinen Platz.  
  
Grundstücke & Schutz  
Sichert euch kostenlos euer eigenes Grundstück und schützt eure Bauwerke mit unserem Claim-System. Kein Griefing, kein Stress. Baut, was ihr möchtet – von der kleinen Hütte bis zur riesigen Stadt.  
  
Ingame-Handel & Shopping District  
Handelt mit anderen Spielern, tauscht Ressourcen oder startet euer eigenes Business im Shopping District. Unsere dynamische Wirtschaft fördert kreatives und strategisches Spiel.  
  
PvP-Arena  
Zeigt eure Fähigkeiten in unserer PvP-Arena. Messt euch mit anderen Spielern in spannenden Kämpfen – freiwillig und fair.  
  
Wöchentliche Events & Minispiele  
Bei uns ist immer etwas los. Freut euch auf abwechslungsreiche Events mit spannenden Minispielen wie:  
  
Waterrace  
Polo Loco  
Sticky Knockback  
Jump and Runs  
Eisbahnrennen  
  
Ihr habt die Chance, tolle Ingame-Preise zu gewinnen und gemeinsam mit der Community Spaß zu haben.  
  
Regelmäßige Updates  
Unser Team arbeitet kontinuierlich an neuen Inhalten, Features und Verbesserungen. Wir hören auf eure Vorschläge und entwickeln CraftValley stetig weiter.  
  
Community & Support  
Bei Fragen, Ideen oder Problemen steht euch unser freundliches Team jederzeit zur Seite. Über Discord könnt ihr einfach mit uns und der Community in Kontakt treten.  
  
Jetzt Teil von CraftValley werden  
CraftValley ist der perfekte Ort, um zu bauen, zu handeln, zu entdecken und gemeinsam Abenteuer zu erleben. Schließt neue Freundschaften, verwirklicht eure Ideen und werdet Teil einer wachsenden Welt.  
  
  
Server-IP: play.CraftValley.de  
Bedrock-IP: bedrock.craftvalley.de  
Port (Bedrock): 46410  
Discord: https://discord.gg/craftvalley  
Wir freuen uns darauf, euch auf dem Server begrüßen zu dürfen.  
Euer CraftValley-Team', 'play.craftvalley.de', 25565, 'mc_java', 'active', true, NULL, 'https://craftvalley.de/', NULL) ON CONFLICT (slug) DO NOTHING;
