INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'edgegamers', 'EdgeGamers', 'In a gaming world filled with chaos, EdgeGamers stands apart, offering a rare haven where honor, loyalty, and integrity thrive—creating a safe, family-friendly space for gamers from all walks of life to enjoy fair, fun, and respectful gameplay.  
  
Our Minecraft server offers one of the most thrilling quests—collect one of every item in the game! Along the way, you''ll earn crate keys as rewards for your progress, but only the most dedicated adventurers who complete the quest in full will receive special community recognition.  
  
Hardcore Factions (HCF) is a thrilling Minecraft multiplayer gamemode where players form factions to build, raid, and battle in a hardcore survival world, with death leading to temporary or permanent bans depending on the server. Players can adopt varied playstyles like trapping, ambushing enemies, farming (resource-focused base-building), or nomadic (roaming and scavenging), blending strategy, PvP, and survival. After our alpha phase a few weeks ago, we’re beyond excited to launch and welcome the eager community to this intense, high-stakes experience!', 'mine.edgegamers.com:25565', 25565, 'mc_java', 'active', true, NULL, 'https://edgegamers.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hazerot-network', 'Hazerot Network', 'Hazerot Network нь өмнө нь Exocraft нэрээр үйл ажиллагаагаа явуулж байсан туршлагатай сервер бөгөөд одоо шинэ нэр, шинэ өнгө төрхтэйгөөр дахин сэргэж байна.  
  
