INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'akumamc', 'AkumaMC', 'Experience the ultimate Minecraft adventure on AkumaMC, where thrills, challenges, and community collide! Dive into two epic gamemodes:  
  
