INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'gyrax-s-create-ultimate-selection-server', 'Gyrax''s Create Ultimate Selection Server', '🌟 Gyrax Servers – Create: Ultimate Selection  
