INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'smithtainment-minecraft', 'Smithtainment Minecraft', 'Smithtainment Gaming has been providing people with a place to call home online for over 10+ years! We take pride in creating a gaming environment that is accepting of everyone. If you are looking for a quality survival server to start a new adventure and meet new friends then look no further. We welcome you to Smithtainment Minecraft.  
  
The dev and building team for Smithtainment have worked extremely hard to put together a custom survival server that still has that vanilla-ish feel that players love. Each player likes to approach survival differently and whether you are a miner, farmer, or fighter there is always something to be doing. So join us and start a job or two and work your way up the ranks while surviving with your friends. Careful though we have heard from the villagers that the mines are exceptionally dangerous these days. While you are at it have a look around our spawn and talk with some of the villagers. Everyone has a story to tell can you unravel the secrets behind what happened in the past?  
  
  
Server IP  
mc.smithtainment.com  
(VERSION 1.21.4 JAVA EDITION)  
  
Discord  
discord.gg/smithtainment  
  
  
Server Info:  
★Vanilla-ish experience with quality of life features such as MCMMO, jobs, leveled mobs, a resource world, stacked mobs and spawners, server and player shops, player warps, ect... The server is also set to Hard mode.  
★When players die they are transported to the fairy and given the opportunity to buy back their items that they lost on death.  
★Commands such as /rtp, /home, /sethome, /resourcetp, /warps, /cosmetics, /tags, /wraps, etc...  
★Custom decor and furniture to decorate any kind of build with!  
★Playtime ranks that unlock more and more perks for players depending on the time spent playing on the server.  
★A balanced in-game shop economy as well as an auction house for players and chest shop for a more player driven economy.  
★A well designed custom spawn with a PvP arena below it.  
★Custom enderdragon fights. Team up to take her down!  
★A welcoming community that provides help to new players if needed.  
★Donators that aren''t OP and have no crazy advantage over regular players.  
★Crates with custom cosmetics for your weapons and armor and chat tags that regularly change depending on the season. Collect them all!  
★24/7 server stability. No lag or random crashes. An active staff team.  
★Block claims and grief prevention. Griefing is also not allowed.  
★Vote Rewards & More!', 'mc.smithtainment.com', 25565, 'mc_java', 'active', true, NULL, 'https://forums.smithtainment.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'null-network-seliana-reborn', 'Null Network: Seliana Reborn', 'Are you ready to leave a mark in our history?  
  
Server was just re-released! It is now YOUR time to make a mark on history!  
  
Null Network: Seliana is an rpg survival server that focuses more on a unique experience. The server emphasizes on RPG elements, and a medieval feel. Currently, we are mostly a filipino playerbase, but we also have some players around the world, mostly in asia! We have a ton of appealing features that will get you hooked!  
  
Weapons for every style of combat! Be it hard hitting Greatsword, fast hitting Daggers, and more! You can also put gems to enhance them! All of this without mods!   
  
Fierce monsters that will keep you on your toes! This isn''t your typical survival server! Bosses and other special mobs spawn!  
  
And much much more! Join us, make new friends, and have a good time! If you need a link in the discord, type in /discord in game!', 'play.null-network.com:25565', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
