INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'sparkmc', 'SparkMC', 'Welcome to SparkMC, the world where your journey begins! Join our friendly place where you can meet new adventurers! Explore the new world, find unique places and complete quests for rewards. Place where you can create your own faction and invite your friends to join you and fight to be the number one! With lag-free gameplay, awesome events, and regular updates, there''s always something exciting to do! So grab your staff and start your adventure!  
  
