INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bud-smp', 'BUD SMP', '🏛️ Bud SMP – Building Focused SMP  
IP: bud.apexmc.co (Java & Bedrock)  
Bedrock Port: 1388  
Discord: https://discord.gg/4gEmr7d3v4  
  
Bud SMP is a laid-back, build-focused survival server powered by Towny. Each season features a new theme—this one is colonial New England. Join our main town, help expand it, or start your own from scratch. We focus on creativity, cooperation, and chill vibes.  
  
🧱 Features This Season:  
  
🏘️ Join an existing town or found your own with Towny  
  
✈️ Flight Charges – fly while building, purchasable with XP or in-game money  
  
🛒 Custom Shopkeepers – set up and run your own stores  
  
🔮 Advanced Enchantments – 200+ unique enchants  
  
🧪 Magic Plugin – optional spells and abilities  
  
💼 Jobs – earn cash passively as you play  
  
Creative world access available by request after active play.  
  
🎯 Best For Players Who Want:  
  
A relaxed survival experience focused on building and towns  
  
Themed seasonal content without strict restrictions  
  
Useful plugins that don’t overwhelm the core gameplay  
  
A friendly, crossplay-compatible community  
  
🎮 Java & Bedrock Compatible  
No whitelist. Just hop in and start building.', 'bud.apexmc.co:1388', 25565, 'mc_java', 'active', true, NULL, 'http://woahderbud.com', NULL) ON CONFLICT (slug) DO NOTHING;
