INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minimc', 'MiniMC', 'MiniMC - Awakening is a unique twist on classic Survival, blending deep RPG progression with stunning fantasy world design. At its core, MiniMC solves the "boring endgame" problem by introducing vertical progression—offering challenges that go far beyond just getting Netherite gear.  
  
