INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'stigma-cobblemon', 'Stigma cobblemon', '**🌌 Welcome to Stigma Cobblemon**  
  
Join right away a **welcoming, fun, and strong community**!  
Discover the **Stigma Cobblemon** server and begin a **brand new, one-of-a-kind adventure**.  
  
**📖 The Story**  
  
_In an unknown dimension, a peculiar egg hatched…  
Stigma Eternatus was born.  
  
When it awakened, its shriek mutated rare and powerful Pokémon —  
the ones we only hear about in stories and myths._  
  
**🎯 Your Objective**  
  
Your final goal is simple:  
  
• **Defeat them all**   
• **Catch them all**  
  
The choice is yours. **Forge your own destiny.**  
  
**🧬 A Unique Pokémon Experience**  
  
Discover **new Pokémon** and **exclusive forms** created especially for the server.  
They will **shape your adventure** and bring completely new strategies and discoveries.  
  
Explore the world of **Stigma Pixelmon** , filled with:  
  
• **Side quests**   
• **Server activities**   
• **Unique exploration**  
  
**🏆 Events & Challenges**  
  
Take part in **regular server events** , including:  
  
• **Ultimate Hunts**   
• **Tournaments**   
• **Special challenges**  
  
These events will appear **throughout your journey** and give you new opportunities to prove your strength.  
  
**✨ Your adventure begins now.**  
  
Will you become the one who **defeats the legends** …   
or the one who **captures them**?  
  
_**The server includes features like these:**_  
  
We are running the server with **all official Pokémon** and **200+ Fakemon**.  
  
**All Legendaries can be summoned** using special items found in **structures or activities**.  
  
All battle **gimmicks are enabled** :  
**Mega Evolutions, Z-Moves, Dynamax, and Teracristallization.**  
  
All **structure chests are instanced** , meaning **every player gets their own loot**.  
  
Monsters spawn **rarely** , but the **difficulty is normal/medium**.  
  
The **economy is entirely player-driven**.  
Sell your Pokémon or items through the **GTS** , or **create your own shop**.  
  
**Pokédex rewards** are granted every **5% completion**.  
Each milestone gives **lifetime kits, nickname tags, and more**.  
  
Take part in **CobbleHunt** : hunt Pokémon with other players and **claim rewards together**.  
  
Explore the wilderness and find **Raids** , where multiple players can challenge **Pokémon bosses**.  
  
Raid difficulty goes up to **7★** — extremely difficult, but **almost always Legendary encounters**.  
  
Discover **many new biomes** and experience Minecraft in a completely new way.  
  
When you **release a Pokémon** , the **server automatically buys it from you**.  
  
Use **special chests and backpacks** to store everything you need **in your base and your inventory**.  
  
Enjoy a **dynamic musical system** : nostalgic music inspired by the **Nintendo DS era** , playing **per biome and during battles**.  
  
Most modern battle themes have been **ported into the Pokémon Black & White style**, along with **original compositions**.  
  
Battle with an **enhanced UI and improved summary screens** , including many **quality-of-life upgrades**.  
  
Challenge the **Battle Tower** with multiple modes:  
**Solo, Duo, Trio, and Boss Battles** — playable **alone or in co-op (up to 3 players)**.  
  
The **End dimension has been completely reworked**.  
Rediscover it with **unique terrain and no more repetitive islands**.  
  
Sometimes, a **wormhole will appear near you**.  
Enter it to explore a **mysterious area**.  
  
**The first 100 players to join the server will receive an additional reward on top of the welcome reward.**  
  
If enough players are active during the first week, a **tournament will be organized within the month**.  
  
And… rumors say that a **mysterious Pokémon may make a special appearance.**  
  
_**Join our community!**_  
  
**Discord:** https://discord.gg/CwsGQGgjd9', 'stigmacobblemon.craft.gg', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/CwsGQGgjd9', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'betelgeuse-studios', 'BETELGEUSE STUDIOS', '🌌 BETELGEUSE STUDIOS NETWORK - SURVIVAL CUSTOM [1.21.1+]  
