INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'alstroe-craft', 'Alstroe Craft', 'Alstroe Craft is a survival Minecraft server dedicated to providing every player with the best possible gameplay experience. The name of this server is derived from the Alstroemeria flower, which stands for loyalty and friendship. Our goal all along is to establish a community where people can socialize, compete, and most importantly, make new friends from all around the world.', 'play.alstroecraft.org', 25565, 'mc_java', 'active', true, NULL, 'http://alstroecraft.org', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cobble-cove', 'Cobble Cove', '📌NEW SERVER!🌴Cobble Cove🌊no modpack required, our server is fully server side!  
  
❓Why should I play Cobble Cove?  
- All of our Purchasable Perks and Ranks are also able to be bought in-game with our free to earn Gems Currency!  
- Our economy is driven and powered by our Players, creating a fun, community based experience.  
- Plenty of fun things to do and participate in like Tournaments, Build Competitions, Breeding, Raids, and more.  
- We have a MAJORITY of the missing Cobblemon Models implemented on our Server!  
- Friendly, Welcoming, and Helpful Community  
- CUSTOM Legendary Spawning System  
- Discord & Minecraft Chat Bridge So you can always see what''s going on  
  
⚔️Pokemon Raids  
Battle against rare Pokémon in a community raid every 2 hours! and get a chance to capture the Pokémon, and various rewards!  
  
📈Pokedex Ranks  
LEVEL UP and strive to capture them all, gaining all kinds of rewards including money, tags, master balls, legendaries, and more...  
  
🏡Breeding  
Breed better IV, Shiny, Missing, or Stronger Pokémon to sell or keep for your team!  
  
🪓Bosses  
Randomly encounter bosses in the wild and defeat them for big rewards!  
  
Other Features  
🌎Player Driven Economy  
💰In-game stores to make building and progression easier!  
✉️Voting for Daily rewards!  
🪙Free daily kit, and reward to help you get started!  
🛒GTS & STS  
🤝Every command, perk, and key is purchasable with in-game currency to ensure a fair experience!  
🫂Casual, Friendly Community  
  
More features will be added and changes will be made from player feedback! We take player suggestions seriously.  
Discord: https://discord.com/invite/NBZUV95whH  
Store: https://cobblecove.net  
IP: cobblecove.net', 'cobblecove.net', 25565, 'mc_java', 'active', true, NULL, 'https://shop.cobblecove.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'coolmc', 'CoolMC', 'CoolMC is a Minecraft Survival and BoxPvP server network from India and Singapore. It has lots of cool and exciting features to experience, like PvP, vote rewards, events, and giveaways! Join CoolMC''s Discord today and learn all about it, from news and support to the server''s rules and more! [IP: play.coolmc.fun | Port: 19132]', 'play.coolmc.fun:19132', 25565, 'mc_java', 'active', true, NULL, 'https://discord.gg/VY4AZkWFd5', NULL) ON CONFLICT (slug) DO NOTHING;
