INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'amethyst-community', 'Amethyst Community', 'Welcome to Amethyst Community, one of Sri Lanka''s finest Minecraft servers! We are always trying to give players an unforgettable experience that goes beyond standard vanilla gameplay.  
  
Our server includes custom world generation and custom weapons and equipment, all designed to provide an engaging RPG experience unlike any other in the region. We have a pleasant staff available 24/7 to assist you with your experience. Whether you''re fighting Dungeon bosses or interacting with our unique economy system, there''s something for everyone.  
  
We also provide full support for both Java and Bedrock players on versions 1.16.5 to 1.21.10!  
New Tricky trial update!! Custom world generation Hard mode survival, RPG experience. Shop and auction house Bank system Ranks 24/7 active staff Bedrock Support!!  
  
Server IP: mc.amethystcommunity.net  
Join us today and dive into a whole new Minecraft adventure!  
  
Discord - https://discord.amethystcommunity.net  
Website - https://www.amethystcommunity.net  
Facebook - https://www.facebook.com/amethystcommunity/  
