INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'wondercraft', 'Wondercraft', '🌟 Welcome to Wondercraft SMP, the ultimate Minecraft wonderland with a plethora of thrilling features that will keep you hooked for hours on end! 🌍  
  
