INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'survivorsmp-net', 'SurvivorSMP.net', 'Dive into the thrilling world of SurvivorSMP, a dynamic Minecraft multiplayer experience where creativity, resilience, and adventure come together. Set in a vast and untamed realm, SurvivorSMP challenges you to survive, build, and thrive in a world teeming with opportunities and surprises.  
  
From humble beginnings to epic builds, every block you place and every path you forge adds to your unique story. Whether you''re a seasoned Minecraft veteran or just starting your journey, SurvivorSMP offers a rich, immersive environment designed to push your skills and spark your imagination. Construct towering fortresses, hidden mountain bases, or sprawling villages — or team up with others to conquer dungeons, complete quests, and overcome the wild challenges of the world around you.  
  
Our dedicated staff works tirelessly to ensure a smooth, fair, and welcoming experience for everyone. With a strong focus on community, you''ll find vibrant discussions, helpful allies, and friendly competition as you work together — or forge your own path — in a world that''s constantly growing and evolving.  
  
SurvivorSMP features regular updates, custom events, and an ever-changing landscape that guarantees no two adventures are ever the same. Whether you''re exploring the deepest caves, trading rare goods, or building your dream home in the wilderness, every moment is part of your legacy.  
  
So grab your pickaxe, don your armor, and step into the world of SurvivorSMP, where your survival story is waiting to be written — one block at a time.  
  
Have a question? email support@survivorsmp.net', 'survivorsmp.net:25565', 25565, 'mc_java', 'active', true, NULL, 'https://store.survivorsmp.net', NULL) ON CONFLICT (slug) DO NOTHING;
