INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'solaria-network', 'Solaria Network', 'Welcome to our network! We currently offer 2 different gameplays!  
