INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'bee-sim', 'Bee Sim', 'Raise your own swarm of bees and become the ultimate beekeeper!  
  
Start your journey with a single loyal bee and begin collecting pollen from vibrant fields filled with flowers of every shape and color. Use the pollen to craft sweet, golden honey — your primary resource to unlock a whole world of buzzing possibilities!  
  
As your honey reserves grow, so does your potential. Unlock new types of bee*, each with their own **unique traits, colors, rarities, and personalities. Some bees are swift and nimble, zipping from flower to flower with incredible speed, while others are strong and mighty, capable of defending the hive from looming threats.  
  
Upgrade your gear to become the best pollen harvester in the land! Choose from a wide variety of collectors, backpacks, and boosters to enhance your harvesting abilities. Want to gather pollen in huge quantities? Equip an industrial vacuum! Prefer to target rare pollen? Use precision tools designed for the job.  
  
Along the way, you’ll meet a variety of friendly bears, each with their own distinct personality and quests to offer. Complete these challenging tasks to earn valuable rewards, from rare bees to unique equipment and powerful boosters that will skyrocket your hive’s productivity.  
  
Climb higher up the mountain to uncover new and mysterious zones, each more challenging and rewarding than the last. Explore lush bamboo forests, icy peaks, enchanted caves, and ancient ruins — all filled with secrets, treasures, and hidden challenges, for only the bravest beekeepers to uncover.  
  
But beware — the journey isn’t all sunshine and daisies. Your bees will need to stand strong against the **dangerous bugs and creatures** that inhabit the mountain, from pesky ladybugs and aggressive rhino beetles to massive mantises and terrifying **GIANT werewolves**.  
  
As you progress, you’ll discover the ability to customise your hive’s strategy by specialising in a particular pollen color — red, blue, or white — creating powerful synergies between your bees and equipment. Each strategy unlocks different perks, bonuses, and advanced mechanics to suit your playstyle.  
  
Master the art of beekeeping, uncover the secrets of the mountain, and build the strongest swarm the world has ever seen. Adventure, discovery, and sweet, golden honey await — are you ready to begin your buzzing journey?', 'play.beesim.gg', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minecory-skyblock', 'Minecory - SkyBlock', '✨ About This Server  
