INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'wiolent-survival-1-21-4', 'Wiolent Survival 1.21.4', 'Eşsiz survival deneyimi yaşamak ister misin? Haydi gel seni bekliyoruz :)  
  
Sistemler​  
Süreli Claim ve Ulus Sistemi  
Arazini belirli süreliğine koruma altına alabilir, kendi ulusunu kurabilir, diğer uluslara savaş ilan edebilir veya müttefik olabilirsin. Süresi dolmadan claim yenileyerek  
korumana devam et.  
  
Özel Büyüler  
34 adet özel büyümüz ile farklılık zamanı! Bu büyüleri büyü masasından çıkarabilir veya XP karşılığında alabilirsin. Ancak dikkat, büyüleri basarken başarı olasılığı vardır.  
  
Seviyeli Zindan Sistemi  
Seviyene uygun zindana girerek yaratıkları alt et ve özel görünümlü parçacıklar kazan. Bu parçacıklar ile sırt çantanı geliştirebilir, efsanevi WioMag Zırhı kuşanabilir, yeni arazi hakları alabilir, arazini genişletebilir, farklı dünyalara geçiş yapabilir ve parçacıklarını dönüştürerek ihtiyaç duyduğun eşyalara ulaşabilirsin.  
  
Seviyeli Spawner Sistemi  
Spawnerlarını sağ tıklayarak XP karşılığında menzilini artırabilir, doğma süresini kısaltabilir ve doğan canavar sayısını çoğaltabilirsin.  
  
Spawner Yetki Sistemi  
Spawnerleri kırabilmek ve envanterine ekleyebilmek için Sihirli Dokunuş yetkisine sahip olman gerekir. Bu yetki, parçacıklar ile satın alınabilir ve en az 4 saatlik oyun süresi şartı vardır. Spawnerleri taşımak veya farklı konumlara yerleştirmek için bu yetki zorunludur.  
  
Özel Etkinlikler  
WioMag Canavarı etkinliğinde bu güçlü yaratığı yenerek içinden spawner parçacıkları elde edebilirsin. Topladığın parçacıklar ile spawner sahibi olabilirsin. Ayrıca balık etkinliğinde en uzun balığı tutarak ödüller kazanabilirsin.  
  
Satış Çubuğu Sistemi  
Sandık içindeki tüm satılabilir eşyaları tek tıkla satmanı sağlar. Parçacıklar ile elde edilir, satış çarpanı özelliği bulunur. Demir, Altın ve yalnızca mağazadan alınabilen özel Elmas satış çubuğu seviyeleri vardır.  
  
Yetenek Sistemi  
15’ten fazla yetenek ile istatistiklerini geliştirip güçlü vuruş, hızlı kırma, hızlı koşma gibi özel yetenekler kazanabilirsin.  
  
Gelişmiş Günlük Ödül  
Meslekler  
Takas Sistemi  
Sırt Çantası  
Müzayede Sistemi  
Oyuncu Pazarı  
  
Daha fazlası için ziyaret et!', 'play.wiolent.com', 25565, 'mc_java', 'active', true, NULL, 'https://wiolent.com/', NULL) ON CONFLICT (slug) DO NOTHING;
