INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'blithe', 'Blithe', 'We are a Whitelisted semi-vanilla survival server enhanced with; an armor-stand editor, proximity chat, mini-blocks, and other plugins that give players the closest gameplay experiences to that of Hermitcraft. Most other plugins used are for moderation and lag efficiency like Core Protect which helps keep our community a safe and friendly place this means there are no plugins that drastically alter the vanilla experience such as; /landclaim, /sethome, or /tpask /tpahere.  
  
