INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'all-outta-blocks', 'All Outta Blocks', 'All Outta Blocks is a welcoming, laid-back Survival SMP built for players who love creativity, collaboration, and good vibes. Whether you’re grinding out big builds, setting up clever farms, or just hanging out and laughing with friends, this server is all about enjoying Minecraft the way it’s meant to be played.  
  
