INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'gravemc', 'GraveMC', 'Hey there adventurer,  
Welcome to GraveMC Network – not just another Minecraft server. We’re a small team (just the two of us) who’ve been building this place out of pure passion since 2020.  
  
