INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'dragonmc', 'DragonMC', 'DragonMC is a vibrant Minecraft server built for every kind of player – whether you love the thrill of combat or prefer a peaceful journey. We proudly host a variety of exciting game modes to keep you entertained:  
  
