INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'play-majesticmc-net', 'play.majesticMC.net', 'MajesticMC is a Minecraft server featuring Survival and PVP in the PVP Arena, which you can easily switch between.   
