INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'pvpgym', 'PvPGym', 'Welcome to PvPGym! We have been the most competitive PvP server on the market since our release in September 2020. We support 1.7-1.21, including cracked clients, and the gamemodes we offer are Practice, SGCW, UHC, and Meetup. Now, what makes us stand out among competitors?  
  
🎮 Quality Gameplay  
Our Practice features 1v1 & 2v2 Ranked queues and leaderboards with a balanced Global ranked kit selection not favoring a particular playstyle as well as 25+ unique kits fine-tuned for competitive play. Our maps are highly optimized and resemble the original terrain of their gamemode to provide a realistic experience.  
  
⚔️ Optimized PvP  
We optimized our knockback, hit detection, pots, rods, and damage to provide a smooth experience while also fixing lava/water glitches and preventing running while eating.  
  
⌨️ ELO Recalculation  
This system automatically refunds ELO points lost to cheaters or due to other unfair circumstances.  
  
⚖️ Fair Play  
Any rule breakers are either automatically detected by our solid AntiCheat or caught by our staff team through effective moderation and screen sharing to ensure fair and cheater-free gameplay. Read our rules to avoid getting banned.  
  
🏆 Hosted Tournaments  
Next to our highly customizable tournament hosting system available to Muscleman ranks, we organize official tournaments with prizes, stats, and leaderboards every weekend.', 'pvpgym.net', 25565, 'mc_java', 'active', true, NULL, 'https://pvpgym.net', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minepiece', 'Minepiece', '🏴‍☠️ Set sail in Minepiece and join an epic One Piece-inspired MMORPG adventure !   
No mods needed, just pure adventure. Eat Devil Fruits, build your crew, conquer islands, and become a legend.  
  
