version 1.21.4!', 'mp.minepiece.net', 25565, 'mc_java', 'active', true, NULL, 'https://minepiece.net/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'nightshadesmp', 'NightshadeSMP', 'Welcome to Nightshade SMP!  
  
NightshadeSMP is a pure vanilla Minecraft server with a focus on relaxed, collaborative gameplay. We''re a small, welcoming community that enjoys Minecraft the way it was meant to be played—no pay-to-win, no unnecessary plugins, just a respectful space to build, explore, and have fun together.  
  
New Season begins June 14th!  
A fresh world awaits.  
Join us as we return to our roots - pure survival, community-driven gameplay.  
  
How to join:  
  
Option 1  
Visit our website and fill out a fast application Here﻿: https://nightshadesmp.net/#whitelist  
  
Option 2﻿  
Complete our application on our Discord server.  
Once submitted, we''ll notify you when you''ve been accepted.  
  
Discord: https://discord.gg/ehBa4hkTwD  
  
Features:  
  
📅 Date Current World Generated: 06-14-2025  
  
⏳ Seasonal worlds: Similar to HermitCraft, our world evolves naturally with seasons resetting only when the community decides.  
  
🗺️ Server Map: https://map.nightshadesmp.net  
  
🎙️ Proximity Chat: An optional mod that allows voice chat with nearby players, creating more immersive and natural in-game interactions  
  
🛡️ Grief prevention: Anyone can view block history and check interactions, ensuring nothing is griefed or stolen. Griefing can be rolled back fast by the staff.  
  
🌱 Pure Vanilla Experience: No plugins or mods that alter core gameplay - just Minecraft as it was meant to be played.  
  
No /TPA /SPAWN /WARP (only player-made forms of transportation)  
No land claim  
No locked chests', '127.0.0.1', 25565, 'mc_java', 'active', true, NULL, 'https://nightshadesmp.net/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'cosmopolitan-club', 'Cosmopolitan Club', 'Cosmopolitan Club is a simple survival server made for girls by girls. It''s quite close to vanilla though we let you set homes, teleport to other players and claim land.   
