INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'onesmp', 'OneSMP', 'Welcome to OneSMP!  
A World Worth Returning to. Est. Jan 2025  
  
Explore a clean, fair world with minimal restrictions. PvP is toggleable, allowing players to forge alliances, compete, or play solo at their own pace in a respectful, community-driven environment where friendships and rivalries grow naturally.  
  
OneSMP is designed for a mature audience. All players are expected to behave respectfully, use appropriate language, and contribute positively to the community.  
  
🌍 Persistent Survival  
A long-term survival world with backups, built for players who want their progress to last.  
✨ Server Modpack  
Optional Modrinth pack for Java that improves performance and polish while keeping the vanilla feel.  
⚒️ Player-Only Economy  
A player-driven economy designed around trust, trading, and real player value, not artificial systems.  
🛡️ Community-Driven  
GriefPrevention, Simple Voice Chat, and feedback-shaped development keep the server fair and fun.  
🤝 Tight-Knit Community  
OneSMP is actively developed with feedback from a small but thoughtful player base. Your ideas help shape the server!  
  
Java & Bedrock crossplay supported.  
Join us and help build a world worth coming back to!', 'play.onesmp.us:25565', 25565, 'mc_java', 'active', true, NULL, 'https://onesmp.us/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minejutsu', 'Minejutsu', 'Minejutsu is a 1.21+ survival multiplayer server with custom resource packs, custom armour, and a friendly community. It features monthly updates and unique features that other servers don''t offer. Join now and try it out on either Minecraft Java or Minecraft Bedrock at play.minejutsu.net!', 'play.minejutsu.net', 25565, 'mc_java', 'active', true, NULL, 'https://store.minejutsu.net/', NULL) ON CONFLICT (slug) DO NOTHING;
