INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'wildmare-minecraft-server', 'WildMare | Minecraft Server', 'Selamat datang di WildMare, dunia survival yang seru dan penuh inovasi!  
