INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'sasquatch-mc', 'Sasquatch MC', 'Welcome to Sasquatch MC!  
  
What makes Sasquatch MC unique? We have a ton of custom items that you can use to become the richest player on the server. You may betray, murder, and grief for as long as you want.  
  
On this server you can strategically choose which of the hundreds of different custom items you like most, since each one has their own use. You can find custom items in the servers custom item shop, trading with players, or completing the servers various dungeons. You can use these custom items to wage massive wars, grind to become the richest, or just to make your life easier. Here are a few examples of some of the best custom items.  
  
Anvil Cannon  
- Crafting recipe in the recipe book custom item  
- Shoots a falling anvil at a player  
- 15 second cooldown  
This item is extremely op, since you need a steel ball in the crafting recipe which is a 1 in 100 chance custom item from the hourly crate.  
  
Trench pickaxe  
- Five tiers  
- Mines in 3x3, but the amount it mines gets bigger with each tier.  
- Upgradable in recipe book.  
This is one of the best pickaxes in the game, as you can use it to mine a lot of blocks at any time. This allows you to optimize your mining greatly.  
  
Oil Goliath armor  
- Improves strength  
- Improves entity interaction range  
- Improves step height  
This armor is great for builders, pvpers, and grinders. Its literally one of the best armor sets on Sasquatch MC.  
  
The other thing that my server has that is very unique is chest shops. Chest shops are like player shops, where people can sell items, without their items being stolen. This is really good for a semi anarchy server like Sasquatch MC.  
There are already several successful chest shops around spawn.', 'Imnahha.games:25586', 25565, 'mc_java', 'active', true, NULL, 'https://www.imnahha.games', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'vaulted-vanilla', 'Vaulted Vanilla', 'Welcome to Vaulted Vanilla!  
  
Vaulted Vanilla is a Minecraft SMP that mixes the feel of modded gameplay with the simplicity of vanilla. Featuring overhauled terrain generation, action-packed structures, quality-of-life plugins, and carefully chosen data packs, we aim to keep survival fresh and exciting.  
  
We''re a new community, so your feedback means a lot—let’s build something awesome together!  
  
Version: 1.21+  
Crossplay: Enabled  
  
Features:  
- Proximity Voice Chat  
- Waystones  
- Overhauled Dimensions (Terralith)  
- Massive Structures  
- Custom Items  
- Like Modded, but Vanilla!  
- Economy & Fishing  
- SlimeFun4  
- No Claims!  
  
Discord: https://discord.gg/bStUBPKYbu', 'vaultedvanilla.org', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'pengartys-classic-prison', 'Pengartys Classic Prison', 'Looking for a classic/old school prison server? You''ve come to the right place!  
  
There seems to be a lack of old school type prison servers in the modern day game. We want to bring back that original classic Minecraft prison server feel with our server. No pay-to-win, no resets and a big grind.  
  
Our map was made with PvPing and lots of player interactions at its core. All areas of the prison are closely near each other so no matter what you do there will be people around.  
  
This is a newly created server so there might be bugs and unfinished features, but we plan to have it feel flawless and enjoyable when its complete.  
  
Community feedback is appreciated and all ideas/complaints will be taken into account and acted upon.  
  
We will be needing staff/guards to help out on the server. There will be an official way to apply for these positions in the near future.  
  
Our Server IP: mc.pengarty.com', 'prison.pengarty.com', 25565, 'mc_java', 'active', true, NULL, NULL, NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'fademc', 'FadeMC', 'Welcome to FadeMC, the ultimate never-resetting, no-griefing, keep-inventory Minecraft survival experience! Whether you''re a seasoned player or a newcomer, FadeMC offers a fun semi-vanilla environment that stays true to the game''s roots. Build epic structures, form alliances with fellow adventurers, and fend off mobs as you carve out your legacy. Join us on FadeMC, where the journey is yours to shape, and every block tells a story. Ready your pickaxe, and let the adventure begin!', 'mp.fademc.xyz', 25565, 'mc_java', 'active', true, NULL, 'https://fademc.xyz', NULL) ON CONFLICT (slug) DO NOTHING;
