INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minestone', 'MineStone', 'MineStone được xây dựng theo phong cách cổ điển kết hợp hiện đại, mang lại trải nghiệm dễ nhìn, không rối mắt, phù hợp với người chơi mới nhờ hệ thống dễ làm quen, đồng thời giúp người chơi cũ tìm lại những kỉ niệm Minecraft mà vẫn có các tính năng hiện đại để vẫn cảm nhận được sự mới mẻ.  
  
