INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'lemoncraft-smp', 'LemonCraft SMP', '🌿 Survival SMP (Chill or Competitive — Your Choice)  
  
