INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'misty-pines-smp', 'Misty Pines SMP', 'Welcome to Misty Pines SMP  
  
Are you ready to embark on a Minecraft adventure unlike any other?  
Misty Pines SMP is a national park-inspired survival server that blends exploration, creativity, and community into a rich, immersive experience.  
  
Explore a World Reimagined  
Venture into a breathtaking Overworld shaped by custom biomes and world generation. From towering mountains to lush valleys, every corner of Misty Pines is crafted for exploration.  
All dimensions — including the Nether and the End — have been fully reimagined, offering brand-new challenges and secrets to uncover.  
  
Enhanced Gameplay Features  
  
Travel with Ease: Set multiple home warps, send teleport requests, or use /wild to explore new land  
  
Player Warps: One free warp to show off your base, shop, or secret lair  
  
Land Claims: Protect your builds and belongings with simple claiming tools  
  
Custom Fishing: Experience deeper progression with new mechanics and rare treasures  
  
Custom Enchantments: Enhance your gear with powerful, unique effects  
  
Custom Nicknames: Express yourself and stand out in chat  
  
Player Economy: Buy, sell, and trade in a thriving marketplace  
  
Decorative Heads: Add detail and flair to your builds with an expansive head library  
  
Tree Feller and Vein Miner Tool: Chop down trees and ores efficiently with ease  
  
A Community That Grows With You  
Whether you''re a master builder, a solo adventurer, or a savvy shopkeeper, Misty Pines welcomes everyone. We believe in giving players the tools to collaborate, create, and thrive in a shared world.  
  
Begin Your Journey  
IP Address: mistypines.playit.plus  
Join us today and start your adventure in the wild, wonderful world of Misty Pines SMP.  
What will you discover first?', 'mistypines.playit.plus', 25565, 'mc_java', 'active', true, NULL, 'https://www.misty-pines.com', NULL) ON CONFLICT (slug) DO NOTHING;
