INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'minecraft-survival-smp-deutscher-community-server', 'Minecraft Survival SMP – Deutscher Community-Server', 'Willkommen auf MinecraftSMP.de – deinem deutschen Survival SMP Server!  
  
Du suchst einen aktiven, deutschen Minecraft Server mit spannenden Features und einer freundlichen Community? Dann bist du bei uns genau richtig!  
  
MinecraftSMP.de ist ein moderner Survival SMP Server aus Deutschland, der auf der neuesten Minecraft-Version (aktuell 1.20.4) läuft – ältere Versionen werden ebenfalls unterstützt.  
Egal ob du in Ruhe bauen, gemeinsam mit Freunden überleben oder dich in PvP-Schlachten beweisen willst – bei uns findest du dein Zuhause.  
  
Unser Server bietet dir:  
  
Ein engagiertes, hilfsbereites Serverteam  
  
Survival, PvP und OneBlock-Modi  
  
Aktive deutsche Community  
  
Regelmäßige Updates & Events  
  
Fairer Freebuild ohne Pay-to-Win  
  
Wir möchten für jeden Spielstil etwas bieten – sei es entspanntes Bauen wie bei Craft Attack, intensives Survival wie auf einem klassischen SMP Server, oder einfach gemeinsames Zocken mit netten Leuten.  
  
Jetzt beitreten und Teil unserer wachsenden Community werden!', 'minecraftsmp.de', 25565, 'mc_java', 'active', true, NULL, 'http://discord.minecraftsmp.de', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'crow-smp', 'Crow SMP', 'If ur looking for a drama free/non toxic place to play Minecraft and hang out. We are looking for u! We are seeking players. I currently have a really small player base with hopes of a big future! Would love to see some new faces and make some friends. Now seeking players. I am cross-play. We are on 1.21.11 Keep inventory is on.  
