INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'hallowed-fantasy-cobblemon', 'Hallowed Fantasy Cobblemon', 'Hallowed Fantasy Cobblemon features a custom region to explore with a wide roster of Regional Forms, NPC & Player-run Gyms, a resource world to gather materials, and so much more!  
  
Come check us out to experience these features:  
  
NEARLY COMPLETE POKEDEX - We have almost every Pokemon modeled, including EVERY Legendary Pokemon! Only 9 non-Legendaries are missing currently.  
  
Custom ever-updating Fantasy Region - Our team has hand-crafted a Pokemon region worth exploring! Builds are constantly being updated with new designs and things to look out for.  
  
Fantasy Forms - Our team focuses on creating Fantasy Regional Forms that are not only amazing to look at, but also useful in competitive battles!   
  
Player-run & NPC Gyms - Try out your Fantasy Forms against our 8 competitive-tier Player-run/dual-typed Gyms and/or against our Pokemon game-style NPC Gyms + Elite 4!  
  
Custom Trainer Levels System - Exclusive to Hallowed Fantasy is a system where you can level up your Trainer Level by defeating/catching Pokemon to earn great rewards!  
  
Separate Player & Resource Worlds - Our server splits the player world & resource world into two, so you can claim land in one world and mine for diamonds, cut trees, and find whatever you need in another! Freely swap between them with /rtp.  
  
ALL Mega Evolutions available along with Terrastralization & Dynamax!  
  
Pokemon Outbreaks - Every 30 minutes, a random Pokemon will have a Mass Outbreak on a random player! 25 of the same Pokemon will spawn with boosted SHINY & IV rates!', 'play.hallowedfantasy.com', 25565, 'mc_java', 'active', true, NULL, 'https://hallowedfantasy.com', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'portalcraft', 'PortalCraft', 'Welcome to PortalCraft, where the boundaries of Minecraft are shattered. Embark on epic adventures through dimensional portals, conquer formidable bosses, and uncover the mysteries of the multiverse. Be among the first to shape the future of this expanding realm!', 'portalcraft.csrv.gg:25565', 25565, 'mc_java', 'active', true, NULL, 'https://linktr.ee/portalcraft', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'neo-survival', 'Neo Survival', '[Java/Bedrock] [1.21.4+ SMP]  
  
DISCORD: discord.gg/neosurvival  
WEBSTORE: store.neosurvival.fun  
JAVA IP: play.neosurvival.fun  
  
Neo Survival is a brand new SMP survival server built with community, creativity, and comfort in mind. Whether you are a builder, adventurer, or casual player, there is something for everyone to enjoy.  
  
- Custom World Generation – Explore beautiful, hand-crafted terrain and unique custom structures scattered across the world.  
- Adorable Custom Pets – Unlock and collect cute companions to follow you on your journey.  
- Rankup System – The more you play, the higher you rank, just like in Valorant or Fortnite.  
- Cosmetics and Furniture – Customize your character and builds with a variety of fun unlockable content.  
- Land Claiming – Protect your builds and stay safe from griefers. Your space is your space.  
- Custom Items and Gear – Discover new tools, weapons, and armor that enhance your survival experience.  
