INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'pkstuff-de', 'pkstuff.de', 'WILLKOMMEN AUF PKSTUFF.DE – DEIN MINECRAFT. DEIN WEG.  
Du suchst keinen weiteren Server mit langweiligen Standardfunktionen, sondern ein Erlebnis, das dich wirklich abholt? Dann bist du auf pkstuff.de genau richtig.  
Wir bieten dir zwei komplett individuell entwickelte Spielmodi, die Minecraft auf ein neues Level heben. Keine Plugins von der Stange, sondern durchdachte Systeme, aktive Entwicklung und Spieltiefe.  
  
CITYBUILD – SYSTEME MIT NIVEAU UND TECHNIK  
Unser Citybuild ist weit mehr als das übliche Grundstücke setzen. Er wurde mit Blick auf Langzeitmotivation und technische Raffinesse entwickelt.  
Hier gibt es keine Schnelllebigkeit, sondern echte Progression.  
Farmbare Spawner mit Creepern oder TNT  
Schwämme, die Lava aufsaugen  
Phantome mit Spezialangriffen  
Haustiere fangbar mit Leine direkt am Spawn  
Fortlaufender Fortschritt durch das Sammelsystem  
Belohnungen für Sammelziele  
Items dauerhaft signieren mit /sign  
Hover-Infos im Chat über Welt, Level und Biom  
Interaktive Anzeigen: [inv], [ec], [money] – auch im Discord sichtbar  
Extras wie Rülpsgeräusche, Aufzüge per Schild, Shops, Anti-Xray  
Dieser Modus ist serverseitig optimiert, stabil, ohne Pay2Win, und bietet Spielern täglich neue Anreize.  
Es ist ein Citybuild mit Charakter – gebaut für Langzeitspieler.  
ADVENTURE – HERAUSFORDERUNG AUF NEUEM NIVEAU  
Unser Adventure-Modus ist kein leichter Spaziergang.  
Hier erwartet dich ein PvE-Erlebnis mit Kämpfen, Fortschritt, Bossen und einzigartigen Belohnungen.  
Erlebe, wie weit Minecraft gehen kann – ohne dass du einen Mod installieren musst.  
Custom-Mobs mit eigenen 3D-Modellen, Sounds und Fähigkeiten  
Bosskämpfe mit Spezialmechaniken und Zonenstruktur  
Ein RPG-System mit aufbauender Schwierigkeit  
Seltene Drops, sammelbare Items, freischaltbare Inhalte  
Resourcepack wird automatisch geladen – keine Mods nötig  
Atmosphärische Sounds, visuelle Effekte und Kampfanimationen  
Dieses Erlebnis ist vollständig Vanilla-kompatibel und einzigartig im deutschsprachigen Raum.  
Du wirst schwitzen, du wirst sammeln, du wirst kämpfen – und du wirst zurückkommen.  
DISCORD & COMMUNITY – ALLES IN ECHTZEIT  
Unser Discord ist das Herz der Community.  
Dort findest du nicht nur andere Spieler, sondern bekommst Einblicke in den Entwicklungsprozess:  
Aktuelle Leaks und Bilder  
Umfragen zu neuen Features  
Testphasen und Updates direkt vom Dev-Team  
Schneller Support und Community-Events  
Discord: https://dc.pkstuff.de  
  
SERVERDATEN  
Java: pkstuff.de  
Bedrock: pkstuff.de:19132  
Version: Immer aktuell  
  
PKSTUFF.DE – KEIN STANDARD. KEIN LIMIT. NUR DEIN SPIEL.', 'pkstuff.de:25565', 25565, 'mc_java', 'active', true, NULL, 'https://map.pkstuff.de/', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'paksiw-smp', 'PAKSIW SMP', 'Looking for a server with real vanilla vibes?  
You’ve found it. My goal is simple: survival that feels like Minecraft, where your vanilla farms work, and the community is friendly, humble, and helpful.  
  
What we’re about  
  
🌱 True Survival, Vanilla Feel — No silly gimmicks. Keep what you build, keep what you earn.  
  
⚙️ Working Vanilla Farms — Iron, gold, mob farms… if it’s vanilla, it works here.  
  
🧭 Chill, Helpful Community — Say hi, ask questions, make friends. Zero drama.  
  
🛡️ Claims = Peace of Mind — Protect your builds, invite friends to co-build, expand as you go.  
  
🗺️ Fair QoL Only — Handy commands like /home, /ender, /recipe, and cosmetics at spawn (purely visual).  
  
🗃️ Quests & Light Progression — Optional tasks for coins/keys—fun side goals without ruining survival.  
  
🏷️ Ranks (Not Pay-to-Win) — VIP/VIP+ and MVP are quality-of-life, not power. Survival balance stays intact.  
  
Why play here?  
  
No pay-to-win nonsense.  
  
Active maintenance so TPS stays solid.  
  
Respectful rules—we keep things cozy and fair.  
  
Owner present (hi, that’s me) and actually listening.  
  
Join us  
  
Jump in, set a claim, meet your neighbors, and start your next long-term world.  
If you just want to build, farm, and relax with good people—this is home. 🧡  
  
TL;DR: Vanilla-feel SMP ✔️ Working farms ✔️ Friendly players ✔️ Claims ✔️ Fair QoL ✔️ Quests ✔️ No P2W ✔️', 'paksiwsmp.com', 25565, 'mc_java', 'active', true, NULL, 'https://www.paksiwsmp.com', NULL) ON CONFLICT (slug) DO NOTHING;
