INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'orchid-towny', 'Orchid Towny', 'We''re a small Minecraft community committed to creating a fun, cozy, and welcoming server for all.  
  
