INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'goklubben-se-svensk-mc-server', 'Goklubben.se Svensk MC Server!', '🌍 Server IP: akion.se  
✨Skapades 2025-07-7 - Av nuvarande ägare akiondev!  
  
Det började som ett test… och blev ett äventyr.  
  
Goklubben.se skapades en kväll när världen utanför var mörk, och vi bara ville spela Minecraft – utan krångel, utan fusk, utan stress.  
Sedan dess har servern vuxit till ett litet universum av byggare, krigare, handlare och upptäcktsresande.  
  
Här hittar du Jobs, mcMMO, SmartSpawner, Shop, RareItems, VoteLoot, Towny, Auction House, dagliga belöningar och mycket mer.  
Vi gillar balans – där PVE och PVP möts, där ekonomi, trygghet och frihet samsas sida vid sida. Man kan välja om man vill ha på PVP eller inte.  
  
Vi älskar våra spelare. Vi skrattar åt buggarna.  
Vi bråkar med config-filer, firar varje ny patch och svär på att “den här gången ska det inte lagga”.  
  
Servern byggdes på kaffe, tålamod och en envis vilja att skapa en plats där spelglädje faktiskt betyder något.  
Så välkommen in – hugg lite ved, möt världen och bli en del av vår historia.', 'akion.se', 25565, 'mc_java', 'active', true, NULL, 'https://goklubben.se', NULL) ON CONFLICT (slug) DO NOTHING;
INSERT INTO servers (id, slug, name, description, host, port, game, status, online_mode, region, website_url, discord_url) VALUES (gen_random_uuid(), 'moontopia-mc', 'Moontopia MC', 'Tief verborgen unter dem silbernen Schein des ewigen Mondes liegt eine Welt voller Geheimnisse, uralter Magie und vergessener Legenden. In MoonTopia baust du nicht nur Häuser – du erschaffst dein eigenes Schicksal. Erkunde verwunschene Wälder, entdecke magische Artefakte, kämpfe gegen dunkle Kreaturen oder gründe deine eigene Siedlung unter dem Sternenhimmel.  
  
Willkommen auf MoonTopia, wo Magie im Mondlicht erwacht.  
  
In den Ländereien von MoonTopia, findet Ihr eine Menge Platz, in schönen Natur generierten großen Biomen um eure Träume und Ideen zu verwirklichen. Im Spawnbereich findet Ihr alles, was Ihr für euren Server start benötigt.   
Darunter eine Schule in der alles was Ihr benötigt z.B. Serverregeln oder Plugins erklärt werden. Eine große Einkaufsmeile in der vielleicht demnächst euer Shop stehen könnte?!? Und einen Zoo, in den Ihr auf jedenfall ein Blick werfen solltet!  
Desweiteren sind wir bemüht unseren Server nach Updates schnellstmöglichst auf die neuste Minecraft Version zu updaten. Aktuelle Server Version -> 1.21.8  
  
Lasst euch von der Vielseitigkeit und der stets vorranschreitenden Entwicklung des Servers, sowie vom freundlichen und angagierten Serverteam überzeugen ein Teil unserer Community zu werden. Es sind für die Zukunft noch größere Projekte, neue Plugins und Möglichkeiten geplant. Auch kleinere und größere Events sind in Planung an denen, wenn Ihr wollt, euch gerne beteiligen dürft. Bei Entscheidungen über die Weiterentwicklung unseres Server möchten wir die Meinung der Community mit einbeziehen.  
  
In unserem Rangsystem könnt Ihr ohne Echtgeld steigen und euch so exklusive Vorteile wie z.B. mehr Home Punkte, Belohnungen oder multiple Grundstücke zu sichern.  
  
Homepage, Forum sowie Discord wo wir so gut wie immer erreichbar sind ist vorhanden.   
  
Alle weiteren Infos zum Server, zum Team und zum aktuellen Status findet Ihr auf unserer Homepage. Oder Ihr kommt auf unserem Discord vorbei uns quatscht ein wenig mit uns,  
  
